// 408 知识点复习数据 - 从幻灯片HTML提取
const REVIEW_DATA = {"data-structure": {"title": "数据结构", "weight": "45分", "slides": [{"title": "Cover", "content": "<p class=\"kicker\">408 · DATA STRUCTURE · 王道 / 严蔚敏 完整版</p>\n    <h1 class=\"h1 huge anim-fade-up\" data-anim=\"fade-up\">数据结构</h1>\n    <h2 class=\"h2\" style=\"font-weight:400;color:var(--text-2);margin-top:-8px\">从线性表到图，<span class=\"gradient-text\">把\"组织数据\"这件事讲透</span>。</h2>\n    <p class=\"lede mt-l\">30 节课，覆盖王道教材 8 章全部考点。从 ADT 定义、伪代码、复杂度，到典型算法、手算实例、出题陷阱，一处不漏。</p>\n    <div class=\"label-strip\">\n      <span class=\"pill\">~45 分</span>\n      <span class=\"pill\">8 章 30 节</span>\n      <span class=\"pill\">大题：树/图/排序</span>\n      <span class=\"pill\">选择：链表/查找/复杂度</span>\n    </div>"}, {"title": "目录", "content": "<p class=\"kicker\">// agenda</p>\n    <h2 class=\"h2\">30 张卡片的完整路线</h2>\n    <div class=\"grid g3 mt-l\" style=\"gap:24px;font-size:13.5px\">\n      <div>\n        <h4 style=\"font-size:15px\">Ch1-3 · 线性结构</h4>\n        <ol class=\"steps mt-s\" style=\"counter-reset:s 0\">\n          <li>绪论 · 数据结构与算法</li>\n          <li>时间 / 空间复杂度</li>\n          <li>顺序表 ADT + 代码</li>\n          <li>单链表 + 头插尾插</li>\n          <li>双链表 / 循环链表</li>\n          <li>链表经典算法</li>\n          <li>栈 + 表达式求值</li>\n          <li>队列 + 循环队列</li>\n          <li>双端队列 / 优先队列</li>\n          <li>串与 KMP</li>\n          <li>nextval 优化</li>\n        </ol>\n      </div>\n      <div>\n        <h4 style=\"font-size:15px\">Ch4-6 · 树与图</h4>\n        <ol class=\"steps mt-s\" style=\"counter-reset:s 11\">\n          <li>数组 / 稀疏矩阵</li>\n          <li>树的存储</li>\n          <li>二叉树性质详细</li>\n          <li>遍历（递归 + 非递归）</li>\n          <li>由序列还原二叉树</li>\n          <li>线索二叉树</li>\n          <li>哈夫曼树与编码</li>\n          <li>BST 插入删除</li>\n          <li>AVL 完整算例</li>\n          <li>红黑树性质</li>\n          <li>B 树 / B+ 树</li>\n        </ol>\n      </div>\n      <div>\n        <h4 style=\"font-size:15px\">Ch6-8 · 图查排</h4>\n        <ol class=\"steps mt-s\" style=\"counter-reset:s 22\">\n          <li>图的存储 + 遍历</li>\n          <li>最短路（Dijkstra/Floyd）</li>\n          <li>最小生成树（Prim/Kruskal）</li>\n          <li>拓扑 + 关键路径</li>\n          <li>查找 + 散列 + ASL</li>\n          <li>排序大全 + 代码</li>\n          <li>外部排序</li>\n          <li>知识地图</li>\n        </ol>\n      </div>\n    </div>"}, {"title": "复杂度", "content": "<p class=\"kicker\">01 · 绪论</p>\n    <h2 class=\"h2\">先把\"快慢\"统一成一个语言。</h2>\n    <div class=\"grid g2 mt-l\" style=\"align-items:start\">\n      <div>\n        <p class=\"lede\">渐进复杂度只关心增长形状，机器无关。</p>\n        <h4 class=\"mt-l\">大 O 的直觉（升序）</h4>\n        <ul class=\"dim mt-s\" style=\"line-height:1.95;font-size:14.5px\">\n          <li><span class=\"bigo o-1\">O(1)</span> 哈希查询、栈顶</li>\n          <li><span class=\"bigo o-logn\">O(log n)</span> 折半 / BST 平均</li>\n          <li><span class=\"bigo o-n\">O(n)</span> 顺序扫描</li>\n          <li><span class=\"bigo o-nlogn\">O(n log n)</span> 归并 / 快排 / 堆排</li>\n          <li><span class=\"bigo o-n2\">O(n²)</span> 冒泡 / 选择 / 插入</li>\n          <li><span class=\"bigo o-n2\">O(2ⁿ)</span> 子集枚举</li>\n          <li><span class=\"bigo o-n2\">O(n!)</span> 全排列</li>\n        </ul>\n      </div>\n      <div class=\"card card-accent\">\n        <h4>主定理速算</h4>\n        <p class=\"mono mt-s\" style=\"font-size:14.5px\">T(n) = a·T(n/b) + f(n)</p>\n        <div class=\"mt-m\" style=\"font-size:13.5px;line-height:1.85\">\n          <div>· T(n) = 2T(n/2) + O(n) → <b>O(n log n)</b></div>\n          <div>· T(n) = T(n/2) + O(1) → <b>O(log n)</b></div>\n          <div>· T(n) = T(n-1) + O(n) → <b>O(n²)</b></div>\n          <div>· T(n) = T(n-1) + O(1) → <b>O(n)</b></div>\n        </div>\n        <h4 class=\"mt-l\">几个易错点</h4>\n        <ul class=\"dim mt-s\" style=\"font-size:13px;line-height:1.85\">\n          <li>常用基数：log₂n、ln n、log₁₀n 在 O 记号里等价</li>\n          <li>n^0.001 渐进大于 (log n)^100</li>\n          <li>2ⁿ ≫ n^k 对任意 k</li>\n          <li>递归函数空间复杂度 = 递归深度 × 每层开销</li>\n        </ul>\n      </div>\n    </div>"}, {"title": "顺序表 vs 链表", "content": "<p class=\"kicker\">02 · 线性表</p>\n    <h2 class=\"h2\">两种实现，两种性能权衡。</h2>\n    <div class=\"cmp mt-l\">\n      <div class=\"card pro\">\n        <div class=\"c-h\">顺序表 SqList</div>\n        <h4>连续内存 · 下标随机访问</h4>\n        <table class=\"cmp-table mt-s\">\n          <tr><th>访问 a[i]</th><td class=\"mono\">O(1)</td></tr>\n          <tr><th>查找元素值</th><td class=\"mono\">O(n)</td></tr>\n          <tr><th>插入第 i 位</th><td class=\"mono\">O(n) 平均 (n-i+1)</td></tr>\n          <tr><th>删除第 i 位</th><td class=\"mono\">O(n) 平均 (n-i)</td></tr>\n          <tr><th>空间</th><td>预分配 / 一次分配；浪费或溢出</td></tr>\n        </table>\n        <p class=\"dim mt-m\" style=\"font-size:13.5px\">✅ 选它：访问多、增删少、表长稳定（如静态查找表）。</p>\n      </div>\n      <div class=\"card con\">\n        <div class=\"c-h\">链表 LinkedList</div>\n        <h4>离散结点 · 指针串接</h4>\n        <table class=\"cmp-table mt-s\">\n          <tr><th>访问第 i 个</th><td class=\"mono\">O(n)</td></tr>\n          <tr><th>查找元素值</th><td class=\"mono\">O(n)</td></tr>\n          <tr><th>已知节点插入</th><td class=\"mono\">O(1)</td></tr>\n          <tr><th>已知节点删除</th><td class=\"mono\">O(1)（双链）/ O(n)（单链）</td></tr>\n          <tr><th>空间</th><td>动态分配；每节点多一指针</td></tr>\n        </table>\n        <p class=\"dim mt-m\" style=\"font-size:13.5px\">✅ 选它：增删频繁、表长不定（如 LRU、邻接表、基数排序桶）。</p>\n      </div>\n    </div>\n    <div class=\"card mt-l\">\n      <h4>📌 平均插入移动次数</h4>\n      <p class=\"mono mt-s\" style=\"font-size:14px\">顺序表在第 i 位插入需移动 n−i+1 个元素；等概率插入第 1~n+1 位的平均移动次数 = <b>n/2</b>。删除平均 = (n−1)/2。</p>\n    </div>"}, {"title": "顺序表代码", "content": "<p class=\"kicker\">02 · 顺序表实现</p>\n    <h2 class=\"h2\">动态顺序表的 ADT 与核心代码。</h2>\n    <div class=\"grid g2 mt-l\" style=\"align-items:start\">\n      <div>\n        <pre class=\"code-block\">\n<span class=\"c\">// 动态顺序表定义</span>\n<span class=\"k\">#define</span> InitSize 100\n<span class=\"k\">typedef struct</span> {\n  ElemType *data;\n  <span class=\"k\">int</span> MaxSize, length;\n} SeqList;\n<span class=\"c\">// 初始化</span>\n<span class=\"k\">void</span> <span class=\"f\">InitList</span>(SeqList &amp;L) {\n  L.data = (ElemType*)malloc(\n            sizeof(ElemType)*InitSize);\n  L.length = 0;\n  L.MaxSize = InitSize;\n}\n<span class=\"c\">// 扩容 (倍增策略)</span>\n<span class=\"k\">void</span> <span class=\"f\">IncreaseSize</span>(SeqList &amp;L, <span class=\"k\">int</span> len) {\n  ElemType *p = L.data;\n  L.data = (ElemType*)malloc(\n            sizeof(ElemType)*(L.MaxSize+len));\n  <span class=\"k\">for</span>(<span class=\"k\">int</span> i=0;i&lt;L.length;i++)\n    L.data[i] = p[i];\n  L.MaxSize += len;\n  free(p);\n}</pre>\n      </div>\n      <div>\n        <pre class=\"code-block\">\n<span class=\"c\">// 第 i 位插入元素 e (1 ≤ i ≤ length+1)</span>\n<span class=\"k\">bool</span> <span class=\"f\">ListInsert</span>(SeqList &amp;L, <span class=\"k\">int</span> i, ElemType e) {\n  <span class=\"k\">if</span>(i&lt;1 || i&gt;L.length+1) <span class=\"k\">return false</span>;\n  <span class=\"k\">if</span>(L.length &gt;= L.MaxSize) <span class=\"k\">return false</span>;\n  <span class=\"k\">for</span>(<span class=\"k\">int</span> j=L.length; j&gt;=i; j--)\n    L.data[j] = L.data[j-1];       <span class=\"c\">// 后移</span>\n  L.data[i-1] = e;\n  L.length++;\n  <span class=\"k\">return true</span>;\n}\n<span class=\"c\">// 删除第 i 位</span>\n<span class=\"k\">bool</span> <span class=\"f\">ListDelete</span>(SeqList &amp;L, <span class=\"k\">int</span> i, ElemType &amp;e) {\n  <span class=\"k\">if</span>(i&lt;1 || i&gt;L.length) <span class=\"k\">return false</span>;\n  e = L.data[i-1];\n  <span class=\"k\">for</span>(<span class=\"k\">int</span> j=i; j&lt;L.length; j++)\n    L.data[j-1] = L.data[j];\n  L.length--;\n  <span class=\"k\">return true</span>;\n}\n<span class=\"c\">// 按值查找 → 下标 (失败返回 0)</span>\n<span class=\"k\">int</span> <span class=\"f\">LocateElem</span>(SeqList L, ElemType e) {\n  <span class=\"k\">for</span>(<span class=\"k\">int</span> i=0;i&lt;L.length;i++)\n    <span class=\"k\">if</span>(L.data[i] == e) <span class=\"k\">return</span> i+1;\n  <span class=\"k\">return</span> 0;\n}</pre>\n      </div>\n    </div>"}, {"title": "单链表代码", "content": "<p class=\"kicker\">02 · 单链表实现</p>\n    <h2 class=\"h2\">带头结点的单链表与两种插入策略。</h2>\n    <div class=\"grid g2 mt-l\" style=\"align-items:start\">\n      <div>\n        <pre class=\"code-block\">\n<span class=\"c\">// 单链表结点</span>\n<span class=\"k\">typedef struct</span> LNode {\n  ElemType data;\n  <span class=\"k\">struct</span> LNode *next;\n} LNode, *LinkList;\n<span class=\"c\">// 头插法 (逆序建立)</span>\nLinkList <span class=\"f\">List_HeadInsert</span>(LinkList &amp;L) {\n  L = (LNode*)malloc(<span class=\"k\">sizeof</span>(LNode));\n  L->next = <span class=\"k\">NULL</span>;\n  ElemType x;\n  scanf(<span class=\"s\">\"%d\"</span>, &amp;x);\n  <span class=\"k\">while</span>(x != 9999) {\n    LNode *s = (LNode*)malloc(<span class=\"k\">sizeof</span>(LNode));\n    s->data = x;\n    s->next = L->next;     <span class=\"c\">// 新节点指向第一个</span>\n    L->next = s;            <span class=\"c\">// 头指向新节点</span>\n    scanf(<span class=\"s\">\"%d\"</span>, &amp;x);\n  }\n  <span class=\"k\">return</span> L;\n}</pre>\n        <p class=\"dim mt-s\" style=\"font-size:13px\">头插法：每次插在表头之后，时间 O(1)，结果<b>逆序</b>。</p>\n      </div>\n      <div>\n        <pre class=\"code-block\">\n<span class=\"c\">// 尾插法 (顺序建立)</span>\nLinkList <span class=\"f\">List_TailInsert</span>(LinkList &amp;L) {\n  L = (LNode*)malloc(<span class=\"k\">sizeof</span>(LNode));\n  LNode *r = L;                <span class=\"c\">// 尾指针</span>\n  ElemType x;\n  scanf(<span class=\"s\">\"%d\"</span>, &amp;x);\n  <span class=\"k\">while</span>(x != 9999) {\n    LNode *s = (LNode*)malloc(<span class=\"k\">sizeof</span>(LNode));\n    s->data = x;\n    r->next = s;\n    r = s;\n    scanf(<span class=\"s\">\"%d\"</span>, &amp;x);\n  }\n  r->next = <span class=\"k\">NULL</span>;\n  <span class=\"k\">return</span> L;\n}\n<span class=\"c\">// 按位查找第 i 个 (i &gt;= 0, 0 即头结点)</span>\nLNode* <span class=\"f\">GetElem</span>(LinkList L, <span class=\"k\">int</span> i) {\n  <span class=\"k\">int</span> j = 0;\n  LNode *p = L;\n  <span class=\"k\">while</span>(p &amp;&amp; j&lt;i) {\n    p = p->next; j++;\n  }\n  <span class=\"k\">return</span> p;          <span class=\"c\">// 失败返回 NULL</span>\n}\n<span class=\"c\">// 后插：在 p 之后插入 s (O(1))</span>\n<span class=\"k\">bool</span> <span class=\"f\">InsertNextNode</span>(LNode *p, ElemType e) {\n  LNode *s = (LNode*)malloc(<span class=\"k\">sizeof</span>(LNode));\n  s->data = e;\n  s->next = p->next;\n  p->next = s;\n  <span class=\"k\">return true</span>;\n}</pre>\n      </div>\n    </div>"}, {"title": "双链表 / 循环链表", "content": "<p class=\"kicker\">02 · 链表变体</p>\n    <h2 class=\"h2\">双向 · 循环 · 静态：三个变种各自的优势。</h2>\n    <div class=\"grid g3 mt-l\">\n      <div class=\"card card-accent\">\n        <h4>双链表 DLinkList</h4>\n        <pre class=\"code-block\" style=\"font-size:12.5px\">\n<span class=\"k\">typedef struct</span> DNode {\n  ElemType data;\n  <span class=\"k\">struct</span> DNode *prior, *next;\n} DNode, *DLinkList;\n<span class=\"c\">// 在 p 后插入 s</span>\ns->next = p->next;\n<span class=\"k\">if</span>(p->next) p->next->prior = s;\ns->prior = p;\np->next = s;\n<span class=\"c\">// 删除 p 后继 q</span>\np->next = q->next;\n<span class=\"k\">if</span>(q->next) q->next->prior = p;\nfree(q);</pre>\n        <p class=\"dim mt-s\" style=\"font-size:12.5px\">已知节点删除自身 = O(1)；单链表必须知前驱。</p>\n      </div>\n      <div class=\"card card-accent\">\n        <h4>循环链表</h4>\n        <p class=\"dim mt-s\" style=\"font-size:13px\">尾结点的 next 指向头（带头结点）或第一个数据节点（不带）。</p>\n        <ul class=\"dim\" style=\"font-size:12.5px;line-height:1.85;margin-top:8px\">\n          <li>循环单链表判空：head->next == head</li>\n          <li>仅设尾指针 r：访问头 = O(1)（r->next），尾插 O(1)</li>\n          <li>循环双链表：尾的 next 是头、头的 prior 是尾</li>\n          <li>应用：约瑟夫问题、轮询调度、月份循环</li>\n        </ul>\n      </div>\n      <div class=\"card card-accent\">\n        <h4>静态链表</h4>\n        <p class=\"dim mt-s\" style=\"font-size:13px\">用数组模拟链表，data + cursor 取代指针。</p>\n        <ul class=\"dim\" style=\"font-size:12.5px;line-height:1.85;margin-top:8px\">\n          <li>不支持动态分配 (嵌入式) 场景下使用</li>\n          <li>cursor 为 -1 即链尾</li>\n          <li>需自管空闲块链</li>\n        </ul>\n        <div class=\"viz mt-s\" style=\"font-size:11.5px;line-height:1.8\">\n  i  data  cursor\n  0   --    1     ← head\n  1   A     2\n  2   B     3\n  3   C    -1</div>\n      </div>\n    </div>"}, {"title": "链表经典算法", "content": "<p class=\"kicker\">02 · 链表 5 题</p>\n    <h2 class=\"h2\">几乎一定会出现在大题里的链表操作。</h2>\n    <div class=\"grid g2 mt-l\" style=\"align-items:start\">\n      <div>\n        <h4>① 逆置（原地）</h4>\n        <pre class=\"code-block\" style=\"font-size:12.5px\">\nLNode *p = L->next, *q, *prev = <span class=\"k\">NULL</span>;\nL->next = <span class=\"k\">NULL</span>;\n<span class=\"k\">while</span>(p) {\n  q = p->next;\n  p->next = L->next;\n  L->next = p;     <span class=\"c\">// 头插法</span>\n  p = q;\n}</pre>\n        <h4 class=\"mt-m\">② 找环（Floyd 龟兔）</h4>\n        <pre class=\"code-block\" style=\"font-size:12.5px\">\nslow = fast = L->next;\n<span class=\"k\">while</span>(fast &amp;&amp; fast->next) {\n  slow = slow->next;\n  fast = fast->next->next;\n  <span class=\"k\">if</span>(slow == fast) <span class=\"k\">break</span>;\n}\n<span class=\"k\">if</span>(!fast) <span class=\"k\">return null</span>;\n<span class=\"c\">// 求环入口：从头与相遇点同速前进</span>\nLNode *p = L->next;\n<span class=\"k\">while</span>(p != slow) {\n  p = p->next; slow = slow->next;\n}\n<span class=\"k\">return</span> p;</pre>\n      </div>\n      <div>\n        <h4>③ 合并两个有序链表 (非递归)</h4>\n        <pre class=\"code-block\" style=\"font-size:12.5px\">\nLNode *p = L1->next, *q = L2->next;\nLNode *r = L1;        <span class=\"c\">// 复用 L1 头</span>\n<span class=\"k\">while</span>(p &amp;&amp; q) {\n  <span class=\"k\">if</span>(p->data &lt;= q->data) {\n    r->next = p; r = p; p = p->next;\n  } <span class=\"k\">else</span> {\n    r->next = q; r = q; q = q->next;\n  }\n}\nr->next = p ? p : q;\nfree(L2);</pre>\n        <h4 class=\"mt-m\">④ 倒数第 k 个（双指针）</h4>\n        <pre class=\"code-block\" style=\"font-size:12.5px\">\nLNode *fast = L, *slow = L;\n<span class=\"k\">for</span>(<span class=\"k\">int</span> i=0; i&lt;k; i++) fast = fast->next;\n<span class=\"k\">while</span>(fast) {\n  fast = fast->next; slow = slow->next;\n}\n<span class=\"k\">return</span> slow->next;   <span class=\"c\">// 即倒数第 k 个</span></pre>\n        <h4 class=\"mt-m\">⑤ 判断回文（栈 / 快慢指针 + 翻转）</h4>\n        <p class=\"dim mt-s\" style=\"font-size:13px\">快慢指针定位中点，反转后半段，再与前半段逐节点比较。O(n) 时间、O(1) 空间。</p>\n      </div>\n    </div>"}, {"title": "栈 + 表达式", "content": "<p class=\"kicker\">03 · 栈</p>\n    <h2 class=\"h2\">栈：递归 / 表达式 / 回溯三大场景。</h2>\n    <div class=\"grid g2 mt-l\" style=\"align-items:start\">\n      <div>\n        <h4>顺序栈 vs 链栈</h4>\n        <table class=\"cmp-table mt-s\">\n          <tr><th></th><th>顺序栈</th><th>链栈</th></tr>\n          <tr><td>判空</td><td class=\"mono\">top==-1</td><td class=\"mono\">top==NULL</td></tr>\n          <tr><td>入栈</td><td>top++; S[top]=x</td><td>头插</td></tr>\n          <tr><td>出栈</td><td>x=S[top--]</td><td>头删</td></tr>\n          <tr><td>满栈</td><td>top==MaxSize-1</td><td>不会满</td></tr>\n        </table>\n        <h4 class=\"mt-l\">栈的卡特兰数</h4>\n        <p class=\"dim mt-s\" style=\"font-size:13.5px\">n 个不同元素入栈，可能的出栈序列数：<br><span class=\"mono\">C(2n,n)/(n+1)</span>（卡特兰数 1,2,5,14,42…）。</p>\n      </div>\n      <div>\n        <h4>中缀 → 后缀</h4>\n        <div class=\"viz mt-s\" style=\"font-size:12.5px\">\nA + B * (C - D) / E\nstep:\nA → 输出\n+ → 栈\nB → 输出\n* → 栈 (优先级高于 +)\n( → 栈\nC → 输出\n- → 栈\nD → 输出\n) → 弹到 ( 为止: -\n/ → 栈顶 * 优先级 ≥ /，先弹 *；再压 /\nE → 输出\n末尾 → 弹空栈: / +\n结果: A B C D - * E / +</div>\n        <h4 class=\"mt-m\">用栈计算后缀</h4>\n        <p class=\"dim mt-s\" style=\"font-size:13px\">遇数字进栈；遇运算符弹两个数 (注意顺序: 后弹的在前)，运算结果再入栈。栈底剩一即结果。</p>\n      </div>\n    </div>"}, {"title": "队列 + 循环", "content": "<p class=\"kicker\">03 · 队列</p>\n    <h2 class=\"h2\">FIFO 与循环队列的判空判满。</h2>\n    <div class=\"grid g2 mt-l\" style=\"align-items:start\">\n      <div>\n        <h4>循环队列三种判空满</h4>\n        <table class=\"cmp-table mt-s\">\n          <tr><th>方案</th><th>判空</th><th>判满</th><th>队长</th></tr>\n          <tr><td>牺牲一格</td><td>front==rear</td><td>(rear+1)%n==front</td><td>(rear-front+n)%n</td></tr>\n          <tr><td>设 size</td><td>size==0</td><td>size==n</td><td>size</td></tr>\n          <tr><td>设 tag</td><td>tag==0 且 ==</td><td>tag==1 且 ==</td><td>—</td></tr>\n        </table>\n        <pre class=\"code-block mt-m\" style=\"font-size:12.5px\">\n<span class=\"c\">// 牺牲一格法</span>\n<span class=\"k\">bool</span> <span class=\"f\">EnQueue</span>(Q &amp;q, ElemType x) {\n  <span class=\"k\">if</span>((q.rear+1)%n == q.front) <span class=\"k\">return false</span>;\n  q.data[q.rear] = x;\n  q.rear = (q.rear+1) % n;\n  <span class=\"k\">return true</span>;\n}\n<span class=\"k\">bool</span> <span class=\"f\">DeQueue</span>(Q &amp;q, ElemType &amp;x) {\n  <span class=\"k\">if</span>(q.rear == q.front) <span class=\"k\">return false</span>;\n  x = q.data[q.front];\n  q.front = (q.front+1) % n;\n  <span class=\"k\">return true</span>;\n}</pre>\n      </div>\n      <div>\n        <h4>链队列</h4>\n        <p class=\"dim mt-s\" style=\"font-size:13.5px\">需要 front + rear 两个指针；带头节点更方便（出空时不用特判）。<br>不会\"满\"，只可能 malloc 失败。</p>\n        <h4 class=\"mt-l\">队列的应用</h4>\n        <ul class=\"dim mt-s\" style=\"font-size:13.5px;line-height:1.9\">\n          <li><b>CPU 调度</b>：就绪队列、阻塞队列</li>\n          <li><b>缓冲</b>：键盘缓冲、打印队列</li>\n          <li><b>BFS</b>：图 / 树的层序遍历</li>\n          <li><b>层次模拟</b>：操作系统页面置换 FIFO</li>\n        </ul>\n        <h4 class=\"mt-l\">两栈实现队列</h4>\n        <pre class=\"code-block\" style=\"font-size:12.5px\">\n<span class=\"c\">// 双栈队列</span>\n<span class=\"k\">push</span>:  入 stack_in\n<span class=\"k\">pop</span>:   stack_out 空时，\n       把 in 全部倒入 out；\n       否则直接出 out 栈顶</pre>\n      </div>\n    </div>"}, {"title": "双端 / 优先队列", "content": "<p class=\"kicker\">03 · 队列扩展</p>\n    <h2 class=\"h2\">两个特殊队列：deque 与 priority queue。</h2>\n    <div class=\"grid g2 mt-l\" style=\"align-items:start\">\n      <div>\n        <h4>双端队列 Deque</h4>\n        <p class=\"dim mt-s\" style=\"font-size:13.5px\">两端都可以入出。受限的两类：</p>\n        <ul class=\"dim mt-s\" style=\"font-size:13.5px;line-height:1.85\">\n          <li><b>输入受限</b>：只在一端入，两端都可出</li>\n          <li><b>输出受限</b>：两端都可入，只在一端出</li>\n        </ul>\n        <p class=\"dim mt-m\" style=\"font-size:13.5px\">问\"给定输入 1,2,3,4，输出 4,1,3,2 是否可能\"是典型题。逐步模拟即可。</p>\n        <div class=\"viz mt-s\" style=\"font-size:12.5px\">\ntypical: 输入受限 deque\n  输入: 1234\n  允许从左/右出，但只从右入\n  推 1: [1]\n  推 2: [1,2]\n  从左出 1: ❌ 想要 4 先\n  …不可能 → 序列非法</div>\n      </div>\n      <div>\n        <h4>优先队列 / 堆</h4>\n        <p class=\"dim mt-s\" style=\"font-size:13.5px\">每次取出\"优先级最高 / 最低\"的元素。底层常用<b>二叉堆</b>。</p>\n        <h4 class=\"mt-m\">大根堆 / 小根堆</h4>\n        <ul class=\"dim mt-s\" style=\"font-size:13.5px;line-height:1.85\">\n          <li>大根堆：父 ≥ 子；堆顶 = 最大值</li>\n          <li>小根堆：父 ≤ 子；堆顶 = 最小值</li>\n          <li>用顺序存储：i 的父 ⌊i/2⌋，左 2i，右 2i+1（下标从 1 开始）</li>\n        </ul>\n        <h4 class=\"mt-m\">建堆 O(n)</h4>\n        <p class=\"dim mt-s\" style=\"font-size:13px\">从最后一个非叶 ⌊n/2⌋ 开始，逐个向下调整（siftDown）。每次插入 / 删除堆顶为 O(log n)。</p>\n        <p class=\"dim mt-s\" style=\"font-size:13px\"><b>应用</b>：Top-K、Dijkstra、合并 K 个有序链表、任务调度。</p>\n      </div>\n    </div>"}, {"title": "串 + KMP", "content": "<p class=\"kicker\">04 · 字符串</p>\n    <h2 class=\"h2\">KMP：用模式串自身信息省下回退。</h2>\n    <div class=\"grid g2 mt-l\" style=\"align-items:start\">\n      <div>\n        <p class=\"dim\" style=\"font-size:13.5px\">朴素匹配：每次失配，主串指针 i 回退到本次起点 + 1，模式串指针 j 回到 0，最坏 O(nm)。</p>\n        <p class=\"dim mt-s\" style=\"font-size:13.5px\">KMP 关键洞察：失配时主串<b>不回退</b>，只把 j 跳到合适位置，利用已知\"前缀 == 后缀\"的部分。</p>\n        <h4 class=\"mt-l\">next 数组定义</h4>\n        <p class=\"mono mt-s\" style=\"background:var(--surface-2);padding:12px;border-radius:8px;font-size:13.5px\">\n          next[j] = P[0..j-1] 的\"<b>最长真前缀 = 真后缀</b>\"长度<br>\n          特别：next[0] = -1 (惯例)\n        </p>\n        <h4 class=\"mt-m\">手算 next 表步骤</h4>\n        <ol class=\"dim mt-s\" style=\"font-size:13px;line-height:1.85\">\n          <li>next[0] = -1, next[1] = 0</li>\n          <li>设当前 next[j] = k</li>\n          <li>若 P[k] == P[j]: next[j+1] = k + 1</li>\n          <li>否则 k = next[k]，回退继续比较</li>\n          <li>若 k 退到 -1，next[j+1] = 0</li>\n        </ol>\n      </div>\n      <div>\n        <h4>完整 next 推导示例</h4>\n        <p class=\"mono\" style=\"font-size:14px\">P = \"ababaca\"</p>\n        <table class=\"cmp-table mt-s\">\n          <tr><th>j</th><td>0</td><td>1</td><td>2</td><td>3</td><td>4</td><td>5</td><td>6</td></tr>\n          <tr><th>P[j]</th><td>a</td><td>b</td><td>a</td><td>b</td><td>a</td><td>c</td><td>a</td></tr>\n          <tr><th>next</th><td>-1</td><td>0</td><td>0</td><td>1</td><td>2</td><td>3</td><td>0</td></tr>\n        </table>\n        <h4 class=\"mt-m\">KMP 主匹配代码</h4>\n        <pre class=\"code-block\" style=\"font-size:12.5px\">\n<span class=\"k\">int</span> <span class=\"f\">KMP</span>(<span class=\"k\">char</span> *S, <span class=\"k\">char</span> *P, <span class=\"k\">int</span> *next) {\n  <span class=\"k\">int</span> i=0, j=0;\n  <span class=\"k\">while</span>(i&lt;strlen(S) &amp;&amp; j&lt;(<span class=\"k\">int</span>)strlen(P)) {\n    <span class=\"k\">if</span>(j == -1 || S[i] == P[j]) {\n      i++; j++;\n    } <span class=\"k\">else</span> {\n      j = next[j];      <span class=\"c\">// 主串 i 不回退！</span>\n    }\n  }\n  <span class=\"k\">if</span>(j == strlen(P)) <span class=\"k\">return</span> i - j;\n  <span class=\"k\">return</span> -1;\n}</pre>\n        <p class=\"dim mt-s\" style=\"font-size:13px\">复杂度：构造 next O(m) + 匹配 O(n) = <b>O(n+m)</b>。</p>\n      </div>\n    </div>"}, {"title": "nextval 优化", "content": "<p class=\"kicker\">04 · KMP 优化</p>\n    <h2 class=\"h2\">为什么 next 还不够好？</h2>\n    <div class=\"grid g2 mt-l\" style=\"align-items:start\">\n      <div>\n        <p class=\"lede\">问题：若 next[j] = k 而 <b>P[j] == P[k]</b>，则 j 跳到 k 后必然又失配，浪费一次比较。</p>\n        <h4 class=\"mt-l\">nextval 定义</h4>\n        <pre class=\"code-block\" style=\"font-size:12.5px\">\n<span class=\"k\">if</span>(P[j] != P[next[j]])\n  nextval[j] = next[j];\n<span class=\"k\">else</span>\n  nextval[j] = nextval[next[j]];   <span class=\"c\">// 继续向上跳</span></pre>\n      </div>\n      <div>\n        <h4>对比示例</h4>\n        <p class=\"mono\" style=\"font-size:14px\">P = \"aaaab\"</p>\n        <table class=\"cmp-table mt-s\">\n          <tr><th>j</th><td>0</td><td>1</td><td>2</td><td>3</td><td>4</td></tr>\n          <tr><th>P[j]</th><td>a</td><td>a</td><td>a</td><td>a</td><td>b</td></tr>\n          <tr><th>next</th><td>-1</td><td>0</td><td>1</td><td>2</td><td>3</td></tr>\n          <tr><th>nextval</th><td>-1</td><td>-1</td><td>-1</td><td>-1</td><td>3</td></tr>\n        </table>\n        <p class=\"dim mt-m\" style=\"font-size:13px\">若失配于 j=3 (P[3]='a')，next 会让 j 跳到 2 又比 'a'，再到 1 比 'a'，再到 0 比 'a'，再到 -1。<br>nextval 直接跳到 -1。</p>\n      </div>\n    </div>"}, {"title": "数组 / 稀疏矩阵", "content": "<p class=\"kicker\">05 · 数组</p>\n    <h2 class=\"h2\">二维数组的两种存储 + 特殊矩阵的压缩。</h2>\n    <div class=\"grid g2 mt-l\" style=\"align-items:start\">\n      <div>\n        <h4>行优先 vs 列优先</h4>\n        <p class=\"dim mt-s\" style=\"font-size:13.5px\">m×n 数组 A，行优先元素 a[i][j] 的地址为：</p>\n        <p class=\"mono\" style=\"font-size:14px;background:var(--surface-2);padding:10px;border-radius:8px\">\n          LOC(a[i][j]) = LOC(a[0][0]) + (i·n + j)·k<br>\n          <span class=\"dim\">// k 为每个元素字节数</span>\n        </p>\n        <p class=\"dim mt-s\" style=\"font-size:13.5px\">C 语言、Python NumPy 默认行优先；Fortran、MATLAB 列优先。</p>\n        <h4 class=\"mt-l\">对称矩阵的压缩</h4>\n        <p class=\"dim mt-s\" style=\"font-size:13.5px\">n 阶对称矩阵 a[i][j] = a[j][i]，仅存上 / 下三角，n(n+1)/2 个元素。</p>\n        <p class=\"mono mt-s\" style=\"font-size:13px\">下三角行优先：k = i(i+1)/2 + j  (i ≥ j)</p>\n      </div>\n      <div>\n        <h4>三角 / 对角矩阵</h4>\n        <ul class=\"dim mt-s\" style=\"font-size:13.5px;line-height:1.85\">\n          <li>三角矩阵：仅存非零部分 + 一个常数</li>\n          <li>三对角：仅存主对角线 ± 1 共 3n-2 个元素</li>\n          <li>k 计算公式根据存储方向略不同，考试时手画下脚标</li>\n        </ul>\n        <h4 class=\"mt-l\">稀疏矩阵</h4>\n        <p class=\"dim mt-s\" style=\"font-size:13.5px\">非零元素远少于总元素：用<b>三元组</b> (i, j, value) 存储。</p>\n        <div class=\"viz mt-s\" style=\"font-size:11.5px\">\n原矩阵 (4×4):\n 0 12  0  0\n 0  0  0 18\n15  0  0  0\n 0  0 91  0\n三元组:\n (0,1,12)\n (1,3,18)\n (2,0,15)\n (3,2,91)\n或: 十字链表 (行 + 列两个方向都串)</div>\n      </div>\n    </div>"}, {"title": "树的存储", "content": "<p class=\"kicker\">06 · 树</p>\n    <h2 class=\"h2\">普通树有三种常用存储。</h2>\n    <div class=\"grid g3 mt-l\">\n      <div class=\"card card-accent\">\n        <h4>① 双亲表示</h4>\n        <p class=\"dim mt-s\" style=\"font-size:13px\">每节点存 data + parent 下标。</p>\n        <div class=\"viz mt-s\" style=\"font-size:11.5px\">\ni  data parent\n0   A    -1\n1   B     0\n2   C     0\n3   D     1\n4   E     1\n5   F     2</div>\n        <p class=\"dim mt-s\" style=\"font-size:12.5px\">✅ 找父亲 O(1)<br>❌ 找儿子 O(n)</p>\n      </div>\n      <div class=\"card card-accent\">\n        <h4>② 孩子表示</h4>\n        <p class=\"dim mt-s\" style=\"font-size:13px\">数组 + 每节点一条孩子链表。</p>\n        <div class=\"viz mt-s\" style=\"font-size:11.5px\">\ni data 孩子链\n0  A   → 1 → 2\n1  B   → 3 → 4\n2  C   → 5\n3  D\n4  E\n5  F</div>\n        <p class=\"dim mt-s\" style=\"font-size:12.5px\">✅ 找儿子方便<br>❌ 找父亲 O(n)</p>\n      </div>\n      <div class=\"card card-accent\">\n        <h4>③ 孩子兄弟（左孩子右兄弟）</h4>\n        <p class=\"dim mt-s\" style=\"font-size:13px\">每节点两个指针：第一个孩子 + 下一个兄弟。<br><b>本质：把普通树转为二叉树！</b></p>\n        <div class=\"viz mt-s\" style=\"font-size:11.5px\">\n普通树:        转换后:\n   A              A\n  /|\\\\             |\n B C D            B\n   |              \\\\\n   E              C\n                  /\\\\\n                 E  D</div>\n        <p class=\"dim mt-s\" style=\"font-size:12.5px\">✅ 复用二叉树算法<br>所有操作 O(度)</p>\n      </div>\n    </div>\n    <div class=\"card mt-l\">\n      <h4>📐 森林 ↔ 二叉树</h4>\n      <p class=\"dim\" style=\"font-size:13.5px\">森林 → 二叉树：每棵树先用孩子兄弟法变二叉树；将后一棵树整体作为前一棵的右子树。反之亦然。<br>森林的<b>先序遍历</b> = 对应二叉树的先序；森林的<b>中序遍历</b> = 对应二叉树的<b>中序</b>（注意：这里中序是\"先左子树、再根、再右兄弟\"）。</p>\n    </div>"}, {"title": "二叉树性质", "content": "<p class=\"kicker\">06 · 二叉树</p>\n    <h2 class=\"h2\">7 条性质 + 3 种特殊形态。</h2>\n    <div class=\"grid g2 mt-l\" style=\"align-items:start\">\n      <div>\n        <h4>必背 7 条</h4>\n        <ol class=\"dim mt-s\" style=\"font-size:13.5px;line-height:1.95\">\n          <li>第 i 层最多 <span class=\"mono\">2^(i-1)</span> 个结点</li>\n          <li>深度 h 的二叉树最多 <span class=\"mono\">2^h - 1</span> 个结点</li>\n          <li>n 个节点的完全二叉树深度 = ⌊log₂n⌋ + 1</li>\n          <li>n 个节点的二叉树有 <span class=\"mono\">n + 1</span> 个空指针</li>\n          <li><b>叶子数 n₀ = n₂ + 1</b>（度为 2 的节点 + 1）</li>\n          <li>具有 n 个节点的不同二叉树形态数 = <span class=\"mono\">C(2n,n)/(n+1)</span>（卡特兰）</li>\n          <li>完全二叉树中，n 个节点，叶子数 = ⌈n/2⌉，单分支至多 1 个</li>\n        </ol>\n      </div>\n      <div>\n        <h4>三种特殊</h4>\n        <div class=\"grid g3 mt-s\" style=\"font-size:12.5px\">\n          <div class=\"card card-soft\"><b>满二叉树</b><p class=\"dim mt-s\">每层都满，叶子全在最底</p></div>\n          <div class=\"card card-soft\"><b>完全二叉树</b><p class=\"dim mt-s\">只有最后一层右部可缺；按层序编号与满二叉树一致</p></div>\n          <div class=\"card card-soft\"><b>扩充二叉树</b><p class=\"dim mt-s\">补 NULL 节点为叶</p></div>\n        </div>\n        <h4 class=\"mt-l\">完全二叉树编号关系</h4>\n        <p class=\"mono mt-s\" style=\"font-size:13.5px;background:var(--surface-2);padding:12px;border-radius:8px;line-height:1.9\">\n          节点 i (从 1 开始)：<br>\n          · 父亲 = ⌊i/2⌋<br>\n          · 左孩子 = 2i<br>\n          · 右孩子 = 2i+1<br>\n          · 所在层 = ⌊log₂i⌋ + 1\n        </p>\n        <h4 class=\"mt-m\">证明 n₀ = n₂ + 1</h4>\n        <p class=\"dim mt-s\" style=\"font-size:13px\">总边数 = 总节点 - 1 = n - 1；又 = 0·n₀ + 1·n₁ + 2·n₂。<br>整理：n₀ + n₁ + n₂ - 1 = n₁ + 2n₂ → <b>n₀ = n₂ + 1</b>。</p>\n      </div>\n    </div>"}, {"title": "二叉树遍历", "content": "<p class=\"kicker\">06 · 遍历</p>\n    <h2 class=\"h2\">递归 + 非递归三种 + 层序。</h2>\n    <div class=\"grid g2 mt-l\" style=\"align-items:start\">\n      <div>\n        <h4>递归三件套</h4>\n        <pre class=\"code-block\" style=\"font-size:12.5px\">\n<span class=\"k\">void</span> <span class=\"f\">preOrder</span>(TreeNode *p) {\n  <span class=\"k\">if</span>(!p) <span class=\"k\">return</span>;\n  visit(p);\n  preOrder(p->left);\n  preOrder(p->right);\n}\n<span class=\"c\">// 中序：换 visit 位置到中间</span>\n<span class=\"c\">// 后序：换 visit 位置到最后</span></pre>\n        <h4 class=\"mt-m\">前序非递归 (栈)</h4>\n        <pre class=\"code-block\" style=\"font-size:12.5px\">\nstack&lt;TreeNode*&gt; st;\nst.push(root);\n<span class=\"k\">while</span>(!st.empty()) {\n  p = st.top(); st.pop();\n  visit(p);\n  <span class=\"k\">if</span>(p->right) st.push(p->right);\n  <span class=\"k\">if</span>(p->left) st.push(p->left);  <span class=\"c\">// 后压先出</span>\n}</pre>\n      </div>\n      <div>\n        <h4>后序非递归（标记法）</h4>\n        <pre class=\"code-block\" style=\"font-size:12.5px\">\nstack&lt;TreeNode*&gt; st;\nTreeNode *p = root, *r = NULL;   <span class=\"c\">// r 记上次访问</span>\n<span class=\"k\">while</span>(p || !st.empty()) {\n  <span class=\"k\">while</span>(p) {\n    st.push(p);\n    p = p->left;\n  }\n  p = st.top();\n  <span class=\"k\">if</span>(p->right &amp;&amp; p->right != r) {\n    p = p->right;\n  } <span class=\"k\">else</span> {\n    visit(p);\n    r = p;\n    st.pop();\n    p = NULL;\n  }\n}</pre>\n        <h4 class=\"mt-m\">层序遍历 (队列)</h4>\n        <pre class=\"code-block\" style=\"font-size:12.5px\">\nqueue&lt;TreeNode*&gt; q;\nq.push(root);\n<span class=\"k\">while</span>(!q.empty()) {\n  p = q.front(); q.pop();\n  visit(p);\n  <span class=\"k\">if</span>(p->left)  q.push(p->left);\n  <span class=\"k\">if</span>(p->right) q.push(p->right);\n}</pre>\n      </div>\n    </div>"}, {"title": "由序列还原", "content": "<p class=\"kicker\">06 · 反推树</p>\n    <h2 class=\"h2\">由两种遍历序列唯一确定二叉树。</h2>\n    <div class=\"grid g2 mt-l\" style=\"align-items:start\">\n      <div>\n        <h4>哪两个序列能确定？</h4>\n        <ul class=\"dim mt-s\" style=\"font-size:14px;line-height:1.95\">\n          <li>✅ 前 + 中</li>\n          <li>✅ 后 + 中</li>\n          <li>✅ 层 + 中</li>\n          <li>❌ 前 + 后（一般不能）</li>\n          <li>❌ 前 + 层（一般不能）</li>\n        </ul>\n        <h4 class=\"mt-l\">为什么必须有\"中序\"？</h4>\n        <p class=\"dim\" style=\"font-size:13.5px\">前/后/层都只告诉你\"根在哪儿\"，但<b>中序</b>是唯一把根的左、右子树分开的序列。两者结合才能递归切分。</p>\n      </div>\n      <div>\n        <h4>前 + 中 还原步骤</h4>\n        <div class=\"viz mt-s\" style=\"font-size:12px\">\n前序: A B D E C F\n中序: D B E A C F\nstep 1: 前序第 1 个 A 是根\n        中序里 A 把序列分为\n          [D B E] 左子树\n          [C F]    右子树\nstep 2: 在左子树前序 B D E 中\n        第 1 个 B 是左子树的根\n        中序 [D B E] 中 B 把它分为\n          [D]   左\n          [E]   右\nstep 3: 右子树同理\n最终：\n       A\n      / \\\n     B   C\n    / \\   \\\n   D   E   F</div>\n      </div>\n    </div>"}, {"title": "线索二叉树", "content": "<p class=\"kicker\">07 · 线索</p>\n    <h2 class=\"h2\">让\"空指针\"指向前驱后继。</h2>\n    <div class=\"grid g2 mt-l\" style=\"align-items:start\">\n      <div>\n        <h4>动机</h4>\n        <p class=\"dim mt-s\" style=\"font-size:14px\">n 个节点共有 <b>n+1 个空指针</b>。利用它们存放\"中序\"或\"前/后序\"下的前驱后继，就能不用栈做遍历。</p>\n        <h4 class=\"mt-l\">结构</h4>\n        <pre class=\"code-block\" style=\"font-size:12.5px\">\n<span class=\"k\">typedef struct</span> ThreadNode {\n  ElemType data;\n  <span class=\"k\">struct</span> ThreadNode *left, *right;\n  <span class=\"k\">int</span> ltag, rtag;   <span class=\"c\">// 0=孩子, 1=线索</span>\n} ThreadNode;</pre>\n        <h4 class=\"mt-m\">中序线索化算法</h4>\n        <pre class=\"code-block\" style=\"font-size:12.5px\">\nThreadNode *pre = NULL;\n<span class=\"k\">void</span> <span class=\"f\">InThread</span>(ThreadNode *p) {\n  <span class=\"k\">if</span>(!p) <span class=\"k\">return</span>;\n  InThread(p->left);\n  <span class=\"k\">if</span>(!p->left)  { p->left = pre;  p->ltag = 1; }\n  <span class=\"k\">if</span>(pre &amp;&amp; !pre->right) {\n    pre->right = p; pre->rtag = 1;\n  }\n  pre = p;\n  InThread(p->right);\n}</pre>\n      </div>\n      <div>\n        <h4>中序线索树的遍历（无栈）</h4>\n        <pre class=\"code-block\" style=\"font-size:12.5px\">\n<span class=\"c\">// 中序后继：</span>\n<span class=\"c\">// rtag=1 → right 直接是后继</span>\n<span class=\"c\">// rtag=0 → 后继是右子树最左节点</span>\nThreadNode* <span class=\"f\">Next</span>(ThreadNode *p) {\n  <span class=\"k\">if</span>(p->rtag == 1) <span class=\"k\">return</span> p->right;\n  p = p->right;\n  <span class=\"k\">while</span>(p->ltag == 0) p = p->left;\n  <span class=\"k\">return</span> p;\n}\n<span class=\"c\">// 完整遍历</span>\np = first(root);\n<span class=\"k\">while</span>(p) {\n  visit(p);\n  p = Next(p);\n}</pre>\n        <h4 class=\"mt-m\">前序 / 后序线索化</h4>\n        <p class=\"dim mt-s\" style=\"font-size:13px\">前序线索：left 空指前驱、right 空指后继；前驱的查找需父指针或额外栈。<br>后序线索：找后继较复杂（如果是右子树最末则需父指针）。</p>\n      </div>\n    </div>"}, {"title": "哈夫曼", "content": "<p class=\"kicker\">08 · 哈夫曼</p>\n    <h2 class=\"h2\">给一组权值，造一棵 WPL 最小的二叉树。</h2>\n    <div class=\"grid g2 mt-l\" style=\"align-items:start\">\n      <div>\n        <h4>构造步骤</h4>\n        <ol class=\"steps mt-s\" style=\"font-size:13.5px\">\n          <li>把所有权值看作 n 棵单节点树</li>\n          <li>取根权最小的两棵，合为新树（左小右大），权 = 两者之和</li>\n          <li>将新树放回集合</li>\n          <li>重复直到只剩一棵</li>\n        </ol>\n        <h4 class=\"mt-l\">性质</h4>\n        <ul class=\"dim mt-s\" style=\"font-size:13.5px;line-height:1.85\">\n          <li>共 n 个叶子的哈夫曼树有 2n - 1 个节点</li>\n          <li>无度为 1 的节点（每次合并一定产生度 2）</li>\n          <li>WPL = Σ wᵢ × Lᵢ（叶子权 × 路径长度）</li>\n        </ul>\n      </div>\n      <div>\n        <h4>完整例</h4>\n        <p class=\"dim mt-s\" style=\"font-size:13.5px\">权值 {7, 5, 4, 2}</p>\n        <div class=\"viz mt-s\" style=\"font-size:12px\">\nstep1: 取 2,4 → 合并 6\n       {7, 5, 6}\nstep2: 取 5,6 → 合并 11\n       {7, 11}\nstep3: 取 7,11 → 合并 18\n         18\n        /  \\\n       7   11\n           / \\\n          5   6\n              / \\\n             2   4\nWPL = 7·1 + 5·2 + 2·3 + 4·3\n    = 7 + 10 + 6 + 12 = 35</div>\n        <h4 class=\"mt-m\">哈夫曼编码</h4>\n        <p class=\"dim mt-s\" style=\"font-size:13.5px\">从根向左 = 0，向右 = 1。例：A=7→\"0\"、B=5→\"10\"、C=2→\"110\"、D=4→\"111\"。<br><b>前缀码</b>：任何编码不是另一个的前缀，可唯一解码。</p>\n      </div>\n    </div>"}, {"title": "BST 插入删除", "content": "<p class=\"kicker\">09 · 二叉搜索树</p>\n    <h2 class=\"h2\">中序得到升序，插入删除都 O(log n) 平均。</h2>\n    <div class=\"grid g2 mt-l\" style=\"align-items:start\">\n      <div>\n        <h4>插入</h4>\n        <pre class=\"code-block\" style=\"font-size:12.5px\">\n<span class=\"k\">bool</span> <span class=\"f\">BST_Insert</span>(BSTNode *&amp;T, ElemType e) {\n  <span class=\"k\">if</span>(!T) {\n    T = (BSTNode*)malloc(<span class=\"k\">sizeof</span>(BSTNode));\n    T->data = e;\n    T->left = T->right = NULL;\n    <span class=\"k\">return true</span>;\n  }\n  <span class=\"k\">if</span>(e == T->data) <span class=\"k\">return false</span>;\n  <span class=\"k\">if</span>(e &lt; T->data) <span class=\"k\">return</span> BST_Insert(T->left, e);\n  <span class=\"k\">return</span> BST_Insert(T->right, e);\n}</pre>\n        <p class=\"dim mt-s\" style=\"font-size:13px\">逐次插入 {45, 24, 53, 12, 28} 得到的 BST，中序为 12, 24, 28, 45, 53。<b>顺序不同形态不同。</b></p>\n      </div>\n      <div>\n        <h4>删除（最难的情况）</h4>\n        <ol class=\"dim mt-s\" style=\"font-size:13.5px;line-height:1.85\">\n          <li>叶节点：直接删除。</li>\n          <li>只有一个子树：用唯一子树代替自己。</li>\n          <li>有两个子树：用<b>中序后继</b>（右子树的最左节点）或中序前驱替换 data，然后删除那个后继 / 前驱节点（递归回到情况 1 或 2）。</li>\n        </ol>\n        <div class=\"viz mt-s\" style=\"font-size:11.5px\">\n删 45:        45         48\n              /\\\\         /\\\\\n             24 53  →   24 53\n             /\\\\ /\\\\       /\\\\ /\\\\\n            12 28 48 60   12 28  60\n                  (取后继 48 顶上)</div>\n        <h4 class=\"mt-l\">平均 / 最坏</h4>\n        <p class=\"dim mt-s\" style=\"font-size:13px\">随机插入：树高 O(log n)，操作 O(log n)。<br>有序插入：退化为单链表，O(n)。<br>→ 引出 AVL / 红黑树。</p>\n      </div>\n    </div>"}, {"title": "AVL 插入旋转", "content": "<p class=\"kicker\">10 · AVL</p>\n    <h2 class=\"h2\">四种旋转完整图解。</h2>\n    <div class=\"grid g2 mt-l\" style=\"align-items:start\">\n      <div>\n        <h4>平衡因子 BF</h4>\n        <p class=\"dim mt-s\" style=\"font-size:13.5px\">BF(node) = h(左子树) - h(右子树) ∈ {-1, 0, 1}。插入后某节点 BF 变 ±2 即失衡。</p>\n        <h4 class=\"mt-l\">四种失衡 + 调整</h4>\n        <table class=\"cmp-table mt-s\">\n          <tr><th>类型</th><th>失衡发生</th><th>旋转</th></tr>\n          <tr><td>LL</td><td>左孩子的左子树插入</td><td>右单旋</td></tr>\n          <tr><td>RR</td><td>右孩子的右子树插入</td><td>左单旋</td></tr>\n          <tr><td>LR</td><td>左孩子的右子树插入</td><td>先左孩左旋 → 再右旋</td></tr>\n          <tr><td>RL</td><td>右孩子的左子树插入</td><td>先右孩右旋 → 再左旋</td></tr>\n        </table>\n        <p class=\"dim mt-m\" style=\"font-size:13px\">⚠️ 总是从最低失衡节点开始调整。调整后该子树高度不变 → 不会向上传播。</p>\n      </div>\n      <div>\n        <h4>构造例：插入序列 {5, 4, 2, 8, 6, 9}</h4>\n        <div class=\"viz mt-s\" style=\"font-size:11.5px\">\n插 5:    5\n插 4:    5\n        /\n       4\n插 2:    5       LL 失衡 (BF(5)=2)\n        /        右旋 4 →\n       4          4\n      /          /\\\\\n     2          2  5\n插 8:    4\n        /\\\\\n       2  5\n            \\\\\n             8\n插 6:    4         RL 失衡 (BF(5)=-2)\n        /\\\\        子树 5,8 的 8 左插 6\n       2  5        先 8 右旋: 5,6,8\n           \\\\       再 5 左旋: 6 顶上\n            8\n           /\n          6        4\n                  /\\\\\n                 2  6\n                   /\\\\\n                  5  8\n插 9:    4\n        /\\\\\n       2  6\n         /\\\\\n        5  8\n            \\\\\n             9</div>\n      </div>\n    </div>"}, {"title": "红黑树", "content": "<p class=\"kicker\">10 · 红黑树（理解性）</p>\n    <h2 class=\"h2\">弱平衡 → 比 AVL 调整少 → 实际用得最多。</h2>\n    <div class=\"grid g2 mt-l\" style=\"align-items:start\">\n      <div>\n        <h4>5 条性质</h4>\n        <ol class=\"dim mt-s\" style=\"font-size:13.5px;line-height:1.9\">\n          <li>每个节点不是红就是黑</li>\n          <li>根是黑</li>\n          <li>每个叶（NIL）都是黑</li>\n          <li>红节点的子节点必为黑（不存在连续红）</li>\n          <li>从任意节点到其所有叶的简单路径上，黑节点数相同</li>\n        </ol>\n        <h4 class=\"mt-l\">高度结论</h4>\n        <p class=\"mono mt-s\" style=\"background:var(--surface-2);padding:12px;border-radius:8px;font-size:14px\">\n          n 个内节点的红黑树，<br>\n          高度 h ≤ 2·log₂(n + 1)<br>\n          → 查找 / 插入 / 删除 <b>O(log n)</b>\n        </p>\n      </div>\n      <div>\n        <h4>AVL vs 红黑树</h4>\n        <table class=\"cmp-table mt-s\">\n          <tr><th></th><th>AVL</th><th>红黑树</th></tr>\n          <tr><td>平衡严格度</td><td>左右高差 ≤ 1</td><td>路径长之比 ≤ 2</td></tr>\n          <tr><td>查找</td><td>更快</td><td>稍慢</td></tr>\n          <tr><td>插入</td><td>最多 2 次旋转</td><td>最多 2 次旋转 + 颜色翻转</td></tr>\n          <tr><td>删除</td><td>O(log n) 次旋转</td><td>最多 3 次旋转</td></tr>\n          <tr><td>适合</td><td>查找远多于增删</td><td>增删频繁，如 STL map、Linux 进程调度</td></tr>\n        </table>\n        <h4 class=\"mt-l\">408 出题边界</h4>\n        <p class=\"dim mt-s\" style=\"font-size:13px\">大纲只要求\"理解概念与性质\"，不要求手画旋转或插入删除细节。看到红黑题，记住\"性质 + 高度结论\"即可。</p>\n      </div>\n    </div>"}, {"title": "B / B+ 树", "content": "<p class=\"kicker\">11 · 多叉平衡树</p>\n    <h2 class=\"h2\">为磁盘 IO 而生的\"矮胖树\"。</h2>\n    <div class=\"grid g2 mt-l\" style=\"align-items:start\">\n      <div>\n        <h4>m 阶 B 树定义</h4>\n        <ul class=\"dim mt-s\" style=\"font-size:13.5px;line-height:1.85\">\n          <li>每个节点至多 m 个孩子（m-1 个关键字）</li>\n          <li>非根 至少 ⌈m/2⌉ 个孩子（⌈m/2⌉-1 个关键字）</li>\n          <li>根至少 2 个孩子（除非为叶）</li>\n          <li>所有叶在同一层（绝对平衡）</li>\n          <li>关键字升序排列；孩子 = 关键字 + 1</li>\n        </ul>\n        <h4 class=\"mt-l\">插入分裂</h4>\n        <p class=\"dim mt-s\" style=\"font-size:13.5px\">插入总是在叶层。若关键字数 = m，<b>从中间分裂</b>：左半留下、右半新建节点、中间关键字上提到父亲。父亲再满则递归上传。</p>\n        <h4 class=\"mt-l\">删除</h4>\n        <p class=\"dim mt-s\" style=\"font-size:13.5px\">非叶节点关键字 → 用中序后继顶上（化为叶子删除）。叶节点关键字数不足 → 先<b>向兄弟借</b>（旋转），不能借则<b>与兄弟合并</b>，可能引起父亲递归不足。</p>\n      </div>\n      <div>\n        <h4>B+ 树（数据库索引）</h4>\n        <ul class=\"dim mt-s\" style=\"font-size:13.5px;line-height:1.85\">\n          <li>所有<b>数据都在叶</b>，内部节点只是索引</li>\n          <li>叶节点按横向链表连接 → 区间查询 O(log + k)</li>\n          <li>关键字数 = 孩子数（与 B 树差 1）</li>\n          <li>每次查找都要走到叶</li>\n          <li>对应应用：MySQL InnoDB、文件系统目录索引</li>\n        </ul>\n        <h4 class=\"mt-l\">B vs B+ 总览</h4>\n        <table class=\"cmp-table mt-s\">\n          <tr><th></th><th>B 树</th><th>B+ 树</th></tr>\n          <tr><td>数据存放</td><td>非叶+叶</td><td>只在叶</td></tr>\n          <tr><td>关键字数</td><td>孩子-1</td><td>孩子数</td></tr>\n          <tr><td>查找路径</td><td>可能中途命中</td><td>必到叶</td></tr>\n          <tr><td>区间查询</td><td>差</td><td>沿链表很快</td></tr>\n          <tr><td>叶节点链</td><td>无</td><td>有</td></tr>\n        </table>\n      </div>\n    </div>"}, {"title": "图 · 存储遍历", "content": "<p class=\"kicker\">12 · 图</p>\n    <h2 class=\"h2\">两种存储 + 两种遍历。</h2>\n    <div class=\"grid g2 mt-l\" style=\"align-items:start\">\n      <div>\n        <h4>邻接矩阵</h4>\n        <pre class=\"code-block\" style=\"font-size:12.5px\">\n<span class=\"k\">typedef struct</span> {\n  VertexType vex[MaxN];\n  EdgeType edge[MaxN][MaxN];\n  <span class=\"k\">int</span> vexnum, arcnum;\n} MGraph;</pre>\n        <p class=\"dim mt-s\" style=\"font-size:13px\">空间 O(V²)；判 (i,j) 有边 O(1)；列邻接 O(V)。<br>稠密图首选；不便处理稀疏。</p>\n        <h4 class=\"mt-l\">邻接表</h4>\n        <pre class=\"code-block\" style=\"font-size:12.5px\">\n<span class=\"k\">typedef struct</span> ArcNode {\n  <span class=\"k\">int</span> adjvex;\n  <span class=\"k\">struct</span> ArcNode *next;\n} ArcNode;\n<span class=\"k\">typedef struct</span> VNode {\n  VertexType data;\n  ArcNode *first;\n} VNode, AdjList[MaxN];</pre>\n        <p class=\"dim mt-s\" style=\"font-size:13px\">空间 O(V+E)；列邻接 O(度)；稀疏图首选。<br>有向图：出弧链 / 逆邻接表存入弧。</p>\n      </div>\n      <div>\n        <h4>DFS（栈 / 递归）</h4>\n        <pre class=\"code-block\" style=\"font-size:12.5px\">\n<span class=\"k\">bool</span> visited[MaxN] = {<span class=\"k\">false</span>};\n<span class=\"k\">void</span> <span class=\"f\">DFS</span>(Graph G, <span class=\"k\">int</span> v) {\n  visit(v);\n  visited[v] = <span class=\"k\">true</span>;\n  <span class=\"k\">for</span>(w = FirstNeighbor(G, v); w &gt;= 0;\n       w = NextNeighbor(G, v, w))\n    <span class=\"k\">if</span>(!visited[w]) DFS(G, w);\n}\n<span class=\"c\">// 处理非连通图：</span>\n<span class=\"k\">for</span>(<span class=\"k\">int</span> i=0; i&lt;G.vexnum; i++)\n  <span class=\"k\">if</span>(!visited[i]) DFS(G, i);</pre>\n        <h4 class=\"mt-m\">BFS（队列）</h4>\n        <pre class=\"code-block\" style=\"font-size:12.5px\">\n<span class=\"k\">void</span> <span class=\"f\">BFS</span>(Graph G, <span class=\"k\">int</span> v) {\n  visit(v); visited[v] = <span class=\"k\">true</span>;\n  Q.push(v);\n  <span class=\"k\">while</span>(!Q.empty()) {\n    v = Q.pop();\n    <span class=\"k\">for</span>(w = FirstNeighbor(G, v); w &gt;= 0;\n         w = NextNeighbor(G, v, w))\n      <span class=\"k\">if</span>(!visited[w]) {\n        visit(w); visited[w] = <span class=\"k\">true</span>;\n        Q.push(w);\n      }\n  }\n}</pre>\n        <p class=\"dim mt-s\" style=\"font-size:13px\">邻接表：O(V+E)；邻接矩阵：O(V²)。<br>BFS 在无权图中即最短路径算法（层数即距离）。</p>\n      </div>\n    </div>"}, {"title": "最短路径", "content": "<p class=\"kicker\">13 · Dijkstra & Floyd</p>\n    <h2 class=\"h2\">单源 vs 多源；非负权 vs 任意权。</h2>\n    <div class=\"grid g2 mt-l\" style=\"align-items:start\">\n      <div>\n        <h4>Dijkstra · 单源 · 非负权</h4>\n        <ol class=\"dim mt-s\" style=\"font-size:13px;line-height:1.85\">\n          <li>初始 dist[src]=0, 其他=∞，S = {src}</li>\n          <li>取 dist 最小的未确定点 u 加入 S</li>\n          <li>松弛 u 的所有邻居 v：if dist[v] &gt; dist[u]+w(u,v) → 更新</li>\n          <li>重复直到 S 覆盖所有点</li>\n        </ol>\n        <p class=\"mono mt-s\" style=\"font-size:13px;background:var(--surface-2);padding:10px;border-radius:8px\">\n          O(V²) 朴素；O((V+E)log V) 二叉堆<br>\n          O(V log V + E) 斐波那契堆\n        </p>\n        <h4 class=\"mt-l\">手算表格</h4>\n        <div class=\"viz\" style=\"font-size:11.5px\">\n图: 1—(4)—2—(11)—3\n    |       /  \\\\\n    (8)   (8) (2)\n    \\\\    /     \\\\\n     4-(7)-5-(6)-6 ...\ndist 数组每次只更新一个\"已确定\"\n直观写法：每轮列出 dist[], path[]</div>\n      </div>\n      <div>\n        <h4>Floyd · 多源</h4>\n        <pre class=\"code-block\" style=\"font-size:12.5px\">\n<span class=\"k\">int</span> D[V][V];     <span class=\"c\">// 初始为权值</span>\n<span class=\"k\">for</span> k = 0..V-1:\n  <span class=\"k\">for</span> i = 0..V-1:\n    <span class=\"k\">for</span> j = 0..V-1:\n      <span class=\"k\">if</span>(D[i][k]+D[k][j] &lt; D[i][j])\n        D[i][j] = D[i][k]+D[k][j];\n        path[i][j] = k;</pre>\n        <p class=\"dim mt-s\" style=\"font-size:13px\">本质：动态规划。D⁽ᵏ⁾[i][j] = 只经过前 k 个顶点的最短路径。<br>O(V³) 时间、O(V²) 空间。能处理负权但不能有负环。</p>\n        <h4 class=\"mt-l\">何时选谁？</h4>\n        <ul class=\"dim mt-s\" style=\"font-size:13px;line-height:1.85\">\n          <li>只问一对点 / 单源 → Dijkstra（更快）</li>\n          <li>问所有对 → Floyd（写起来简单）</li>\n          <li>有负权 → Floyd 或 Bellman-Ford</li>\n        </ul>\n      </div>\n    </div>"}, {"title": "最小生成树", "content": "<p class=\"kicker\">13 · Prim & Kruskal</p>\n    <h2 class=\"h2\">连通图 V 个顶点的 V-1 条边的最小总权树。</h2>\n    <div class=\"grid g2 mt-l\" style=\"align-items:start\">\n      <div>\n        <h4>Prim · 加点法</h4>\n        <ol class=\"dim mt-s\" style=\"font-size:13px;line-height:1.85\">\n          <li>U = {任一起点 v₀}, V-U = 其余点</li>\n          <li>找 (u∈U, v∈V-U) 中权最小的边 (u,v)</li>\n          <li>把 v 加入 U，把 (u,v) 加入 MST</li>\n          <li>重复 V-1 次</li>\n        </ol>\n        <p class=\"mono mt-s\" style=\"font-size:13px\">O(V²) 朴素 / 适合<b>稠密图</b><br>O(E log V) 用堆</p>\n        <h4 class=\"mt-l\">Kruskal · 加边法</h4>\n        <ol class=\"dim mt-s\" style=\"font-size:13px;line-height:1.85\">\n          <li>所有边按权升序排序</li>\n          <li>依次取权最小、不构成环的边</li>\n          <li>用<b>并查集</b>判环（合并两端点的代表元）</li>\n          <li>选满 V-1 条边</li>\n        </ol>\n        <p class=\"mono mt-s\" style=\"font-size:13px\">O(E log E) 排序主导 / 适合<b>稀疏图</b></p>\n      </div>\n      <div>\n        <h4>并查集 Union-Find</h4>\n        <pre class=\"code-block\" style=\"font-size:12.5px\">\n<span class=\"k\">int</span> parent[N];\n<span class=\"k\">void</span> <span class=\"f\">init</span>() {\n  <span class=\"k\">for</span>(<span class=\"k\">int</span> i=0;i&lt;N;i++) parent[i] = i;\n}\n<span class=\"k\">int</span> <span class=\"f\">find</span>(<span class=\"k\">int</span> x) {\n  <span class=\"k\">if</span>(parent[x] == x) <span class=\"k\">return</span> x;\n  <span class=\"k\">return</span> parent[x] = find(parent[x]);  <span class=\"c\">// 路径压缩</span>\n}\n<span class=\"k\">void</span> <span class=\"f\">unite</span>(<span class=\"k\">int</span> a, <span class=\"k\">int</span> b) {\n  parent[find(a)] = find(b);\n}</pre>\n        <h4 class=\"mt-m\">MST 的两条性质</h4>\n        <ul class=\"dim mt-s\" style=\"font-size:13px;line-height:1.85\">\n          <li><b>切性质</b>：横跨切的最小边一定在某棵 MST 中</li>\n          <li><b>环性质</b>：任意环中权最大的边不在某棵 MST 中</li>\n          <li>所有边权互不相同时 MST 唯一</li>\n        </ul>\n      </div>\n    </div>"}, {"title": "拓扑 + AOE", "content": "<p class=\"kicker\">13 · 有向图</p>\n    <h2 class=\"h2\">拓扑排序 + 关键路径完整过程。</h2>\n    <div class=\"grid g2 mt-l\" style=\"align-items:start\">\n      <div>\n        <h4>AOV 拓扑排序</h4>\n        <ol class=\"dim mt-s\" style=\"font-size:13px;line-height:1.85\">\n          <li>统计每个顶点的入度</li>\n          <li>把入度为 0 的入队</li>\n          <li>反复取队首 → 输出 → 把它的所有邻居入度 -1，新出现的 0 入队</li>\n          <li>若输出节点数 &lt; V，<b>存在环</b></li>\n        </ol>\n        <p class=\"mono mt-s\" style=\"font-size:13px\">O(V+E)。拓扑序不唯一。</p>\n        <h4 class=\"mt-l\">逆拓扑序（DFS）</h4>\n        <p class=\"dim\" style=\"font-size:13px\">DFS 中按\"退栈\"次序输出即得逆拓扑；其反过来即拓扑序。</p>\n      </div>\n      <div>\n        <h4>AOE 关键路径 5 步</h4>\n        <ol class=\"dim mt-s\" style=\"font-size:12.5px;line-height:1.85\">\n          <li>正向遍历拓扑序，求每个事件最早发生 <b>ve(v)</b><br>ve(v₀)=0，ve(v)=max{ve(u) + w(u,v)}</li>\n          <li>逆向遍历拓扑序，求每个事件最迟发生 <b>vl(v)</b><br>vl(终)=ve(终)，vl(u)=min{vl(v) - w(u,v)}</li>\n          <li>每个活动 a=(u,v)：最早开始 e(a)=ve(u)，最迟开始 l(a)=vl(v)-w(u,v)</li>\n          <li>机动时间 d(a) = l(a) - e(a)</li>\n          <li><b>d(a) = 0 的活动构成关键路径</b></li>\n        </ol>\n        <div class=\"viz mt-s\" style=\"font-size:11.5px\">\nve: 沿拓扑顺序取最大\nvl: 沿逆拓扑顺序取最小\n路径长度 = ve(终) = vl(终) = 完工时间</div>\n      </div>\n    </div>"}, {"title": "查找 + 散列", "content": "<p class=\"kicker\">14 · 查找</p>\n    <h2 class=\"h2\">折半判定树 · 散列冲突 · ASL 计算。</h2>\n    <div class=\"grid g2 mt-l\" style=\"align-items:start\">\n      <div>\n        <h4>折半判定树（11 个元素例）</h4>\n        <div class=\"viz mt-s\" style=\"font-size:11.5px\">\n              6\n            /   \\\\\n           3     9\n          /\\\\   /\\\\\n         1  4 7  10\n        /\\\\  /\\\\ \\\\  \\\\\n       0 2 5 / 8  11\nASL 成功 = (1·1 + 2·2 + 3·4 + 4·4) / 11\n       = 33 / 11 = 3\nASL 失败 = 所有 NIL 路径长之和 / 失败节点数</div>\n        <h4 class=\"mt-l\">分块查找</h4>\n        <p class=\"dim mt-s\" style=\"font-size:13px\">块内无序、块间有序。用索引表（每块的最大值 + 起始下标）。<br>ASL = L_I + L_S，L_I=⌈log₂(b+1)⌉ 用折半找块，L_S=(s+1)/2 块内顺序。</p>\n      </div>\n      <div>\n        <h4>散列函数</h4>\n        <ul class=\"dim mt-s\" style=\"font-size:13px;line-height:1.85\">\n          <li>直接定址：H(k) = a·k + b</li>\n          <li>除留余数：H(k) = k mod p（p 取不大于表长的质数）</li>\n          <li>数字分析、平方取中、折叠</li>\n        </ul>\n        <h4 class=\"mt-m\">冲突处理</h4>\n        <ul class=\"dim mt-s\" style=\"font-size:13px;line-height:1.85\">\n          <li>开放定址<br>· 线性探测 H_i = (H+i) mod m → 易堆积<br>· 平方探测 H_i = (H + ±i²) mod m<br>· 双散列 H_i = (H + i·H₂(k)) mod m</li>\n          <li>拉链法：每槽位是链表，删除安全</li>\n        </ul>\n        <h4 class=\"mt-m\">ASL 计算示例（除留 + 线性探测）</h4>\n        <div class=\"viz\" style=\"font-size:11px\">\n表长 13, 关键字 19, 14, 23, 1, 68, 20\nH(k) = k mod 13\nH(19)=6, H(14)=1, H(23)=10, H(1)=1+1, H(68)=3+0, H(20)=7\n冲突情况：14 占 1；1 探测 1→2 共 2 次\nASL_succ = (1·5 + 2·1)/6 = 7/6 ≈ 1.17</div>\n      </div>\n    </div>"}, {"title": "排序大全", "content": "<p class=\"kicker\">15 · 排序</p>\n    <h2 class=\"h2\">八大排序 + 代码 + 适用场景。</h2>\n    <table class=\"cmp-table mt-l\">\n      <thead><tr><th>算法</th><th>平均</th><th>最坏</th><th>空间</th><th>稳定</th><th>核心思想</th></tr></thead>\n      <tbody>\n        <tr><td><b>直接插入</b></td><td class=\"mono\">O(n²)</td><td class=\"mono\">O(n²)</td><td>O(1)</td><td>✅</td><td>哨兵 + 逐个比较后移</td></tr>\n        <tr><td><b>希尔</b></td><td class=\"mono\">~O(n^1.3)</td><td class=\"mono\">O(n²)</td><td>O(1)</td><td>❌</td><td>分组插入，缩小增量</td></tr>\n        <tr><td><b>冒泡</b></td><td class=\"mono\">O(n²)</td><td class=\"mono\">O(n²)</td><td>O(1)</td><td>✅</td><td>相邻交换</td></tr>\n        <tr><td><b>快速</b></td><td class=\"mono\">O(n log n)</td><td class=\"mono\">O(n²)</td><td>O(log n)</td><td>❌</td><td>分治：枢轴划分</td></tr>\n        <tr><td><b>直接选择</b></td><td class=\"mono\">O(n²)</td><td class=\"mono\">O(n²)</td><td>O(1)</td><td>❌</td><td>每轮选最小</td></tr>\n        <tr><td><b>堆排序</b></td><td class=\"mono\">O(n log n)</td><td class=\"mono\">O(n log n)</td><td>O(1)</td><td>❌</td><td>大根堆 + 顶尾交换</td></tr>\n        <tr><td><b>归并</b></td><td class=\"mono\">O(n log n)</td><td class=\"mono\">O(n log n)</td><td>O(n)</td><td>✅</td><td>分治：合并有序段</td></tr>\n        <tr><td><b>基数</b></td><td class=\"mono\">O(d(n+r))</td><td class=\"mono\">O(d(n+r))</td><td>O(n+r)</td><td>✅</td><td>位排序 + 桶</td></tr>\n      </tbody>\n    </table>\n    <div class=\"grid g2 mt-l\">\n      <div>\n        <h4>快排核心代码</h4>\n        <pre class=\"code-block\" style=\"font-size:12px\">\n<span class=\"k\">int</span> <span class=\"f\">partition</span>(<span class=\"k\">int</span> *a, <span class=\"k\">int</span> l, <span class=\"k\">int</span> r) {\n  <span class=\"k\">int</span> pivot = a[l];\n  <span class=\"k\">while</span>(l &lt; r) {\n    <span class=\"k\">while</span>(l &lt; r &amp;&amp; a[r] &gt;= pivot) r--;\n    a[l] = a[r];\n    <span class=\"k\">while</span>(l &lt; r &amp;&amp; a[l] &lt;= pivot) l++;\n    a[r] = a[l];\n  }\n  a[l] = pivot;\n  <span class=\"k\">return</span> l;\n}\n<span class=\"k\">void</span> <span class=\"f\">quickSort</span>(<span class=\"k\">int</span> *a, <span class=\"k\">int</span> l, <span class=\"k\">int</span> r) {\n  <span class=\"k\">if</span>(l &gt;= r) <span class=\"k\">return</span>;\n  <span class=\"k\">int</span> p = partition(a, l, r);\n  quickSort(a, l, p-1);\n  quickSort(a, p+1, r);\n}</pre>\n      </div>\n      <div>\n        <h4>记忆口诀</h4>\n        <ul class=\"dim mt-s\" style=\"font-size:13px;line-height:1.85\">\n          <li><b>稳定五连</b>：插入 / 冒泡 / 归并 / 基数 / 计数</li>\n          <li><b>原地 O(1) 空间</b>：插入 / 希尔 / 冒泡 / 选择 / 堆</li>\n          <li><b>无关初始序</b>：选择 / 归并 / 基数 / 堆</li>\n          <li><b>最坏退化</b>：快速 O(n²)；其他多为最坏 = 平均</li>\n        </ul>\n        <h4 class=\"mt-m\">外部排序</h4>\n        <p class=\"dim mt-s\" style=\"font-size:13px\">归并段 + k 路败者树。读取磁盘块 → 内排序 → 归并写回。性能瓶颈：IO 次数。优化：增大归并段长度、增加归并路数。</p>\n      </div>\n    </div>"}]}, "computer-organization": {"title": "计算机组成原理", "weight": "45分", "slides": [{"title": "Cover", "content": "<p class=\"kicker\">408 · COMPUTER ORGANIZATION · 唐朔飞 / 白中英 完整版</p>\n    <h1 class=\"h1 huge anim-fade-up\" data-anim=\"fade-up\">计算机组成原理</h1>\n    <h2 class=\"h2\" style=\"font-weight:400;color:var(--text-2);margin-top:-8px\"><span class=\"gradient-text\">从一根线、一个门</span>，到一台能跑程序的机器。</h2>\n    <p class=\"lede mt-l\">28 节课，覆盖王道 8 章。从二进制编码、定点 / 浮点运算，到存储层次、Cache 算例、指令系统、CPU、流水线、总线、IO 完整链路。</p>\n    <div class=\"label-strip\">\n      <span class=\"pill\">~45 分</span>\n      <span class=\"pill\">8 章 28 节</span>\n      <span class=\"pill\">大题：Cache + 指令 + 流水线</span>\n    </div>"}, {"title": "目录", "content": "<p class=\"kicker\">// agenda</p>\n    <h2 class=\"h2\">28 张卡片：从 0/1 到完整计算机</h2>\n    <div class=\"grid g3 mt-l\" style=\"gap:24px;font-size:13px\">\n      <div>\n        <h4 style=\"font-size:15px\">数据 & 运算</h4>\n        <ol class=\"steps mt-s\" style=\"counter-reset:s 0\">\n          <li>计算机性能指标</li>\n          <li>进制 + 原反补移</li>\n          <li>补码运算 + 溢出</li>\n          <li>IEEE 754 浮点</li>\n          <li>浮点运算</li>\n          <li>加法器与 CLA</li>\n          <li>原码 + Booth 乘法</li>\n          <li>定点除法</li>\n        </ol>\n      </div>\n      <div>\n        <h4 style=\"font-size:15px\">存储 & 指令</h4>\n        <ol class=\"steps mt-s\" style=\"counter-reset:s 8\">\n          <li>存储层次</li>\n          <li>SRAM / DRAM 内部</li>\n          <li>ROM 家族</li>\n          <li>主存扩展</li>\n          <li>Cache 三种映射</li>\n          <li>Cache 替换 + 写</li>\n          <li>虚拟存储与 TLB</li>\n          <li>指令格式 + 寻址</li>\n        </ol>\n      </div>\n      <div>\n        <h4 style=\"font-size:15px\">CPU & IO</h4>\n        <ol class=\"steps mt-s\" style=\"counter-reset:s 16\">\n          <li>CPU 内部结构</li>\n          <li>数据通路</li>\n          <li>控制器（硬布线/微程序）</li>\n          <li>流水线五段</li>\n          <li>流水线性能 + 冒险</li>\n          <li>总线分类</li>\n          <li>总线仲裁 / 通信</li>\n          <li>中断完整流程</li>\n          <li>IO 控制方式</li>\n          <li>整机一图回顾</li>\n        </ol>\n      </div>\n    </div>"}, {"title": "性能指标", "content": "<p class=\"kicker\">01 · 性能</p>\n    <h2 class=\"h2\">字长 · 主频 · CPI · MIPS · MFLOPS。</h2>\n    <div class=\"grid g2 mt-l\" style=\"align-items:start\">\n      <div>\n        <h4>核心定义</h4>\n        <ul class=\"dim mt-s\" style=\"font-size:14px;line-height:1.9\">\n          <li><b>字长</b>：CPU 一次处理的二进制位数（8/16/32/64）</li>\n          <li><b>主频 f</b>：时钟频率（Hz），周期 T = 1/f</li>\n          <li><b>CPI</b>：每条指令平均周期数</li>\n          <li><b>MIPS</b>：百万条指令/秒</li>\n          <li><b>MFLOPS</b>：百万浮点运算/秒</li>\n        </ul>\n        <h4 class=\"mt-l\">关键公式</h4>\n        <p class=\"mono mt-s\" style=\"font-size:13.5px;background:var(--surface-2);padding:12px;border-radius:8px;line-height:1.95\">\n          T_程序 = 指令数 × CPI × T_时钟<br>\n          &emsp;&emsp;&emsp;= 指令数 × CPI / f<br><br>\n          MIPS = f / (CPI × 10⁶)<br>\n          加速比 S = T_old / T_new\n        </p>\n      </div>\n      <div>\n        <h4>Amdahl 定律</h4>\n        <p class=\"mono mt-s\" style=\"font-size:13.5px;background:var(--surface-2);padding:12px;border-radius:8px;line-height:1.95\">\n          S = 1 / [(1-f) + f/p]<br>\n          <span class=\"dim\">// f: 可加速比例, p: 加速倍数</span>\n        </p>\n        <p class=\"dim mt-s\" style=\"font-size:13px\">例：90% 可并行，10% 串行。无论多少处理器，最大加速 = 1/0.1 = 10。</p>\n        <h4 class=\"mt-l\">基准程序 Benchmark</h4>\n        <ul class=\"dim mt-s\" style=\"font-size:13px;line-height:1.85\">\n          <li>SPEC CPU：综合整数/浮点</li>\n          <li>TPC：事务处理</li>\n          <li>Linpack：高性能计算</li>\n        </ul>\n        <h4 class=\"mt-m\">三种地址</h4>\n        <ul class=\"dim mt-s\" style=\"font-size:13px;line-height:1.85\">\n          <li>主存物理地址：内存芯片真实地址</li>\n          <li>逻辑/虚拟地址：进程视角</li>\n          <li>指令地址：取指地址</li>\n        </ul>\n      </div>\n    </div>"}, {"title": "进制 + 编码", "content": "<p class=\"kicker\">02 · 数据表示</p>\n    <h2 class=\"h2\">原码 / 反码 / 补码 / 移码（8 位为例）。</h2>\n    <div class=\"grid g2 mt-l\" style=\"align-items:start\">\n      <div>\n        <h4>对比表</h4>\n        <table class=\"cmp-table mt-s\">\n          <tr><th></th><th>+0</th><th>-0</th><th>范围</th></tr>\n          <tr><td>原码</td><td>0 0000000</td><td>1 0000000</td><td>−127~+127</td></tr>\n          <tr><td>反码</td><td>0 0000000</td><td>1 1111111</td><td>−127~+127</td></tr>\n          <tr><td>补码</td><td colspan=\"2\">唯一 0 0000000</td><td>−128~+127</td></tr>\n          <tr><td>移码</td><td colspan=\"2\">补码符号位取反</td><td>同补码</td></tr>\n        </table>\n        <h4 class=\"mt-l\">转换口诀</h4>\n        <ul class=\"dim mt-s\" style=\"font-size:13.5px;line-height:1.85\">\n          <li>正数：三码相同</li>\n          <li>负数：反码 = 原码符号位不动其余取反</li>\n          <li>负数：补码 = 反码 + 1（或原码符号位不动其余取反末位+1）</li>\n          <li>补码 → 真值：补码再取一次补码，加负号</li>\n        </ul>\n      </div>\n      <div>\n        <h4>典型转换例</h4>\n        <p class=\"mono\" style=\"font-size:13.5px\">x = -22 (8 位)</p>\n        <pre class=\"code-block\" style=\"font-size:12.5px\">\n|x| = 22 = 00010110\n原码 = 1 0010110\n反码 = 1 1101001  (除符号位取反)\n补码 = 1 1101010  (反码 +1)\n移码 = 0 1101010  (补码符号位取反)</pre>\n        <h4 class=\"mt-l\">三种进制互换</h4>\n        <div class=\"viz mt-s\" style=\"font-size:12px\">\n2 → 10:  按位权展开\n2 → 16:  4 位一组\n10 → 2: 整数除 2 取余, 小数乘 2 取整\n例 0.625 → 二进制:\n  0.625 × 2 = 1.25  → 1\n  0.25  × 2 = 0.50  → 0\n  0.50  × 2 = 1.00  → 1\n结果: 0.101</div>\n      </div>\n    </div>"}, {"title": "补码运算", "content": "<p class=\"kicker\">02 · 加减乘除</p>\n    <h2 class=\"h2\">补码加减法 + 三种溢出判定。</h2>\n    <div class=\"grid g2 mt-l\" style=\"align-items:start\">\n      <div>\n        <h4>补码加法规则</h4>\n        <p class=\"dim mt-s\" style=\"font-size:13.5px\">[A]补 + [B]补 = [A+B]补<br>[A-B]补 = [A]补 + [-B]补<br><b>符号位一起参加运算</b>，进位丢弃。</p>\n        <h4 class=\"mt-l\">三种溢出判定</h4>\n        <table class=\"cmp-table mt-s\">\n          <tr><th>方法</th><th>判别</th></tr>\n          <tr><td>双符号位</td><td>结果符号位为 01 → 上溢, 10 → 下溢</td></tr>\n          <tr><td>单符号位 + 进位</td><td>最高位进位 C_s ≠ 次高位进位 C_{s-1} → 溢出</td></tr>\n          <tr><td>OF 标志</td><td>同号相加，结果异号 → 溢出</td></tr>\n        </table>\n        <h4 class=\"mt-l\">实例</h4>\n        <pre class=\"code-block\" style=\"font-size:12.5px\">\nA = +120 = 01111000\nB = +50  = 00110010\nA+B  =    10101010 (= -86?)\n真值: 120+50 = 170 &gt; 127 → 溢出!\n双符: 0 0|1111000 + 0 0|0110010\n       = 0 1|0101010 → 01 上溢</pre>\n      </div>\n      <div>\n        <h4>定点小数 vs 整数</h4>\n        <p class=\"dim mt-s\" style=\"font-size:13.5px\">定点表示：小数点位置约定，硬件不存。<br><b>定点纯整数</b>：小数点在最低位之右<br><b>定点纯小数</b>：小数点在符号位之右</p>\n        <h4 class=\"mt-l\">逻辑移位 vs 算术移位</h4>\n        <table class=\"cmp-table mt-s\">\n          <tr><th></th><th>左移</th><th>右移</th></tr>\n          <tr><td>逻辑</td><td>末补 0</td><td>首补 0</td></tr>\n          <tr><td>算术 (原码)</td><td>符号位不变,末补 0</td><td>符号位不变,首补 0</td></tr>\n          <tr><td>算术 (补码)</td><td>符号位不变,末补 0</td><td>符号位不变,首补符号位</td></tr>\n          <tr><td>意义</td><td>×2 (溢出注意)</td><td>÷2</td></tr>\n        </table>\n      </div>\n    </div>"}, {"title": "IEEE 754", "content": "<p class=\"kicker\">03 · 浮点</p>\n    <h2 class=\"h2\">符号 · 阶码（移码）· 尾数</h2>\n    <div class=\"grid g2 mt-l\" style=\"align-items:start\">\n      <div>\n        <h4>三种规格</h4>\n        <p class=\"dim mt-s\" style=\"font-size:13px\">单精度 32 bit：S(1) | E(8) | M(23)，偏置 127</p>\n        <p class=\"dim\" style=\"font-size:13px\">双精度 64 bit：S(1) | E(11) | M(52)，偏置 1023</p>\n        <h4 class=\"mt-l\">规格化数</h4>\n        <p class=\"mono mt-s\" style=\"font-size:14px;background:var(--surface-2);padding:12px;border-radius:8px\">\n          值 = (−1)^S × 1.M × 2^(E−bias)\n        </p>\n        <p class=\"dim mt-s\" style=\"font-size:13px\">尾数最高位\"1\"隐含不存 → 多 1 位精度。</p>\n        <h4 class=\"mt-m\">四种特殊值</h4>\n        <table class=\"cmp-table mt-s\">\n          <tr><th>E</th><th>M</th><th>意义</th></tr>\n          <tr><td>00…0</td><td>0</td><td>±0</td></tr>\n          <tr><td>00…0</td><td>≠0</td><td>非规格化数（接近 0）</td></tr>\n          <tr><td>11…1</td><td>0</td><td>±∞</td></tr>\n          <tr><td>11…1</td><td>≠0</td><td>NaN</td></tr>\n        </table>\n      </div>\n      <div>\n        <h4>完整算例：5.75 → IEEE 754 单精度</h4>\n        <pre class=\"code-block\" style=\"font-size:12.5px\">\n5.75 = 101.11(二)\n     = 1.0111 × 2²\nS = 0\nE = 2 + 127 = 129 = 10000001\nM = 0111000_0000000_0000000 0  (23位)\n结果: 0 10000001 01110000...0\nHEX:  0x40B80000\n反过来: 0xC2820000 是多少?\nS=1, E=10000101=133, M=00000100...0\n值 = -1.0000100... × 2^(133-127)\n   = -1.03125 × 64\n   = -66.0</pre>\n        <h4 class=\"mt-m\">表示范围</h4>\n        <p class=\"mono mt-s\" style=\"font-size:12.5px;background:var(--surface-2);padding:10px;border-radius:8px\">\n          单精度最大 ≈ 3.4×10³⁸<br>\n          单精度最小（规格化）≈ 1.18×10⁻³⁸<br>\n          精度 ≈ 7 位十进制\n        </p>\n      </div>\n    </div>"}, {"title": "浮点运算", "content": "<p class=\"kicker\">03 · 浮点</p>\n    <h2 class=\"h2\">对阶 → 尾数运算 → 规格化 → 舍入。</h2>\n    <div class=\"grid g2 mt-l\" style=\"align-items:start\">\n      <div>\n        <h4>加减法 5 步</h4>\n        <ol class=\"steps mt-s\" style=\"counter-reset:s 0\">\n          <li>对阶：<b>小阶向大阶看齐</b>（小阶尾数右移，阶码加）</li>\n          <li>尾数求和（差）</li>\n          <li>规格化：左规 / 右规<br>左规：尾数首两位异号，左移 + 阶码减<br>右规：尾数溢出，右移 + 阶码加</li>\n          <li>舍入：就近偶舍入、0 舍 1 入</li>\n          <li>溢出判断：阶码上溢 → ∞</li>\n        </ol>\n      </div>\n      <div>\n        <h4>实例</h4>\n        <pre class=\"code-block\" style=\"font-size:12px\">\nA = 0.1101 × 2^011\nB = 0.1011 × 2^001\nstep1 对阶: B → 0.001011 × 2^011\nstep2 加:   0.1101    0\n          + 0.001011  0\n          = 0.111111  0\nstep3 规格化: 已规格化\nstep4 舍入:   保持 0.1111 (4 位)\nstep5 溢出:   无\n结果 = 0.1111 × 2^011</pre>\n        <h4 class=\"mt-m\">乘除法</h4>\n        <p class=\"dim mt-s\" style=\"font-size:13px\">乘法：阶码相加，尾数相乘，结果规格化。<br>除法：阶码相减，尾数相除，结果规格化。</p>\n        <h4 class=\"mt-m\">舍入方式</h4>\n        <ul class=\"dim mt-s\" style=\"font-size:12.5px;line-height:1.85\">\n          <li><b>就近偶</b>：默认；中间数向偶数舍</li>\n          <li>朝零 / 朝正无穷 / 朝负无穷</li>\n          <li>0 舍 1 入：截断高位为 1 时+1</li>\n        </ul>\n      </div>\n    </div>"}, {"title": "加法器 / CLA", "content": "<p class=\"kicker\">04 · ALU 内部</p>\n    <h2 class=\"h2\">从全加器到 CLA 先行进位。</h2>\n    <div class=\"grid g2 mt-l\" style=\"align-items:start\">\n      <div>\n        <h4>半加器 vs 全加器</h4>\n        <table class=\"cmp-table mt-s\">\n          <tr><th></th><th>半加器</th><th>全加器</th></tr>\n          <tr><td>输入</td><td>A, B</td><td>A, B, Cin</td></tr>\n          <tr><td>Sum</td><td>A⊕B</td><td>A⊕B⊕Cin</td></tr>\n          <tr><td>Cout</td><td>AB</td><td>AB + (A⊕B)Cin</td></tr>\n        </table>\n        <h4 class=\"mt-l\">串行进位 CRA</h4>\n        <p class=\"dim mt-s\" style=\"font-size:13.5px\">n 个全加器首尾串接，C_i+1 = G_i + P_i · C_i。<br>延迟 O(n)，每级 2 个门级延迟。</p>\n        <p class=\"mono mt-s\" style=\"font-size:13px;background:var(--surface-2);padding:10px;border-radius:8px\">\n          G_i = A_i · B_i &nbsp;<span class=\"dim\">// 生成</span><br>\n          P_i = A_i ⊕ B_i &nbsp;<span class=\"dim\">// 传播</span>\n        </p>\n      </div>\n      <div>\n        <h4>先行进位 CLA</h4>\n        <p class=\"dim mt-s\" style=\"font-size:13.5px\">把 C_i+1 完全用 G_0..G_i、P_0..P_i、C_0 展开 → 不再依赖前一级。</p>\n        <p class=\"mono mt-s\" style=\"font-size:12.5px;background:var(--surface-2);padding:10px;border-radius:8px;line-height:1.85\">\n          C₁ = G₀ + P₀·C₀<br>\n          C₂ = G₁ + P₁·G₀ + P₁·P₀·C₀<br>\n          C₃ = G₂ + P₂·G₁ + P₂·P₁·G₀ + …\n        </p>\n        <p class=\"dim mt-s\" style=\"font-size:13px\">单级 CLA 不可能做得很大（指数级门数）。实际：4 位一组 CLA，组间再 CLA → O(log n) 延迟。</p>\n        <h4 class=\"mt-l\">ALU 结构</h4>\n        <p class=\"dim mt-s\" style=\"font-size:13px\">ALU = 加法器 + 控制信号选择运算（+ / − / AND / OR / XOR）。复杂运算（×/÷）由多个加减循环完成。</p>\n      </div>\n    </div>"}, {"title": "原码 + Booth 乘法", "content": "<p class=\"kicker\">05 · 乘法</p>\n    <h2 class=\"h2\">原码一位乘 + 补码 Booth。</h2>\n    <div class=\"grid g2 mt-l\" style=\"align-items:start\">\n      <div>\n        <h4>原码一位乘</h4>\n        <ol class=\"dim mt-s\" style=\"font-size:13px;line-height:1.85\">\n          <li>符号位单独 XOR 决定结果符号</li>\n          <li>数值部分按绝对值乘</li>\n          <li>初始部分积 = 0；乘数末位为 1 → +|X|，否则 +0</li>\n          <li>部分积逻辑右移 1 位</li>\n          <li>n 位乘数循环 n 次</li>\n        </ol>\n        <p class=\"mono mt-s\" style=\"font-size:13px\">X = 0.1101, Y = 0.1011</p>\n        <pre class=\"code-block\" style=\"font-size:12px\">\n部分积      乘数\n00.0000   1011\n+ X=0.1101\n00.1101 → 右移\n00.01101  1101.1...    Y末位1→+X\n+ X\n01.00111 → 右移\n00.10011 11.01...      Y末位1→+X\n+ X\n01.01111 → 右移\n00.101111 1.110...     Y末位0→不加\n+ 0\n00.101111 → 右移\n00.0101111  1.1110     Y末位1→+X\n+ X\n01.0010111 → 右移\n00.10010111  完成\n结果: +0.10001111  (5/8 × 11/16)</pre>\n      </div>\n      <div>\n        <h4>Booth 补码乘法</h4>\n        <p class=\"dim mt-s\" style=\"font-size:13.5px\">乘数末尾加附加位 Y_n+1 = 0。每次比较 (Y_n, Y_n+1)：</p>\n        <table class=\"cmp-table mt-s\">\n          <tr><th>Y_n Y_n+1</th><th>操作</th></tr>\n          <tr><td>0 0 / 1 1</td><td>+0, 右移</td></tr>\n          <tr><td>0 1</td><td>+[X]补, 右移</td></tr>\n          <tr><td>1 0</td><td>−[X]补 = +[-X]补, 右移</td></tr>\n        </table>\n        <p class=\"dim mt-s\" style=\"font-size:13px\">n 位补码乘 → n 次操作（自动处理符号）。结果即直接为乘积补码。</p>\n        <h4 class=\"mt-l\">两位 Booth</h4>\n        <p class=\"dim mt-s\" style=\"font-size:13px\">同时看 3 位 (Y_n−1, Y_n, Y_n+1)，每次右移 2 位 → 减半操作次数。实际硬件常用。</p>\n      </div>\n    </div>"}, {"title": "定点除法", "content": "<p class=\"kicker\">05 · 除法</p>\n    <h2 class=\"h2\">恢复余数 vs 加减交替。</h2>\n    <div class=\"grid g2 mt-l\" style=\"align-items:start\">\n      <div>\n        <h4>原码恢复余数法</h4>\n        <ol class=\"dim mt-s\" style=\"font-size:13px;line-height:1.85\">\n          <li>余数 R = 被除数 X</li>\n          <li>R = R − Y</li>\n          <li>若 R ≥ 0：商位 = 1</li>\n          <li>若 R &lt; 0：商位 = 0，<b>恢复 R = R + Y</b></li>\n          <li>R 左移一位</li>\n          <li>循环 n 次</li>\n        </ol>\n        <p class=\"dim mt-s\" style=\"font-size:13px\">缺点：恢复操作浪费时间；步骤数不定。</p>\n      </div>\n      <div>\n        <h4>加减交替法（不恢复余数）</h4>\n        <ol class=\"dim mt-s\" style=\"font-size:13px;line-height:1.85\">\n          <li>余数 R 与除数 Y 同号 → 商 1，R = R − Y</li>\n          <li>余数 R 与除数 Y 异号 → 商 0，R = R + Y</li>\n          <li>每次 R 左移一位</li>\n          <li>n 步后得到 n 位商</li>\n          <li>最后若末位上商 0，可加 Y 恢复正余数</li>\n        </ol>\n        <p class=\"dim mt-s\" style=\"font-size:13px\">优点：步骤数固定，硬件实现简洁。补码除法的标准算法。</p>\n        <h4 class=\"mt-l\">除法溢出</h4>\n        <p class=\"dim mt-s\" style=\"font-size:13px\">商超出表示范围（如 0.X / 0.Y 商 ≥ 1）→ 触发溢出异常。</p>\n      </div>\n    </div>"}, {"title": "存储层次", "content": "<p class=\"kicker\">06 · 存储</p>\n    <h2 class=\"h2\">金字塔 + 局部性原理 = 高速 / 大容量错觉。</h2>\n    <div class=\"grid g2 mt-l\" style=\"align-items:start\">\n      <div>\n        <div class=\"viz mt-s\" style=\"font-size:12px\">\n寄存器  ←→  ns       数十字节\nCache    ←→  ns       数十 MB\nTLB      ←→  ns       数百项\n主存      ←→  100ns    GB\nSSD       ←→  μs       TB\nHDD       ←→  ms       TB\n向上: 快、小、贵\n向下: 慢、大、便宜</div>\n        <h4 class=\"mt-l\">局部性原理</h4>\n        <ul class=\"dim mt-s\" style=\"font-size:13.5px;line-height:1.85\">\n          <li><b>时间局部性</b>：刚访问的近期还会用</li>\n          <li><b>空间局部性</b>：附近地址会被一起用</li>\n          <li>循环、数组遍历、子程序 → 局部性强</li>\n          <li>随机访问 → 局部性差，Cache 无效</li>\n        </ul>\n      </div>\n      <div>\n        <h4>三级存储观点</h4>\n        <ul class=\"dim mt-s\" style=\"font-size:13.5px;line-height:1.85\">\n          <li><b>Cache-主存</b>：硬件管理，对编程透明</li>\n          <li><b>主存-辅存（虚拟存储）</b>：硬件+OS 共同管，对编程透明</li>\n          <li><b>主存-辅存（文件系统）</b>：OS 管，编程感知</li>\n        </ul>\n        <h4 class=\"mt-l\">三种存储分类</h4>\n        <table class=\"cmp-table mt-s\">\n          <tr><th>按介质</th><td>半导体 / 磁表面 / 光</td></tr>\n          <tr><th>按存取方式</th><td>RAM (随机) / 顺序 (磁带) / 直接 (磁盘)</td></tr>\n          <tr><th>易失性</th><td>RAM 易失 / ROM 不易失</td></tr>\n          <tr><th>可改写</th><td>RAM 可改 / ROM 多次改 / 只读</td></tr>\n        </table>\n        <p class=\"dim mt-s\" style=\"font-size:13px\">CPU 访问主存的两个指标：<b>带宽</b>（每秒字节）+ <b>访存时间</b>。</p>\n      </div>\n    </div>"}, {"title": "SRAM / DRAM", "content": "<p class=\"kicker\">06 · 半导体存储器</p>\n    <h2 class=\"h2\">触发器 vs 电容：两种主存技术。</h2>\n    <div class=\"grid g2 mt-l\" style=\"align-items:start\">\n      <div>\n        <table class=\"cmp-table mt-s\">\n          <tr><th></th><th>SRAM</th><th>DRAM</th></tr>\n          <tr><td>存储元</td><td>双稳态触发器（6T）</td><td>电容（1T1C）</td></tr>\n          <tr><td>每位元件</td><td>6 个晶体管</td><td>1 个晶体管 + 1 电容</td></tr>\n          <tr><td>速度</td><td>快（几 ns）</td><td>慢（几十 ns）</td></tr>\n          <tr><td>密度</td><td>低</td><td>高 (~4 倍)</td></tr>\n          <tr><td>是否刷新</td><td>否</td><td>需要（电荷会泄漏）</td></tr>\n          <tr><td>功耗</td><td>低（静态）</td><td>较高（刷新）</td></tr>\n          <tr><td>价格</td><td>贵</td><td>便宜</td></tr>\n          <tr><td>用途</td><td>Cache、寄存器</td><td>主存（DDR）</td></tr>\n        </table>\n      </div>\n      <div>\n        <h4>DRAM 刷新</h4>\n        <p class=\"dim mt-s\" style=\"font-size:13.5px\">每隔 2 ms 必须刷一遍（电容电荷保持时间）。3 种方式：</p>\n        <ul class=\"dim mt-s\" style=\"font-size:13px;line-height:1.85\">\n          <li><b>集中刷新</b>：每 2 ms 内集中刷一段时间（停止访存的\"死区\"）</li>\n          <li><b>分散刷新</b>：每次访存后顺便刷一行 → 访存周期变长</li>\n          <li><b>异步刷新</b>：每行单独定时 → 折中</li>\n        </ul>\n        <p class=\"dim mt-s\" style=\"font-size:13px\">若主存有 128 行 → 集中需 128 × 0.5μs = 64μs\"死区\"；分散将访存周期从 0.5μs 增至 1μs。</p>\n        <h4 class=\"mt-l\">DRAM 行列地址复用</h4>\n        <p class=\"dim mt-s\" style=\"font-size:13px\">为减少地址引脚，DRAM 把地址分行 / 列两次发送（RAS / CAS 选通信号）。</p>\n        <h4 class=\"mt-m\">现代 DRAM</h4>\n        <p class=\"dim mt-s\" style=\"font-size:13px\">SDRAM → DDR → DDR2/3/4/5；带宽提升靠预取 + 并行 bank。</p>\n      </div>\n    </div>"}, {"title": "ROM 家族", "content": "<p class=\"kicker\">06 · ROM</p>\n    <h2 class=\"h2\">五种 ROM 各自的\"擦写性\"。</h2>\n    <div class=\"grid g2 mt-l\" style=\"align-items:start\">\n      <div>\n        <table class=\"cmp-table mt-s\">\n          <tr><th>类型</th><th>编程方式</th><th>擦写</th></tr>\n          <tr><td>掩膜 ROM</td><td>出厂时光刻</td><td>不可改</td></tr>\n          <tr><td>PROM</td><td>一次性熔丝</td><td>仅写一次</td></tr>\n          <tr><td>EPROM</td><td>电写紫外擦</td><td>可重复</td></tr>\n          <tr><td>EEPROM</td><td>电写电擦</td><td>可按字节擦</td></tr>\n          <tr><td>Flash</td><td>电写电擦</td><td>按块擦</td></tr>\n        </table>\n        <h4 class=\"mt-l\">应用场景</h4>\n        <ul class=\"dim mt-s\" style=\"font-size:13px;line-height:1.85\">\n          <li>掩膜：大量生产的固件</li>\n          <li>EEPROM：BIOS / 配置数据</li>\n          <li>Flash：SSD / U 盘 / 手机存储</li>\n        </ul>\n      </div>\n      <div>\n        <h4>Flash 内部</h4>\n        <p class=\"dim mt-s\" style=\"font-size:13.5px\">NOR Flash：按字节访问，可直接执行代码（XIP）；常用于 BIOS。<br>NAND Flash：按页 / 块访问，密度高；用于 SSD、U 盘。</p>\n        <h4 class=\"mt-l\">SSD vs HDD</h4>\n        <table class=\"cmp-table mt-s\">\n          <tr><th></th><th>HDD</th><th>SSD</th></tr>\n          <tr><td>介质</td><td>磁盘</td><td>NAND Flash</td></tr>\n          <tr><td>随机读</td><td>~10ms</td><td>~50μs</td></tr>\n          <tr><td>抗振</td><td>差</td><td>好</td></tr>\n          <tr><td>寿命</td><td>长（机械）</td><td>有写次数限制（磨损）</td></tr>\n          <tr><td>FTL</td><td>无</td><td>有（闪存翻译层 + 磨损均衡）</td></tr>\n        </table>\n      </div>\n    </div>"}, {"title": "主存扩展", "content": "<p class=\"kicker\">06 · 容量扩展</p>\n    <h2 class=\"h2\">位扩展 · 字扩展 · 字位扩展。</h2>\n    <div class=\"grid g2 mt-l\" style=\"align-items:start\">\n      <div>\n        <h4>位扩展</h4>\n        <p class=\"dim mt-s\" style=\"font-size:13.5px\">每字位数不够 → 多片<b>并行</b>组合。共用地址线，各管自己的数据位。</p>\n        <div class=\"viz mt-s\" style=\"font-size:12px\">\n8K×4 → 扩成 8K×8：用两片\n                  A0~A12 同时给两片\n                  片1 → D0~D3\n                  片2 → D4~D7</div>\n        <h4 class=\"mt-m\">字扩展</h4>\n        <p class=\"dim mt-s\" style=\"font-size:13.5px\">字数不够 → 多片<b>串接</b>。共用数据线，地址多出的高位用来选片（片选信号）。</p>\n        <div class=\"viz mt-s\" style=\"font-size:12px\">\n8K×8 → 扩成 16K×8：用两片\n                   A0~A12 给两片\n                   A13 → 译码器 → CS₁/CS₂\n                   D0~D7 共享</div>\n      </div>\n      <div>\n        <h4>字位扩展（同时）</h4>\n        <p class=\"dim mt-s\" style=\"font-size:13.5px\">例：用 1K×4 芯片，组成 4K×8 主存。</p>\n        <p class=\"mono mt-s\" style=\"font-size:13px;background:var(--surface-2);padding:12px;border-radius:8px\">\n          需芯片数 = (4K/1K) × (8/4) = 4 × 2 = 8 片<br>\n          每两片并联补位（8 位）<br>\n          四组串联补字（4K）<br>\n          A0~A9 给所有片；A10A11 译码片选\n        </p>\n        <h4 class=\"mt-l\">译码器</h4>\n        <ul class=\"dim mt-s\" style=\"font-size:13px;line-height:1.85\">\n          <li>线选法：每片用一根高位线选；浪费</li>\n          <li>译码法：用 2-4、3-8 译码器分配片选</li>\n          <li>n 选 1：log₂n 根地址线 → n 片</li>\n        </ul>\n        <h4 class=\"mt-m\">CPU ↔ 主存接口</h4>\n        <p class=\"dim mt-s\" style=\"font-size:13px\">CPU 通过 MAR 给地址、MDR 给/收数据、读/写控制线发命令；主存通过 DRDY 应答。</p>\n      </div>\n    </div>"}, {"title": "Cache 三种映射", "content": "<p class=\"kicker\">07 · Cache</p>\n    <h2 class=\"h2\">直接 / 全相联 / 组相联 + 地址划分。</h2>\n    <div class=\"grid g2 mt-l\" style=\"align-items:start\">\n      <div>\n        <h4>地址划分</h4>\n        <p class=\"dim mt-s\" style=\"font-size:13.5px\">主存地址 = 块地址 + 块内偏移；块地址再分：</p>\n        <div class=\"viz mt-s\" style=\"font-size:12px\">\n全相联:  Tag                |  块内\n直接:    Tag |  Cache 行号  |  块内\n组相联:  Tag |  组号        |  块内\n例: 主存 1M, Cache 32KB, 块 32B\n   主存地址 20 位\n   块大小 = 2⁵ → 块内 5 位\n   块数 = 2¹⁵ 个 Cache 块\n        2¹⁵ 个块号\n直接映射: 行号 = 块号 mod (Cache 块数 = 1024)\n         = 10 位 → Tag = 5 位\n全相联:   Tag 完整 15 位\n4 路组相联: 组数 = 1024/4 = 256\n          组号 7 位, Tag 8 位</div>\n      </div>\n      <div>\n        <h4>对比</h4>\n        <table class=\"cmp-table mt-s\">\n          <tr><th></th><th>直接</th><th>全相联</th><th>组相联</th></tr>\n          <tr><td>放置自由度</td><td>固定</td><td>任意</td><td>组内任意</td></tr>\n          <tr><td>查找</td><td>1 次</td><td>n 次并行</td><td>组内并行</td></tr>\n          <tr><td>电路复杂</td><td>低</td><td>高</td><td>中</td></tr>\n          <tr><td>冲突</td><td>抖动严重</td><td>无</td><td>较少</td></tr>\n        </table>\n        <p class=\"dim mt-s\" style=\"font-size:13px\">实际系统多用 <b>4 路 / 8 路组相联</b>，在自由度和电路复杂度间折中。</p>\n        <h4 class=\"mt-l\">命中率公式</h4>\n        <p class=\"mono mt-s\" style=\"font-size:13.5px;background:var(--surface-2);padding:12px;border-radius:8px\">\n          T_avg = h·t_c + (1−h)·t_m<br>\n          <span class=\"dim\">// h 命中率, t_c Cache 时间, t_m 主存时间</span>\n        </p>\n        <p class=\"dim mt-s\" style=\"font-size:13px\">例：h=0.95, t_c=2ns, t_m=100ns → T = 0.95·2 + 0.05·100 = 6.9 ns</p>\n      </div>\n    </div>"}, {"title": "Cache 替换 / 写", "content": "<p class=\"kicker\">07 · 替换与一致</p>\n    <h2 class=\"h2\">3 种替换 + 2 种写策略。</h2>\n    <div class=\"grid g2 mt-l\" style=\"align-items:start\">\n      <div>\n        <h4>替换算法</h4>\n        <table class=\"cmp-table mt-s\">\n          <tr><th>算法</th><th>策略</th><th>特点</th></tr>\n          <tr><td>随机</td><td>随机选一行替换</td><td>硬件最简单</td></tr>\n          <tr><td>FIFO</td><td>替换最早调入</td><td>有 Belady</td></tr>\n          <tr><td>LRU</td><td>替换最近最久未用</td><td>性能好，硬件复杂</td></tr>\n          <tr><td>LFU</td><td>替换最少使用</td><td>需计数器</td></tr>\n        </table>\n        <p class=\"dim mt-s\" style=\"font-size:13px\">直接映射不需要替换算法（位置已固定）；只有全 / 组相联需要。</p>\n      </div>\n      <div>\n        <h4>写策略</h4>\n        <table class=\"cmp-table mt-s\">\n          <tr><th></th><th>Write-through</th><th>Write-back</th></tr>\n          <tr><td>写时</td><td>同时写 Cache + 主存</td><td>只写 Cache，置 dirty</td></tr>\n          <tr><td>替换</td><td>不写回</td><td>dirty=1 才写回</td></tr>\n          <tr><td>多处理一致性</td><td>容易</td><td>需缓存一致性协议</td></tr>\n          <tr><td>性能</td><td>每写都慢</td><td>积攒成块写</td></tr>\n        </table>\n        <h4 class=\"mt-l\">写不命中</h4>\n        <ul class=\"dim mt-s\" style=\"font-size:13px;line-height:1.85\">\n          <li><b>写分配</b>：先把块调入 Cache 再写</li>\n          <li><b>非写分配</b>：直接写主存</li>\n          <li>常组合：<b>WB + 写分配</b>（块未来要读）<br>&emsp;&emsp;&emsp;&emsp;<b>WT + 非写分配</b></li>\n        </ul>\n        <h4 class=\"mt-m\">多核一致性</h4>\n        <p class=\"dim mt-s\" style=\"font-size:13px\">MESI 协议：每行有 Modified / Exclusive / Shared / Invalid 状态；总线监听（snooping）。</p>\n      </div>\n    </div>"}, {"title": "虚拟存储", "content": "<p class=\"kicker\">08 · 虚拟存储</p>\n    <h2 class=\"h2\">从硬件视角看 TLB 与页表。</h2>\n    <div class=\"grid g2 mt-l\" style=\"align-items:start\">\n      <div>\n        <h4>地址变换硬件流程</h4>\n        <ol class=\"dim mt-s\" style=\"font-size:13.5px;line-height:1.85\">\n          <li>CPU 发出虚拟地址 (P, d)</li>\n          <li>查 TLB：命中 → 直接得 PFN，访存</li>\n          <li>TLB 未命中 → 查内存页表</li>\n          <li>页表命中且 V=1 → 更新 TLB → 访存</li>\n          <li>V=0 → 缺页中断 → OS 处理</li>\n          <li>访存前还要查 Cache</li>\n        </ol>\n        <h4 class=\"mt-l\">EAT 公式</h4>\n        <p class=\"mono mt-s\" style=\"font-size:13px;background:var(--surface-2);padding:10px;border-radius:8px;line-height:1.85\">\n          假设 TLB 命中率 h，未命中需两次访存：<br>\n          EAT = h·(t_TLB + t_mem) + (1−h)·(t_TLB + 2·t_mem)\n        </p>\n        <p class=\"dim mt-s\" style=\"font-size:13px\">实测：x86 TLB 64-1024 项，命中率 &gt; 99%。</p>\n      </div>\n      <div>\n        <h4>段页式硬件</h4>\n        <div class=\"viz mt-s\" style=\"font-size:12px\">\n逻辑 = 段号 S | 段内页号 P | 页内偏移 d\nS → 段表 → 段内页表起址\n   (同时验证 S &lt; 段表长度)\nP → 页表 → 物理块号 F\n   (检查页号 &lt; 段长 / 页大小)\n物理 = F | d\n带 TLB: 同时缓存 (S, P) → F 映射</div>\n        <h4 class=\"mt-m\">TLB / Cache / 主存关系</h4>\n        <table class=\"cmp-table mt-s\">\n          <tr><th>目的</th><th>缓存什么</th></tr>\n          <tr><td>TLB</td><td>页表项（虚 → 物理）</td></tr>\n          <tr><td>Cache</td><td>主存数据 / 指令</td></tr>\n          <tr><td>主存</td><td>磁盘上的页 / 段</td></tr>\n        </table>\n      </div>\n    </div>"}, {"title": "指令系统", "content": "<p class=\"kicker\">09 · 指令</p>\n    <h2 class=\"h2\">指令格式 + 9 种寻址方式。</h2>\n    <div class=\"grid g2 mt-l\" style=\"align-items:start\">\n      <div>\n        <h4>指令格式</h4>\n        <p class=\"dim mt-s\" style=\"font-size:13.5px\">操作码 OP + 地址码。按地址数分：</p>\n        <ul class=\"dim mt-s\" style=\"font-size:13px;line-height:1.85\">\n          <li><b>三地址</b>：OP, A₁, A₂, A₃（A₁ ⊕ A₂ → A₃）</li>\n          <li><b>二地址</b>：OP, dst, src（dst ← dst ⊕ src）</li>\n          <li><b>一地址</b>：OP, A（隐含累加器：AC ← AC ⊕ A）</li>\n          <li><b>零地址</b>：OP（栈式 / NOP / HALT）</li>\n        </ul>\n        <h4 class=\"mt-l\">操作码扩展</h4>\n        <p class=\"dim mt-s\" style=\"font-size:13.5px\">定长操作码无法兼顾\"指令数多\"与\"地址位长\"。扩展法：<br>· 短地址指令用长 OP（少地址腾出位给 OP）<br>· 长地址指令用短 OP</p>\n        <p class=\"dim mt-s\" style=\"font-size:13px\">例：4 位 OP + 12 位地址（三地址 4 位 × 3）。当 OP=1111 时表示扩展，剩下用次 4 位再做选择。</p>\n      </div>\n      <div>\n        <h4>9 种寻址方式</h4>\n        <table class=\"cmp-table mt-s\">\n          <tr><th>方式</th><th>EA 计算</th><th>用途</th></tr>\n          <tr><td>立即</td><td>A 本身就是数</td><td>常数</td></tr>\n          <tr><td>直接</td><td>EA = A</td><td>定位变量</td></tr>\n          <tr><td>间接</td><td>EA = (A)</td><td>跳转表</td></tr>\n          <tr><td>寄存器</td><td>R 本身存数</td><td>最快</td></tr>\n          <tr><td>寄存器间接</td><td>EA = (R)</td><td>指针</td></tr>\n          <tr><td>相对</td><td>EA = PC + A</td><td>跳转、循环</td></tr>\n          <tr><td>基址</td><td>EA = BR + A</td><td>程序定位</td></tr>\n          <tr><td>变址</td><td>EA = IX + A</td><td>数组访问</td></tr>\n          <tr><td>堆栈</td><td>SP 隐含</td><td>函数调用</td></tr>\n        </table>\n        <p class=\"dim mt-s\" style=\"font-size:13px\"><b>基址 vs 变址</b>：基址寄存器对用户透明（OS 改 BR）；变址寄存器对用户开放（程序改 IX，遍历数组）。</p>\n      </div>\n    </div>"}, {"title": "CPU 内部结构", "content": "<p class=\"kicker\">10 · CPU</p>\n    <h2 class=\"h2\">PC · IR · MAR · MDR · ALU · CU · PSW。</h2>\n    <div class=\"grid g2 mt-l\" style=\"align-items:start\">\n      <div>\n        <h4>关键部件</h4>\n        <ul class=\"dim mt-s\" style=\"font-size:14px;line-height:1.95\">\n          <li><b>PC</b> 程序计数器 · 下一条指令地址</li>\n          <li><b>IR</b> 指令寄存器 · 当前指令</li>\n          <li><b>MAR</b> · 当前访存地址</li>\n          <li><b>MDR</b> · 当前访存数据</li>\n          <li><b>ALU</b> · 算逻运算单元</li>\n          <li><b>通用寄存器组</b> R0…R31</li>\n          <li><b>PSW</b> · 标志位（Z/C/V/S/I）</li>\n          <li><b>CU</b> · 控制单元，产生微命令</li>\n        </ul>\n      </div>\n      <div>\n        <h4>三种数据通路</h4>\n        <table class=\"cmp-table mt-s\">\n          <tr><th>结构</th><th>特点</th></tr>\n          <tr><td>单总线</td><td>所有部件挂同一总线；逻辑简单但同时只能传一次</td></tr>\n          <tr><td>多总线</td><td>多条并行总线；提高并发</td></tr>\n          <tr><td>专用</td><td>固定线路连接；最快，电路复杂</td></tr>\n        </table>\n        <h4 class=\"mt-l\">单总线下一条加法指令</h4>\n        <pre class=\"code-block\" style=\"font-size:12px\">\n<span class=\"c\">// ADD R0, R1</span>\n<span class=\"c\">// 假设 ALU 有两个输入锁存器 Y、Z</span>\nT1:  R1out, Yin              <span class=\"c\">// R1 → Y</span>\nT2:  R0out, ALUop=add, Zin   <span class=\"c\">// R0+Y → Z</span>\nT3:  Zout, R0in              <span class=\"c\">// Z → R0</span></pre>\n      </div>\n    </div>"}, {"title": "数据通路", "content": "<p class=\"kicker\">10 · 数据通路</p>\n    <h2 class=\"h2\">取指 → 译码 → 执行 → 访存 → 写回。</h2>\n    <div class=\"grid g2 mt-l\" style=\"align-items:start\">\n      <div>\n        <h4>取指阶段 IF（公共）</h4>\n        <pre class=\"code-block\" style=\"font-size:12.5px\">\nT1: PCout, MARin\nT2: MEMrd, PCout, ALUop=+1, Zin\nT3: MDRout(IR), Zout, PCin\nT4: IRout</pre>\n        <p class=\"dim mt-s\" style=\"font-size:13px\">指令送 IR、PC 自增。</p>\n        <h4 class=\"mt-l\">译码阶段 ID</h4>\n        <p class=\"dim mt-s\" style=\"font-size:13px\">控制器分析 OP 字段 → 决定接下来的微操作序列。读出寄存器送 ALU 输入端。</p>\n      </div>\n      <div>\n        <h4>执行举例：ADD R1, [R2]</h4>\n        <pre class=\"code-block\" style=\"font-size:12.5px\">\nT5: R2out, MARin          <span class=\"c\">// R2 给地址</span>\nT6: MEMrd                  <span class=\"c\">// 读主存</span>\nT7: MDRout, Yin            <span class=\"c\">// 数据 → Y</span>\nT8: R1out, ALUop=add, Zin  <span class=\"c\">// R1 + Y → Z</span>\nT9: Zout, R1in             <span class=\"c\">// 写回 R1</span>\nT10: PSW 更新 Z/C/V/S\nT11: End</pre>\n        <h4 class=\"mt-l\">指令周期 4 阶段</h4>\n        <ul class=\"dim mt-s\" style=\"font-size:13px;line-height:1.85\">\n          <li><b>取指</b>：取指令 + PC+1</li>\n          <li><b>间址</b>：若需间接寻址</li>\n          <li><b>执行</b>：完成指令功能</li>\n          <li><b>中断</b>：检查 / 响应中断</li>\n        </ul>\n      </div>\n    </div>"}, {"title": "控制器", "content": "<p class=\"kicker\">11 · 控制器</p>\n    <h2 class=\"h2\">硬布线 vs 微程序。</h2>\n    <div class=\"grid g2 mt-l\" style=\"align-items:start\">\n      <div>\n        <h4>硬布线 Hardwired</h4>\n        <p class=\"dim mt-s\" style=\"font-size:13.5px\">由组合逻辑电路产生控制信号。一条信号 = OP × 节拍 × 标志位 → 与门。</p>\n        <ul class=\"dim mt-s\" style=\"font-size:13px;line-height:1.85\">\n          <li>✅ 速度快（直接组合逻辑）</li>\n          <li>❌ 修改 / 扩展难（重画电路）</li>\n          <li>典型 RISC 用</li>\n        </ul>\n        <h4 class=\"mt-l\">微程序 Microprogrammed</h4>\n        <p class=\"dim mt-s\" style=\"font-size:13.5px\">把每条机器指令分解成微指令序列，存入控制存储器（CM，通常 ROM）。每个时钟读一条微指令 → 控制信号。</p>\n      </div>\n      <div>\n        <h4>微指令结构</h4>\n        <table class=\"cmp-table mt-s\">\n          <tr><th>格式</th><th>说明</th></tr>\n          <tr><td>水平型</td><td>一字段一信号；并行多，存大</td></tr>\n          <tr><td>垂直型</td><td>类似机器指令；存少，需译码</td></tr>\n          <tr><td>混合型</td><td>折中</td></tr>\n        </table>\n        <h4 class=\"mt-l\">微指令地址形成</h4>\n        <ul class=\"dim mt-s\" style=\"font-size:13px;line-height:1.85\">\n          <li>下一条由当前微指令的下址字段指出</li>\n          <li>计数器自增</li>\n          <li>分支 / 转移由标志位修改地址</li>\n        </ul>\n        <h4 class=\"mt-m\">CISC vs RISC</h4>\n        <p class=\"dim mt-s\" style=\"font-size:13px\">CISC（x86）：指令多、变长、寻址复杂 → 微程序；RISC（ARM、RISC-V）：指令少、定长、Load-Store → 硬布线 + 流水线。</p>\n      </div>\n    </div>"}, {"title": "流水线 5 段", "content": "<p class=\"kicker\">12 · 流水线</p>\n    <h2 class=\"h2\">IF · ID · EX · MEM · WB。</h2>\n    <div class=\"grid g2 mt-l\" style=\"align-items:start;gap:32px\">\n      <div>\n        <div class=\"pipe\">\n          <div class=\"lbl\"></div>\n          <div class=\"c\" style=\"background:var(--surface-2);color:var(--text-3)\">t1</div>\n          <div class=\"c\" style=\"background:var(--surface-2);color:var(--text-3)\">t2</div>\n          <div class=\"c\" style=\"background:var(--surface-2);color:var(--text-3)\">t3</div>\n          <div class=\"c\" style=\"background:var(--surface-2);color:var(--text-3)\">t4</div>\n          <div class=\"c\" style=\"background:var(--surface-2);color:var(--text-3)\">t5</div>\n          <div class=\"c\" style=\"background:var(--surface-2);color:var(--text-3)\">t6</div>\n          <div class=\"c\" style=\"background:var(--surface-2);color:var(--text-3)\">t7</div>\n          <div class=\"c\" style=\"background:var(--surface-2);color:var(--text-3)\">t8</div>\n          <div class=\"lbl\">I1</div>\n          <div class=\"c if\">IF</div><div class=\"c id\">ID</div><div class=\"c ex\">EX</div><div class=\"c me\">MEM</div><div class=\"c wb\">WB</div>\n          <div class=\"c empty\"></div><div class=\"c empty\"></div><div class=\"c empty\"></div>\n          <div class=\"lbl\">I2</div>\n          <div class=\"c empty\"></div>\n          <div class=\"c if\">IF</div><div class=\"c id\">ID</div><div class=\"c ex\">EX</div><div class=\"c me\">MEM</div><div class=\"c wb\">WB</div>\n          <div class=\"c empty\"></div><div class=\"c empty\"></div>\n          <div class=\"lbl\">I3</div>\n          <div class=\"c empty\"></div><div class=\"c empty\"></div>\n          <div class=\"c if\">IF</div><div class=\"c id\">ID</div><div class=\"c ex\">EX</div><div class=\"c me\">MEM</div><div class=\"c wb\">WB</div>\n          <div class=\"c empty\"></div>\n          <div class=\"lbl\">I4</div>\n          <div class=\"c empty\"></div><div class=\"c empty\"></div><div class=\"c empty\"></div>\n          <div class=\"c if\">IF</div><div class=\"c id\">ID</div><div class=\"c ex\">EX</div><div class=\"c me\">MEM</div><div class=\"c wb\">WB</div>\n        </div>\n        <h4 class=\"mt-l\">五段功能</h4>\n        <ul class=\"dim mt-s\" style=\"font-size:13px;line-height:1.85\">\n          <li><b>IF</b> 取指：从 ICache 读指令，PC+4</li>\n          <li><b>ID</b> 译码：解析 + 读寄存器</li>\n          <li><b>EX</b> 执行：ALU 运算 / 计算分支地址</li>\n          <li><b>MEM</b> 访存：读写 DCache（仅 load/store）</li>\n          <li><b>WB</b> 写回：结果写回寄存器</li>\n        </ul>\n      </div>\n      <div>\n        <h4>性能公式</h4>\n        <p class=\"mono mt-s\" style=\"font-size:13.5px;background:var(--surface-2);padding:12px;border-radius:8px;line-height:1.95\">\n          k 段流水，n 条指令：<br>\n          T = (k + n − 1) × Δt<br><br>\n          加速比 S = nk / (k + n − 1)<br>\n          n → ∞ 时 S → k （最大加速比）<br><br>\n          吞吐率 TP = n / T<br>\n          n → ∞ 时 TP → 1/Δt\n        </p>\n        <h4 class=\"mt-l\">流水线分类</h4>\n        <ul class=\"dim mt-s\" style=\"font-size:13px;line-height:1.85\">\n          <li><b>单功能</b> vs <b>多功能</b>：能处理几种任务</li>\n          <li><b>静态</b> vs <b>动态</b>：能否动态切换功能</li>\n          <li><b>线性</b> vs <b>非线性</b>：是否有反馈</li>\n          <li><b>标量</b> vs <b>超标量</b>：每周期完成几条</li>\n        </ul>\n      </div>\n    </div>"}, {"title": "流水线冒险", "content": "<p class=\"kicker\">12 · 冒险</p>\n    <h2 class=\"h2\">结构 · 数据 · 控制 三种冒险。</h2>\n    <div class=\"grid g2 mt-l\" style=\"align-items:start\">\n      <div>\n        <h4>三种冒险</h4>\n        <table class=\"cmp-table mt-s\">\n          <tr><th>类型</th><th>原因</th><th>对策</th></tr>\n          <tr><td>结构冒险</td><td>同时刻争抢一份资源（如取指 + 访存）</td><td>独立 ICache/DCache；增端口</td></tr>\n          <tr><td>数据冒险 RAW</td><td>后指令读上一指令未写回的值</td><td>转发 forwarding / 插气泡 / 编译重排</td></tr>\n          <tr><td>控制冒险</td><td>分支指令未定时仍取下一条</td><td>分支预测 / 延迟槽 / 提前判断</td></tr>\n        </table>\n      </div>\n      <div>\n        <h4>数据冒险三种</h4>\n        <ul class=\"dim mt-s\" style=\"font-size:13px;line-height:1.85\">\n          <li><b>RAW</b> Read After Write：后指令读前指令的写（常见）</li>\n          <li><b>WAW</b> Write After Write：写顺序错</li>\n          <li><b>WAR</b> Write After Read：写覆盖未读</li>\n        </ul>\n        <h4 class=\"mt-l\">分支预测</h4>\n        <ul class=\"dim mt-s\" style=\"font-size:13px;line-height:1.85\">\n          <li><b>静态</b>：永远预测不跳转 / 跳转</li>\n          <li><b>1 位动态</b>：根据上次结果预测</li>\n          <li><b>2 位饱和</b>：抗噪能力强（最常用）</li>\n          <li><b>BTB</b> 分支目标缓冲：缓存分支目标</li>\n        </ul>\n        <h4 class=\"mt-m\">进阶</h4>\n        <ul class=\"dim mt-s\" style=\"font-size:13px;line-height:1.85\">\n          <li><b>超标量</b>：多条流水并行发射</li>\n          <li><b>超流水</b>：段切更细，频率更高</li>\n          <li><b>乱序</b>：动态调度，无依赖即发射</li>\n        </ul>\n      </div>\n    </div>"}, {"title": "总线分类", "content": "<p class=\"kicker\">13 · 总线</p>\n    <h2 class=\"h2\">几条共享线，把所有部件连起来。</h2>\n    <div class=\"grid g2 mt-l\" style=\"align-items:start\">\n      <div>\n        <h4>按功能</h4>\n        <ul class=\"dim mt-s\" style=\"font-size:13.5px;line-height:1.85\">\n          <li><b>数据总线</b>：双向，传输数据；位数 = 字长</li>\n          <li><b>地址总线</b>：单向，传输地址；位数决定寻址范围</li>\n          <li><b>控制总线</b>：双向，传命令 / 状态 / 时钟</li>\n        </ul>\n        <h4 class=\"mt-l\">按层次</h4>\n        <ul class=\"dim mt-s\" style=\"font-size:13.5px;line-height:1.85\">\n          <li>片内总线（CPU 内部）</li>\n          <li>系统总线（CPU ↔ 主存 ↔ IO）</li>\n          <li>通信总线（机间）</li>\n        </ul>\n        <h4 class=\"mt-l\">按时序</h4>\n        <ul class=\"dim mt-s\" style=\"font-size:13.5px;line-height:1.85\">\n          <li><b>同步</b>：统一时钟，简单快但要求一致</li>\n          <li><b>异步</b>：握手信号</li>\n          <li><b>半同步</b>：同步 + 等待信号</li>\n          <li><b>分离</b>：地址 / 数据分两次传，提高利用率</li>\n        </ul>\n      </div>\n      <div>\n        <h4>带宽计算</h4>\n        <p class=\"mono mt-s\" style=\"font-size:13.5px;background:var(--surface-2);padding:12px;border-radius:8px;line-height:1.95\">\n          带宽 = 频率 × 宽度 × 每周期数<br>\n          单位：B/s 或 GT/s × byte<br><br>\n          例：PCIe 4.0 ×16 = 16 GT/s × 2 B × 16 lanes<br>\n          &emsp;&emsp;&emsp; = 64 GB/s\n        </p>\n        <h4 class=\"mt-l\">总线性能指标</h4>\n        <ul class=\"dim mt-s\" style=\"font-size:13px;line-height:1.85\">\n          <li><b>位宽</b>：并行传输的位数</li>\n          <li><b>频率</b>：时钟速度</li>\n          <li><b>带宽</b>：每秒数据量</li>\n          <li><b>主从</b>：主设备发起，从设备响应</li>\n        </ul>\n        <h4 class=\"mt-m\">典型总线</h4>\n        <p class=\"dim mt-s\" style=\"font-size:13px\">前端总线 FSB（已淘汰）→ QPI/UPI → PCIe；存储总线：DDR；外设：USB / SATA / Thunderbolt。</p>\n      </div>\n    </div>"}, {"title": "总线仲裁 / 通信", "content": "<p class=\"kicker\">13 · 仲裁 + 通信</p>\n    <h2 class=\"h2\">谁先用 + 怎么传。</h2>\n    <div class=\"grid g2 mt-l\" style=\"align-items:start\">\n      <div>\n        <h4>4 种仲裁方式</h4>\n        <table class=\"cmp-table mt-s\">\n          <tr><th>方式</th><th>原理</th><th>优 / 缺点</th></tr>\n          <tr><td>链式查询</td><td>请求线广播，允许信号链式传递</td><td>简单；但近 CPU 优先</td></tr>\n          <tr><td>计数器定时</td><td>计数器递增问每个设备</td><td>起点可移动 → 均衡</td></tr>\n          <tr><td>独立请求</td><td>每设备一对请求 / 允许线</td><td>最快；线多</td></tr>\n          <tr><td>分布式</td><td>设备间协商</td><td>高可靠（无单点）</td></tr>\n        </table>\n      </div>\n      <div>\n        <h4>异步通信三种握手</h4>\n        <table class=\"cmp-table mt-s\">\n          <tr><th>模式</th><th>特点</th></tr>\n          <tr><td>不互锁</td><td>各自定时撤销；最快但易丢</td></tr>\n          <tr><td>半互锁</td><td>请求方等应答后撤请求</td></tr>\n          <tr><td>全互锁</td><td>双方都等对方撤销；最可靠最慢</td></tr>\n        </table>\n        <h4 class=\"mt-l\">同步通信</h4>\n        <p class=\"dim mt-s\" style=\"font-size:13px\">主从在统一时钟下，按固定时序传输（如 T1 发地址，T2 发数据）。需要双方速度匹配。</p>\n        <h4 class=\"mt-m\">突发传输</h4>\n        <p class=\"dim mt-s\" style=\"font-size:13px\">连续传送多个数据，只用一次地址 → 大幅提高带宽（DRAM 默认开启 burst）。</p>\n      </div>\n    </div>"}, {"title": "中断系统", "content": "<p class=\"kicker\">14 · 中断</p>\n    <h2 class=\"h2\">完整中断处理流程 + 嵌套。</h2>\n    <div class=\"grid g2 mt-l\" style=\"align-items:start\">\n      <div>\n        <h4>中断分类</h4>\n        <ul class=\"dim mt-s\" style=\"font-size:13.5px;line-height:1.85\">\n          <li><b>外中断</b>：外设 / 时钟 / IO 完成（可屏蔽 + 不可屏蔽 NMI）</li>\n          <li><b>内中断</b>：异常 / 故障 / trap（除零、缺页、保护错）</li>\n          <li><b>陷阱</b>：系统调用</li>\n        </ul>\n        <h4 class=\"mt-l\">完整流程</h4>\n        <ol class=\"dim mt-s\" style=\"font-size:13px;line-height:1.85\">\n          <li>当前指令结束</li>\n          <li>检查 INTR → 有则进入中断周期</li>\n          <li>关中断，硬件保存 PC、PSW</li>\n          <li>识别中断源（向量 / 查询）</li>\n          <li>跳到 ISR 入口</li>\n          <li>软件保存通用寄存器</li>\n          <li>开中断（允许嵌套）</li>\n          <li>处理中断</li>\n          <li>关中断 → 恢复现场</li>\n          <li>开中断 + IRET</li>\n        </ol>\n      </div>\n      <div>\n        <h4>中断屏蔽字</h4>\n        <p class=\"dim mt-s\" style=\"font-size:13.5px\">每个中断源有一组屏蔽位，决定它能屏蔽哪些其它中断源。<b>同级或低级总被屏蔽</b>，自屏要看实现。</p>\n        <pre class=\"code-block\" style=\"font-size:12.5px\">\n<span class=\"c\">// 例: 4 个中断源 A B C D</span>\n<span class=\"c\">// 优先级 A &gt; B &gt; C &gt; D</span>\n源    A B C D\nA的屏蔽字: 1 1 1 1   <span class=\"c\">// 全屏蔽自及更低</span>\nB:           0 1 1 1\nC:           0 0 1 1\nD:           0 0 0 1</pre>\n        <h4 class=\"mt-m\">向量中断</h4>\n        <p class=\"dim mt-s\" style=\"font-size:13px\">每个中断源 → 一个向量号 → 中断向量表中的 ISR 入口地址。<br>查询式：CPU 轮询所有源；慢但灵活。</p>\n        <h4 class=\"mt-m\">中断 vs 异常</h4>\n        <p class=\"dim mt-s\" style=\"font-size:13px\">中断：异步（外部事件），随机发生；异常：同步（指令引起），必发于该条指令。</p>\n      </div>\n    </div>"}, {"title": "IO 控制方式", "content": "<p class=\"kicker\">15 · IO</p>\n    <h2 class=\"h2\">查询 → 中断 → DMA → 通道。</h2>\n    <div class=\"grid g2 mt-l\" style=\"align-items:start\">\n      <div>\n        <table class=\"cmp-table mt-s\">\n          <tr><th>方式</th><th>CPU 介入</th><th>每次单位</th></tr>\n          <tr><td>程序查询</td><td>持续轮询</td><td>1 字</td></tr>\n          <tr><td>程序中断</td><td>请求时响应</td><td>1 字 / 中断</td></tr>\n          <tr><td><b>DMA</b></td><td>启动 + 结束</td><td>1 块 / 中断</td></tr>\n          <tr><td>通道</td><td>仅启动通道程序</td><td>1 组数据 / 中断</td></tr>\n        </table>\n        <h4 class=\"mt-l\">DMA 三种工作方式</h4>\n        <ul class=\"dim mt-s\" style=\"font-size:13px;line-height:1.85\">\n          <li><b>停止 CPU</b>：DMA 长时间占用总线</li>\n          <li><b>周期挪用</b>：DMA 偷一个总线周期（最常用）</li>\n          <li><b>交替访问</b>：CPU 与 DMA 错相</li>\n        </ul>\n        <h4 class=\"mt-m\">DMA 处理流程</h4>\n        <ol class=\"dim mt-s\" style=\"font-size:12.5px;line-height:1.85\">\n          <li>CPU 通过 IO 指令初始化 DMA：源 / 目地址 / 长度 / 方向</li>\n          <li>DMA 请求总线</li>\n          <li>CPU 让出总线（或挪用周期）</li>\n          <li>DMA 在内存 ↔ 设备间直接搬数据</li>\n          <li>传完发中断告知 CPU</li>\n        </ol>\n      </div>\n      <div>\n        <h4>通道</h4>\n        <p class=\"dim mt-s\" style=\"font-size:13.5px\">是一种<b>独立的 IO 处理器</b>，能执行通道程序，CPU 只下达开始命令。常见于大型机。</p>\n        <ul class=\"dim mt-s\" style=\"font-size:13px;line-height:1.85\">\n          <li>字节多路通道：低速设备共享</li>\n          <li>选择通道：高速设备独占</li>\n          <li>数组多路通道：折中</li>\n        </ul>\n        <h4 class=\"mt-l\">IO 端口编址</h4>\n        <table class=\"cmp-table mt-s\">\n          <tr><th>方式</th><th>说明</th></tr>\n          <tr><td>独立编址</td><td>专用 IO 指令 IN/OUT；端口空间独立</td></tr>\n          <tr><td>统一编址（内存映射）</td><td>把 IO 寄存器映射到内存地址空间，用普通 load/store 即可</td></tr>\n        </table>\n        <h4 class=\"mt-m\">设备分类</h4>\n        <ul class=\"dim mt-s\" style=\"font-size:13px;line-height:1.85\">\n          <li>按速度：低 / 中 / 高速</li>\n          <li>按交互：人机 / 机机</li>\n          <li>按字符 / 块：字符设备 / 块设备</li>\n          <li>按共享：独占 / 共享 / 虚拟（SPOOLing）</li>\n        </ul>\n      </div>\n    </div>"}, {"title": "整机回顾", "content": "<p class=\"kicker\">// summary</p>\n    <h2 class=\"h2\">把整个计组串成一张图。</h2>\n    <div class=\"grid g2 mt-l\">\n      <div class=\"card\">\n        <h4>5 大功能部件</h4>\n        <ul class=\"dim mt-s\" style=\"font-size:14px;line-height:1.95\">\n          <li>① 运算器（ALU + 寄存器组 + PSW）</li>\n          <li>② 控制器（PC, IR, MAR, MDR, CU）</li>\n          <li>③ 存储器（Cache - 主存 - 辅存）</li>\n          <li>④ 输入设备</li>\n          <li>⑤ 输出设备</li>\n        </ul>\n        <h4 class=\"mt-l\">3 大思想</h4>\n        <ul class=\"dim mt-s\" style=\"font-size:14px;line-height:1.95\">\n          <li>抽象层次（电路 → 逻辑 → 体系 → 指令）</li>\n          <li>局部性原理（Cache、TLB、虚拟存储一脉相承）</li>\n          <li>并行 / 流水（流水线、超标量、多核）</li>\n        </ul>\n      </div>\n      <div class=\"card\">\n        <h4>一条指令的一生</h4>\n        <div class=\"viz mt-s\" style=\"font-size:12px\">\n1. PC → MAR → 主存\n2. 主存 → MDR → IR\n3. PC ← PC + 4 (取指完成)\n4. IR 译码 → CU 产生微指令\n5. 读寄存器 → ALU 输入端\n6. ALU 运算 → 结果 Z\n7. (load/store) → MEM\n8. 结果回写寄存器\n9. 更新 PSW\n10. 检查中断 → 下一条</div>\n        <h4 class=\"mt-l\">8 章高频考点</h4>\n        <ul class=\"dim mt-s\" style=\"font-size:13px;line-height:1.85\">\n          <li>数据：补码、IEEE 754 互转</li>\n          <li>运算：Booth / 加减交替</li>\n          <li>Cache：地址划分 + 命中率</li>\n          <li>指令：寻址方式 + 操作码扩展</li>\n          <li>CPU：微操作 + 流水线时空图</li>\n          <li>总线：带宽计算</li>\n          <li>IO：中断 vs DMA</li>\n        </ul>\n      </div>\n    </div>"}]}, "operating-system": {"title": "操作系统", "weight": "35分", "slides": [{"title": "Cover", "content": "<p class=\"kicker\">408 · OPERATING SYSTEM · 汤小丹 / 王道 完整版</p>\n    <h1 class=\"h1 huge anim-fade-up\" data-anim=\"fade-up\">操作系统</h1>\n    <h2 class=\"h2\" style=\"font-weight:400;color:var(--text-2);margin-top:-8px\">从 <span class=\"gradient-text\">\"如何管理资源\"</span> 这个问题开始。</h2>\n    <p class=\"lede mt-l\">28 节课，完整覆盖王道 6 章内容：从概念到进程、调度、同步、内存、虚拟内存、文件、IO，每个考点都有代码 / 算例 / 陷阱。</p>\n    <div class=\"label-strip\">\n      <span class=\"pill\">~35 分</span>\n      <span class=\"pill\">6 章 28 节</span>\n      <span class=\"pill\">大题：调度 / 同步 / 页表</span>\n      <span class=\"pill\">小题：状态机 / 算法 / 数据结构</span>\n    </div>"}, {"title": "目录", "content": "<p class=\"kicker\">// agenda</p>\n    <h2 class=\"h2\">28 张卡片完整路线</h2>\n    <div class=\"grid g3 mt-l\" style=\"gap:24px;font-size:13px\">\n      <div>\n        <h4 style=\"font-size:15px\">Ch1-2 · 进程</h4>\n        <ol class=\"steps mt-s\" style=\"counter-reset:s 0\">\n          <li>OS 概念 / 特征 / 分类</li>\n          <li>用户态核心态 / 系统调用</li>\n          <li>中断 / 异常 / 陷阱</li>\n          <li>进程 / PCB / 组织</li>\n          <li>状态机 + 进程控制</li>\n          <li>线程 / 用户级内核级</li>\n          <li>三层调度 / 切换</li>\n          <li>FCFS / SJF / SRTN</li>\n          <li>RR / 优先级 / MLFQ</li>\n        </ol>\n      </div>\n      <div>\n        <h4 style=\"font-size:15px\">Ch2-3 · 同步内存</h4>\n        <ol class=\"steps mt-s\" style=\"counter-reset:s 9\">\n          <li>同步互斥 / 临界区</li>\n          <li>信号量 PV</li>\n          <li>P-C 经典</li>\n          <li>R-W + 哲学家</li>\n          <li>死锁四条件</li>\n          <li>银行家算例</li>\n          <li>IPC 进程通信</li>\n          <li>内存分配 + 装入</li>\n          <li>分页 + TLB</li>\n        </ol>\n      </div>\n      <div>\n        <h4 style=\"font-size:15px\">Ch4-6 · 虚存文件IO</h4>\n        <ol class=\"steps mt-s\" style=\"counter-reset:s 18\">\n          <li>多级 / 反置页表</li>\n          <li>分段 / 段页式</li>\n          <li>虚拟内存 / 缺页</li>\n          <li>置换算法对比</li>\n          <li>工作集 / 抖动</li>\n          <li>文件 / FCB / inode</li>\n          <li>文件分配方式</li>\n          <li>空闲管理</li>\n          <li>磁盘调度</li>\n          <li>IO 控制方式</li>\n        </ol>\n      </div>\n    </div>"}, {"title": "OS 概念", "content": "<p class=\"kicker\">01 · 概念</p>\n    <h2 class=\"h2\">OS = 资源管理器 + 接口提供者 + 抽象。</h2>\n    <div class=\"grid g2 mt-l\" style=\"align-items:start\">\n      <div>\n        <h4>四大特征</h4>\n        <ul class=\"dim mt-s\" style=\"font-size:14.5px;line-height:1.9\">\n          <li><b>并发</b> · 宏观同时多任务（vs 并行：物理同时）</li>\n          <li><b>共享</b> · 互斥共享 / 同时共享</li>\n          <li><b>虚拟</b> · 时分（虚拟 CPU）/ 空分（虚拟内存）</li>\n          <li><b>异步</b> · 推进速度不可预知</li>\n        </ul>\n        <h4 class=\"mt-l\">OS 发展史</h4>\n        <ul class=\"dim mt-s\" style=\"font-size:13px;line-height:1.85\">\n          <li>手工 → 单道批 → 多道批（提高 CPU 利用率）</li>\n          <li>分时（交互）→ 实时（响应严格）→ 通用</li>\n          <li>网络 / 分布式 / 嵌入式 / 个人机 / 手机</li>\n        </ul>\n      </div>\n      <div>\n        <h4>四种 OS 体系结构</h4>\n        <table class=\"cmp-table mt-s\">\n          <tr><th>结构</th><th>核心 / 特点</th></tr>\n          <tr><td>单体</td><td>整个 OS 在内核态；速度快，难维护（早期 Linux）</td></tr>\n          <tr><td>分层</td><td>下层为上层服务；调试方便，但调用链长（THE）</td></tr>\n          <tr><td>微内核</td><td>仅调度 / IPC / 基础内存在内核态；其余以服务进程实现（Mach、Minix）</td></tr>\n          <tr><td>外核</td><td>把硬件抽象做薄给应用更大自由度</td></tr>\n          <tr><td>模块化</td><td>可加载内核模块（现代 Linux）</td></tr>\n        </table>\n        <h4 class=\"mt-l\">OS 目标</h4>\n        <ol class=\"dim mt-s\" style=\"font-size:13px;line-height:1.85\">\n          <li>资源利用率（吞吐率）</li>\n          <li>响应速度 / 公平</li>\n          <li>方便、可靠、可扩展</li>\n          <li>提供良好的用户接口</li>\n        </ol>\n      </div>\n    </div>"}, {"title": "用户态 / 系统调用", "content": "<p class=\"kicker\">02 · 模式</p>\n    <h2 class=\"h2\">CPU 有两种模式，特权指令不让你乱用。</h2>\n    <div class=\"grid g2 mt-l\" style=\"align-items:start\">\n      <div>\n        <h4>区别</h4>\n        <table class=\"cmp-table mt-s\">\n          <tr><th></th><th>用户态</th><th>核心态</th></tr>\n          <tr><td>权限</td><td>仅普通指令</td><td>全部指令（含特权）</td></tr>\n          <tr><td>地址空间</td><td>用户空间</td><td>系统空间</td></tr>\n          <tr><td>程序</td><td>应用程序</td><td>OS 内核</td></tr>\n          <tr><td>切换方式</td><td>→ 核心：中断 / 异常 / 系统调用</td><td>← 用户：iret / sysret</td></tr>\n        </table>\n        <h4 class=\"mt-l\">典型特权指令</h4>\n        <ul class=\"dim mt-s\" style=\"font-size:13.5px;line-height:1.85\">\n          <li>启动 / 停止 IO</li>\n          <li>开 / 关中断</li>\n          <li>修改 PSW、时钟</li>\n          <li>切换页表 / 设置时钟</li>\n          <li>装入 PSW / DAR</li>\n        </ul>\n      </div>\n      <div>\n        <h4>系统调用 System Call</h4>\n        <p class=\"dim mt-s\" style=\"font-size:13.5px\">用户程序请求 OS 服务的<b>唯一合法入口</b>。</p>\n        <ol class=\"dim mt-s\" style=\"font-size:13.5px;line-height:1.85\">\n          <li>用户程序把参数 + 系统调用号放入寄存器</li>\n          <li>执行<b>陷入指令 trap</b> → 进入核心态</li>\n          <li>跳到对应的系统调用处理程序</li>\n          <li>执行服务（如 read 文件）</li>\n          <li>iret / sysret 返回用户态</li>\n        </ol>\n        <h4 class=\"mt-l\">5 类系统调用</h4>\n        <div class=\"grid g2 mt-s\" style=\"font-size:12.5px\">\n          <div class=\"card card-soft\"><b>设备管理</b><p class=\"dim mt-s\">request / release / read / write</p></div>\n          <div class=\"card card-soft\"><b>文件管理</b><p class=\"dim mt-s\">open / close / create / unlink</p></div>\n          <div class=\"card card-soft\"><b>进程控制</b><p class=\"dim mt-s\">fork / exec / wait / exit</p></div>\n          <div class=\"card card-soft\"><b>进程通信</b><p class=\"dim mt-s\">pipe / msgget / shmget</p></div>\n          <div class=\"card card-soft\"><b>内存管理</b><p class=\"dim mt-s\">mmap / brk / sbrk</p></div>\n        </div>\n      </div>\n    </div>"}, {"title": "中断 / 异常 / 陷阱", "content": "<p class=\"kicker\">02 · 控制转移</p>\n    <h2 class=\"h2\">三种\"非顺序流\"事件，处理方式相通。</h2>\n    <div class=\"grid g2 mt-l\" style=\"align-items:start\">\n      <div>\n        <h4>分类</h4>\n        <table class=\"cmp-table mt-s\">\n          <tr><th>类型</th><th>来源</th><th>典型</th></tr>\n          <tr><td>外中断</td><td>外设 / 时钟</td><td>键盘、磁盘 ready、定时器</td></tr>\n          <tr><td>内中断</td><td>CPU 内部</td><td>除零、缺页、保护错</td></tr>\n          <tr><td>陷阱</td><td>主动 trap</td><td>系统调用</td></tr>\n        </table>\n        <p class=\"dim mt-s\" style=\"font-size:13px\">中断 / 异常都涉及\"保护现场 → 跳服务程序 → 恢复\"。</p>\n        <h4 class=\"mt-l\">中断屏蔽</h4>\n        <ul class=\"dim mt-s\" style=\"font-size:13.5px;line-height:1.85\">\n          <li><b>不可屏蔽 NMI</b>：硬件故障、电源失效</li>\n          <li><b>可屏蔽 INTR</b>：可由 PSW.IF 位关闭</li>\n          <li>同优先级 / 低优先级时屏蔽</li>\n        </ul>\n      </div>\n      <div>\n        <h4>中断处理流程</h4>\n        <ol class=\"steps mt-s\" style=\"counter-reset:s 0\">\n          <li>当前指令结束</li>\n          <li>检查 INTR；有 → 入核心态</li>\n          <li>关中断，硬件保护 PC、PSW</li>\n          <li>识别中断源（向量表）</li>\n          <li>由中断服务程序：保存通用寄存器现场</li>\n          <li>开中断（允许嵌套）</li>\n          <li>处理中断</li>\n          <li>关中断 + 恢复现场 + iret</li>\n        </ol>\n        <h4 class=\"mt-l\">多重中断</h4>\n        <p class=\"dim mt-s\" style=\"font-size:13px\">在服务中允许更高优先级中断。每级有<b>中断屏蔽字</b>规定能屏蔽哪些级别。同级总是屏蔽，且需自屏。</p>\n      </div>\n    </div>"}, {"title": "进程 + PCB", "content": "<p class=\"kicker\">03 · 进程</p>\n    <h2 class=\"h2\">进程是\"程序的一次执行\"。</h2>\n    <div class=\"grid g2 mt-l\" style=\"align-items:start\">\n      <div>\n        <h4>进程的特征</h4>\n        <ul class=\"dim mt-s\" style=\"font-size:13.5px;line-height:1.85\">\n          <li><b>动态</b>：执行的活动（程序是静态的指令集合）</li>\n          <li><b>并发</b>：可以同时存在多个进程</li>\n          <li><b>独立</b>：独立地址空间和资源</li>\n          <li><b>异步</b>：推进速度不可预知</li>\n          <li><b>结构</b>：PCB + 数据段 + 程序段</li>\n        </ul>\n        <h4 class=\"mt-l\">PCB 进程控制块</h4>\n        <pre class=\"code-block\" style=\"font-size:12.5px\">\n<span class=\"c\">// 进程在系统中存在的唯一标识</span>\nstruct PCB {\n  PID, UID, GID;           <span class=\"c\">// 标识符</span>\n  PSW, PC, GPR[];           <span class=\"c\">// 处理机状态</span>\n  state, priority, queue;   <span class=\"c\">// 调度信息</span>\n  PageTableBase, ASID;      <span class=\"c\">// 内存</span>\n  OpenFileTable;            <span class=\"c\">// 文件</span>\n  IPC channels;             <span class=\"c\">// 通信</span>\n  CPU/IO usage;             <span class=\"c\">// 记账</span>\n};</pre>\n      </div>\n      <div>\n        <h4>进程组织</h4>\n        <ul class=\"dim mt-s\" style=\"font-size:13.5px;line-height:1.85\">\n          <li><b>链接方式</b>：同状态的 PCB 串成队列；OS 维护多个就绪队列 / 阻塞队列</li>\n          <li><b>索引方式</b>：每种状态一张索引表，表项指向 PCB</li>\n        </ul>\n        <h4 class=\"mt-l\">5 状态进程模型</h4>\n        <p class=\"dim mt-s\" style=\"font-size:13.5px\">新建（创建中）→ 就绪（等 CPU）→ 运行（在 CPU 上）→ 阻塞（等事件）→ 终止（资源回收中）。<br>+ 挂起状态（被换出内存）：就绪挂起 / 阻塞挂起。</p>\n        <p class=\"dim mt-s\" style=\"font-size:13px\">引入\"挂起\"是为了腾出内存给其他进程。挂起 ≠ 阻塞：挂起是用户/OS 主动换出。</p>\n      </div>\n    </div>"}, {"title": "进程状态 / 控制", "content": "<p class=\"kicker\">03 · 状态机 + 原语</p>\n    <h2 class=\"h2\">7 种转换 + 4 种原语。</h2>\n    <div class=\"grid g2 mt-l\" style=\"align-items:start\">\n      <div>\n        <svg viewBox=\"0 0 480 320\" style=\"width:100%;height:auto\">\n          <defs>\n            <style>\n              .box{fill:#1e1e2e;stroke:#cba6f7;stroke-width:2;rx:8;ry:8}\n              .lbl{font:600 13px var(--font-mono);fill:#cdd6f4;text-anchor:middle;dominant-baseline:central}\n              .arr{stroke:#7f849c;stroke-width:1.5;fill:none;marker-end:url(#a)}\n              .txt{font:500 11px var(--font-mono);fill:#a6adc8}\n            </style>\n            <marker id=\"a\" viewBox=\"0 0 10 10\" refX=\"9\" refY=\"5\" markerWidth=\"6\" markerHeight=\"6\" orient=\"auto\"><path d=\"M0 0 L10 5 L0 10z\" fill=\"#7f849c\"/></marker>\n          </defs>\n          <rect class=\"box\" x=\"180\" y=\"10\" width=\"120\" height=\"44\"/><text class=\"lbl\" x=\"240\" y=\"32\">新建 NEW</text>\n          <rect class=\"box\" x=\"20\" y=\"120\" width=\"120\" height=\"44\"/><text class=\"lbl\" x=\"80\" y=\"142\">就绪 READY</text>\n          <rect class=\"box\" x=\"180\" y=\"120\" width=\"120\" height=\"44\"/><text class=\"lbl\" x=\"240\" y=\"142\">运行 RUNNING</text>\n          <rect class=\"box\" x=\"340\" y=\"120\" width=\"120\" height=\"44\"/><text class=\"lbl\" x=\"400\" y=\"142\">阻塞 WAIT</text>\n          <rect class=\"box\" x=\"180\" y=\"230\" width=\"120\" height=\"44\"/><text class=\"lbl\" x=\"240\" y=\"252\">终止 TERM</text>\n          <path class=\"arr\" d=\"M240,54 L80,120\"/><text class=\"txt\" x=\"120\" y=\"86\">接纳</text>\n          <path class=\"arr\" d=\"M140,142 L180,142\"/><text class=\"txt\" x=\"160\" y=\"132\">调度</text>\n          <path class=\"arr\" d=\"M180,150 L140,150\" stroke=\"#cba6f7\"/><text class=\"txt\" x=\"160\" y=\"170\">时间片到</text>\n          <path class=\"arr\" d=\"M300,142 L340,142\"/><text class=\"txt\" x=\"320\" y=\"132\">等待 IO</text>\n          <path class=\"arr\" d=\"M400,164 C 400,200 260,200 140,164\"/><text class=\"txt\" x=\"270\" y=\"200\">IO 完成</text>\n          <path class=\"arr\" d=\"M240,164 L240,230\"/><text class=\"txt\" x=\"260\" y=\"200\">exit</text>\n        </svg>\n      </div>\n      <div>\n        <h4>四种进程控制原语</h4>\n        <table class=\"cmp-table mt-s\">\n          <tr><th>原语</th><th>执行内容</th></tr>\n          <tr><td><b>创建</b></td><td>申请 PCB → 分配资源 → 初始化 → 入就绪队列</td></tr>\n          <tr><td><b>撤销</b></td><td>终止子孙 → 归还资源 → 释放 PCB</td></tr>\n          <tr><td><b>阻塞</b></td><td>保存运行现场 → 状态改阻塞 → 入对应等待队列</td></tr>\n          <tr><td><b>唤醒</b></td><td>从阻塞队列移出 → 状态改就绪 → 入就绪队列</td></tr>\n        </table>\n        <p class=\"dim mt-s\" style=\"font-size:13px\"><b>原语</b>：用关 / 开中断保证执行不可中断；必在<b>核心态</b>执行。</p>\n        <h4 class=\"mt-l\">易错点</h4>\n        <ul class=\"dim mt-s\" style=\"font-size:13px;line-height:1.85\">\n          <li>就绪 → 阻塞 <b>不存在</b>（必先运行）</li>\n          <li>阻塞 → 运行 <b>不存在</b>（必先就绪）</li>\n          <li>\"阻塞\"是进程自己执行 P 操作或 IO 请求\"主动\"造成的</li>\n        </ul>\n      </div>\n    </div>"}, {"title": "线程", "content": "<p class=\"kicker\">03 · 线程</p>\n    <h2 class=\"h2\">把\"进程\"的两个职责拆开：资源 + 执行。</h2>\n    <div class=\"grid g2 mt-l\" style=\"align-items:start\">\n      <div>\n        <h4>线程 vs 进程</h4>\n        <table class=\"cmp-table mt-s\">\n          <tr><th></th><th>进程</th><th>线程</th></tr>\n          <tr><td>地址空间</td><td>独立</td><td>共享所属进程的</td></tr>\n          <tr><td>切换开销</td><td>大</td><td>小</td></tr>\n          <tr><td>通信</td><td>IPC</td><td>共享变量（需同步）</td></tr>\n          <tr><td>调度单位</td><td>—</td><td>是</td></tr>\n          <tr><td>资源单位</td><td>是</td><td>不是</td></tr>\n        </table>\n        <h4 class=\"mt-l\">线程独占的部分</h4>\n        <p class=\"dim mt-s\" style=\"font-size:13.5px\">PC、寄存器组、栈、线程局部存储 TLS。</p>\n        <h4 class=\"mt-m\">线程共享（来自进程）</h4>\n        <p class=\"dim\" style=\"font-size:13.5px\">代码段、堆、全局变量、文件描述符、信号处理器。</p>\n      </div>\n      <div>\n        <h4>三种实现</h4>\n        <table class=\"cmp-table mt-s\">\n          <tr><th></th><th>用户级 ULT</th><th>内核级 KLT</th></tr>\n          <tr><td>切换</td><td>用户库，快</td><td>陷核，慢</td></tr>\n          <tr><td>阻塞</td><td>整进程阻塞</td><td>仅当前线程</td></tr>\n          <tr><td>多核</td><td>❌</td><td>✅</td></tr>\n          <tr><td>调度</td><td>用户控制</td><td>OS 调度</td></tr>\n        </table>\n        <h4 class=\"mt-l\">多线程模型</h4>\n        <ul class=\"dim mt-s\" style=\"font-size:13.5px;line-height:1.85\">\n          <li><b>多对一</b>：多 ULT 映射到 1 KLT（不能并行）</li>\n          <li><b>一对一</b>：一 ULT 一 KLT（Windows、Linux 默认）</li>\n          <li><b>多对多</b>：M:N 映射（Solaris 早期）</li>\n        </ul>\n      </div>\n    </div>"}, {"title": "三层调度", "content": "<p class=\"kicker\">04 · 调度概念</p>\n    <h2 class=\"h2\">高级 / 中级 / 低级，三层各管一摊。</h2>\n    <div class=\"grid g2 mt-l\" style=\"align-items:start\">\n      <div>\n        <table class=\"cmp-table mt-s\">\n          <tr><th>层级</th><th>对象</th><th>动作</th><th>频率</th></tr>\n          <tr><td><b>高级</b>（作业）</td><td>外存 → 内存</td><td>挑选哪个作业进入内存</td><td>低</td></tr>\n          <tr><td><b>中级</b>（交换）</td><td>内存 ↔ 外存</td><td>挂起 / 激活</td><td>中</td></tr>\n          <tr><td><b>低级</b>（进程）</td><td>就绪 → 运行</td><td>从就绪队列选一个上 CPU</td><td>高</td></tr>\n        </table>\n        <h4 class=\"mt-l\">不能切换的时机</h4>\n        <ul class=\"dim mt-s\" style=\"font-size:13px;line-height:1.85\">\n          <li>关中断时</li>\n          <li>处理中断 / 异常 / 系统调用过程中（部分实现可抢占）</li>\n          <li>在内核临界区</li>\n          <li>原子操作执行中</li>\n        </ul>\n      </div>\n      <div>\n        <h4>调度评价指标</h4>\n        <p class=\"mono mt-s\" style=\"font-size:13.5px;background:var(--surface-2);padding:14px;border-radius:8px;line-height:1.95\">\n          周转时间 = 完成 - 提交<br>\n          带权周转 = 周转 / 服务<br>\n          等待时间 = 周转 - 服务<br>\n          响应时间 = 首次响应 - 请求<br>\n          CPU 利用率 = 忙 / 总<br>\n          吞吐率 = 完成数 / 单位时间\n        </p>\n        <h4 class=\"mt-l\">抢占 vs 非抢占</h4>\n        <ul class=\"dim mt-s\" style=\"font-size:13px;line-height:1.85\">\n          <li><b>非抢占</b>：进程主动让出 CPU（FCFS、SJF 非抢占）</li>\n          <li><b>抢占</b>：更高优先 / 时间片到 → 强行剥夺（SRTN、RR、抢占优先级）</li>\n        </ul>\n        <h4 class=\"mt-m\">饥饿 Starvation</h4>\n        <p class=\"dim mt-s\" style=\"font-size:13px\">低优先级 / 长任务一直不被调度。解决：<b>老化</b> aging — 等待时间越长优先级越高。</p>\n      </div>\n    </div>"}, {"title": "FCFS / SJF / SRTN", "content": "<p class=\"kicker\">04 · 三个基础算法</p>\n    <h2 class=\"h2\">先来先服务 · 短作业 · 最短剩余时间。</h2>\n    <div class=\"grid g2 mt-l\" style=\"align-items:start\">\n      <div>\n        <h4>典型甘特图（4 进程）</h4>\n        <p class=\"dim mt-s\" style=\"font-size:13px\">进程到达：A(0,7) B(2,4) C(4,1) D(5,4)</p>\n        <table class=\"cmp-table mt-s\">\n          <tr><th>FCFS</th><td>A 0-7 | B 7-11 | C 11-12 | D 12-16</td></tr>\n          <tr><th>SJF 非抢占</th><td>A 0-7 | C 7-8 | B 8-12 | D 12-16</td></tr>\n          <tr><th>SRTN</th><td>A 0-2 | B 2-4 | C 4-5 | B 5-7 | D 7-11 | A 11-16</td></tr>\n        </table>\n        <p class=\"dim mt-s\" style=\"font-size:13px\">SJF 在选 B 时 C 还没到；SRTN 一旦更短的来，立即抢占。</p>\n      </div>\n      <div>\n        <h4>三大特点对比</h4>\n        <table class=\"cmp-table mt-s\">\n          <tr><th></th><th>FCFS</th><th>SJF</th><th>SRTN</th></tr>\n          <tr><td>抢占</td><td>否</td><td>否</td><td>是</td></tr>\n          <tr><td>平均等待</td><td>大</td><td>小</td><td>最小</td></tr>\n          <tr><td>护航效应</td><td>有</td><td>无</td><td>无</td></tr>\n          <tr><td>饥饿</td><td>无</td><td>长任务</td><td>长任务</td></tr>\n          <tr><td>实现</td><td>简单</td><td>需 burst 预测</td><td>需 burst + 抢占</td></tr>\n        </table>\n        <p class=\"dim mt-m\" style=\"font-size:13px\">SJF 在 burst 已知或可预测（指数平均 τ_{n+1} = α·t_n + (1-α)τ_n）。<br>SRTN 在新进程到达时再判断一次。</p>\n      </div>\n    </div>"}, {"title": "RR / 优先级 / MLFQ", "content": "<p class=\"kicker\">04 · 交互式算法</p>\n    <h2 class=\"h2\">时间片轮转 · 优先级 · 多级反馈队列。</h2>\n    <div class=\"grid g2 mt-l\" style=\"align-items:start\">\n      <div>\n        <h4>时间片轮转 RR</h4>\n        <ul class=\"dim mt-s\" style=\"font-size:13.5px;line-height:1.85\">\n          <li>就绪队列 FIFO，每进程 q 单位 CPU</li>\n          <li>q 太大 → 退化 FCFS；q 太小 → 切换开销大</li>\n          <li>典型 q = 10~100 ms</li>\n          <li>响应快、公平，但平均周转不一定最小</li>\n        </ul>\n        <h4 class=\"mt-l\">优先级调度</h4>\n        <ul class=\"dim mt-s\" style=\"font-size:13.5px;line-height:1.85\">\n          <li><b>静态优先级</b>：进程创建时定，简单但低优先饥饿</li>\n          <li><b>动态优先级</b>：随运行/等待时间调整（老化）</li>\n          <li><b>抢占式</b>：每当更高优先到达 / 唤醒立即抢占</li>\n          <li><b>非抢占式</b>：当前完成或主动让</li>\n        </ul>\n      </div>\n      <div>\n        <h4>多级反馈队列 MLFQ</h4>\n        <ol class=\"dim mt-s\" style=\"font-size:13.5px;line-height:1.85\">\n          <li>设 k 个就绪队列，优先级由高到低，时间片由短到长</li>\n          <li>新进程进队列 1（最高优先）</li>\n          <li>该队空才调度下一队列</li>\n          <li>用完时间片仍未结束 → 降到下一级</li>\n          <li>队列 k（最低）通常用 RR</li>\n        </ol>\n        <div class=\"viz mt-s\" style=\"font-size:12px\">\nQ1 [优先级高, q=10ms ]  → 用完降级\nQ2 [优先级中, q=20ms ]\nQ3 [优先级低, q=40ms ]\nQ4 [优先级最低, RR    ]\n✅ 短任务快出来 (在 Q1)\n✅ 长任务也不会饿 (下落到 Q4)\n✅ 综合最优</div>\n        <p class=\"dim mt-s\" style=\"font-size:13px\">Unix/Linux 早期调度器使用类似 MLFQ。</p>\n      </div>\n    </div>"}, {"title": "同步互斥", "content": "<p class=\"kicker\">05 · 同步</p>\n    <h2 class=\"h2\">为什么需要同步？为了正确性。</h2>\n    <div class=\"grid g2 mt-l\" style=\"align-items:start\">\n      <div>\n        <h4>同步 vs 互斥</h4>\n        <table class=\"cmp-table mt-s\">\n          <tr><th></th><th>互斥</th><th>同步</th></tr>\n          <tr><td>含义</td><td>共享资源不能同时被多个进程访问</td><td>多进程按特定顺序协作</td></tr>\n          <tr><td>类比</td><td>厕所一人一格</td><td>接力赛跑</td></tr>\n          <tr><td>信号量初值</td><td>1（互斥锁）</td><td>0（事件计数）</td></tr>\n        </table>\n        <h4 class=\"mt-l\">临界区四原则</h4>\n        <ol class=\"dim mt-s\" style=\"font-size:13.5px;line-height:1.85\">\n          <li><b>空闲让进</b>：空闲时任一申请可进</li>\n          <li><b>忙则等待</b>：已有进程在内，其他等</li>\n          <li><b>有限等待</b>：不无限等（防饥饿）</li>\n          <li><b>让权等待</b>：等待时让 CPU（防忙等）</li>\n        </ol>\n      </div>\n      <div>\n        <h4>三种互斥实现</h4>\n        <table class=\"cmp-table mt-s\">\n          <tr><th>方法</th><th>说明</th></tr>\n          <tr><td><b>软件</b></td><td>Peterson 算法 / Dekker，纯算法实现，不需特殊指令</td></tr>\n          <tr><td><b>硬件</b></td><td>关中断（单核）/ TestAndSet / Swap 原子指令</td></tr>\n          <tr><td><b>信号量</b></td><td>OS 提供的高层抽象，PV 操作</td></tr>\n          <tr><td><b>管程</b></td><td>编译器封装互斥与同步，条件变量 wait/signal</td></tr>\n        </table>\n        <h4 class=\"mt-l\">TestAndSet (硬件原语)</h4>\n        <pre class=\"code-block\" style=\"font-size:12.5px\">\n<span class=\"k\">bool</span> <span class=\"f\">TS</span>(<span class=\"k\">bool</span> *lock) {\n  <span class=\"k\">bool</span> old = *lock;\n  *lock = <span class=\"k\">true</span>;\n  <span class=\"k\">return</span> old;       <span class=\"c\">// 原子读改写</span>\n}\n<span class=\"c\">// 自旋锁</span>\n<span class=\"k\">while</span>(TS(&amp;lock)) ;\n进入临界区; ...\nlock = <span class=\"k\">false</span>;</pre>\n      </div>\n    </div>"}, {"title": "信号量 PV", "content": "<p class=\"kicker\">05 · 信号量</p>\n    <h2 class=\"h2\">Dijkstra 的两个魔法函数。</h2>\n    <div class=\"grid g2 mt-l\" style=\"align-items:start\">\n      <div>\n        <h4>整型信号量 vs 记录型</h4>\n        <pre class=\"code-block\" style=\"font-size:12.5px\">\n<span class=\"c\">// 整型: 忙等</span>\n<span class=\"k\">P</span>(S): <span class=\"k\">while</span>(S &lt;= 0) ;  <span class=\"c\">// 自旋</span>\n       S--;\n<span class=\"k\">V</span>(S): S++;\n<span class=\"c\">// 记录型: 让权 (考试用)</span>\n<span class=\"k\">typedef</span> { <span class=\"k\">int</span> value; queue L; } sem;\n<span class=\"k\">P</span>(sem &amp;S):\n  S.value--;\n  <span class=\"k\">if</span>(S.value &lt; 0) block(S.L, self);\n<span class=\"k\">V</span>(sem &amp;S):\n  S.value++;\n  <span class=\"k\">if</span>(S.value &lt;= 0) wakeup(S.L);</pre>\n      </div>\n      <div>\n        <h4>信号量含义</h4>\n        <ul class=\"dim mt-s\" style=\"font-size:13.5px;line-height:1.85\">\n          <li>S.value &gt; 0：还有 S.value 个资源可用</li>\n          <li>S.value = 0：无空闲资源，下一次 P 操作会阻塞</li>\n          <li>S.value &lt; 0：|S.value| 个进程在等</li>\n        </ul>\n        <h4 class=\"mt-l\">P / V 的正确使用</h4>\n        <p class=\"dim mt-s\" style=\"font-size:13.5px\">\"P 资源 → P 互斥 → 临界区 → V 互斥 → V 资源\"。<br>顺序错（先 P 互斥再 P 资源）易死锁。</p>\n        <h4 class=\"mt-m\">原子性</h4>\n        <p class=\"dim mt-s\" style=\"font-size:13px\">PV 由 OS 实现，内部用关中断 / 硬件原语保证原子；用户层只看到不可分割的操作。</p>\n      </div>\n    </div>"}, {"title": "生产者-消费者", "content": "<p class=\"kicker\">06 · 经典问题</p>\n    <h2 class=\"h2\">一缓冲区 · N 生产者 · M 消费者。</h2>\n    <div class=\"grid g2 mt-l\" style=\"align-items:start\">\n      <div>\n        <h4>问题约束</h4>\n        <ul class=\"dim mt-s\" style=\"font-size:13.5px;line-height:1.85\">\n          <li>生产者不能往满缓冲区放</li>\n          <li>消费者不能从空缓冲区取</li>\n          <li>缓冲区共享 → 互斥访问</li>\n          <li>共需三个信号量：mutex / empty / full</li>\n        </ul>\n        <h4 class=\"mt-l\">信号量定义</h4>\n        <p class=\"mono mt-s\" style=\"font-size:13.5px;background:var(--surface-2);padding:10px;border-radius:8px\">\n          mutex = 1 &nbsp;<span class=\"dim\">// 缓冲互斥</span><br>\n          empty = N &nbsp;<span class=\"dim\">// 空槽位数</span><br>\n          full  = 0 &nbsp;<span class=\"dim\">// 已填槽数</span>\n        </p>\n      </div>\n      <div>\n        <pre class=\"code-block\">\n<span class=\"k\">producer</span>():\n  <span class=\"k\">while</span>(<span class=\"k\">true</span>) {\n    produce(item);\n    P(empty);          <span class=\"c\">// 等空槽</span>\n    P(mutex);          <span class=\"c\">// 互斥</span>\n    put(item);\n    V(mutex);\n    V(full);           <span class=\"c\">// 多了一份产品</span>\n  }\n<span class=\"k\">consumer</span>():\n  <span class=\"k\">while</span>(<span class=\"k\">true</span>) {\n    P(full);\n    P(mutex);\n    item = get();\n    V(mutex);\n    V(empty);\n    consume(item);\n  }</pre>\n        <p class=\"dim mt-s\" style=\"font-size:13px\">⚠️ 互换 P 顺序：<br>P(mutex); P(empty); 若 empty=0 → 持锁阻塞 → 消费者拿不到 mutex → <b>死锁</b>。</p>\n      </div>\n    </div>"}, {"title": "R-W + 哲学家", "content": "<p class=\"kicker\">06 · 经典问题 (续)</p>\n    <h2 class=\"h2\">读者-写者 + 哲学家进餐。</h2>\n    <div class=\"grid g2 mt-l\" style=\"align-items:start\">\n      <div>\n        <h4>读优先 R-W</h4>\n        <pre class=\"code-block\" style=\"font-size:12.5px\">\nsem mutex=1, w=1; <span class=\"k\">int</span> rc=0;\n<span class=\"k\">reader</span>():\n  P(mutex); rc++;\n  <span class=\"k\">if</span>(rc==1) P(w);     <span class=\"c\">// 第一个读阻塞写</span>\n  V(mutex);\n  read(); ...\n  P(mutex); rc--;\n  <span class=\"k\">if</span>(rc==0) V(w);     <span class=\"c\">// 最后一个读放写</span>\n  V(mutex);\n<span class=\"k\">writer</span>():\n  P(w); write(); V(w);</pre>\n        <p class=\"dim mt-s\" style=\"font-size:13px\">读者优先：只要有读，写就一直等 → <b>写饥饿</b>。<br>写优先需另加 mutex2 阻塞后续读。</p>\n      </div>\n      <div>\n        <h4>哲学家进餐 5 解</h4>\n        <ol class=\"dim mt-s\" style=\"font-size:13px;line-height:1.85\">\n          <li><b>限制并发</b>：room 信号量 = 4，最多 4 人同时拿筷</li>\n          <li><b>原子拿两筷</b>：检查时同时持有 mutex，两支都空才拿</li>\n          <li><b>奇偶</b>：奇数先左，偶数先右 → 必有一人拿不到任何 → 不死锁</li>\n          <li><b>资源分级</b>：给筷子编号，必从小到大拿</li>\n          <li><b>仲裁</b>：用一信号量当门卫</li>\n        </ol>\n        <p class=\"dim mt-s\" style=\"font-size:13px\"><b>本质</b>：哲学家是死锁的\"循环等待\"原型。任意打破 4 条件之一都能解决。</p>\n      </div>\n    </div>"}, {"title": "死锁四条件", "content": "<p class=\"kicker\">07 · 死锁</p>\n    <h2 class=\"h2\">必要条件 + 三种应对策略。</h2>\n    <div class=\"grid g2 mt-l\" style=\"align-items:start\">\n      <div>\n        <h4>4 个必要条件（同时满足 = 死锁）</h4>\n        <ol class=\"dim mt-s\" style=\"font-size:14px;line-height:1.95\">\n          <li><b>互斥</b>：资源不可共享</li>\n          <li><b>占有并请求</b>：已占有的同时请求新的</li>\n          <li><b>不可剥夺</b>：资源只能自愿释放</li>\n          <li><b>循环等待</b>：进程 → 资源 → 进程 形成环</li>\n        </ol>\n        <h4 class=\"mt-l\">三种应对策略</h4>\n        <table class=\"cmp-table mt-s\">\n          <tr><th></th><th>核心</th><th>代价</th></tr>\n          <tr><td><b>预防</b></td><td>破坏 4 条件之一</td><td>资源利用率降低</td></tr>\n          <tr><td><b>避免</b></td><td>运行时安全性检查</td><td>需预先声明最大需求</td></tr>\n          <tr><td><b>检测+解除</b></td><td>不限制，定期检测</td><td>检测开销 + 回滚损失</td></tr>\n        </table>\n      </div>\n      <div>\n        <h4>预防 · 4 条件分别破坏</h4>\n        <ul class=\"dim mt-s\" style=\"font-size:13.5px;line-height:1.85\">\n          <li><b>破互斥</b>：让所有资源可共享（一般做不到）</li>\n          <li><b>破占有并请求</b>：进程开始前一次性申请所有资源</li>\n          <li><b>破不可剥夺</b>：申请新资源失败时主动释放已有资源</li>\n          <li><b>破循环等待</b>：资源编号，必须按号递增申请</li>\n        </ul>\n        <h4 class=\"mt-l\">检测算法（资源分配图化简）</h4>\n        <p class=\"dim mt-s\" style=\"font-size:13.5px\">把进程节点的\"未被阻塞\"的边都消除：所有边都能消则无死锁。残留环 = 死锁进程。</p>\n        <h4 class=\"mt-m\">解除</h4>\n        <ul class=\"dim mt-s\" style=\"font-size:13px;line-height:1.85\">\n          <li>剥夺资源：抢一个进程的资源给另一个</li>\n          <li>撤销进程：按代价从低到高</li>\n          <li>回滚：让进程退到之前的某个安全点</li>\n        </ul>\n      </div>\n    </div>"}, {"title": "银行家算法", "content": "<p class=\"kicker\">07 · 死锁避免</p>\n    <h2 class=\"h2\">分配前先模拟，找得到安全序列才同意。</h2>\n    <div class=\"grid g2 mt-l\" style=\"align-items:start\">\n      <div>\n        <h4>数据结构</h4>\n        <pre class=\"code-block\" style=\"font-size:12.5px\">\nAvailable[m]      <span class=\"c\">// 各类资源现有数</span>\nMax[n][m]         <span class=\"c\">// 进程最大需求</span>\nAllocation[n][m]  <span class=\"c\">// 已分配</span>\nNeed = Max - Allocation\nRequest[i]        <span class=\"c\">// 进程 i 当前请求</span>\n<span class=\"c\">// 1. 请求合法性</span>\n<span class=\"k\">if</span>(Request &gt; Need || Request &gt; Available)\n  reject 或 阻塞;\n<span class=\"c\">// 2. 试探分配</span>\nAvailable -= Request;\nAllocation += Request;\nNeed -= Request;\n<span class=\"c\">// 3. 安全性检查</span>\n若安全 → 真分配\n否则  → 回退试探</pre>\n      </div>\n      <div>\n        <h4>安全性算法</h4>\n        <pre class=\"code-block\" style=\"font-size:12.5px\">\nWork = Available;\nFinish[i] = <span class=\"k\">false</span>;\n<span class=\"k\">repeat</span>:\n  找 i : Finish[i]=<span class=\"k\">false</span> &amp;&amp;\n         Need[i] &lt;= Work\n  <span class=\"k\">if</span>(找到):\n    Work += Allocation[i]\n    Finish[i] = <span class=\"k\">true</span>\n    continue\n  <span class=\"k\">break</span>;\n<span class=\"k\">if</span>(<span class=\"k\">forall</span> Finish[i]=<span class=\"k\">true</span>)\n  → 安全 (Work 序列即安全序列)\n<span class=\"k\">else</span>\n  → 不安全</pre>\n        <h4 class=\"mt-m\">实战例</h4>\n        <p class=\"dim mt-s\" style=\"font-size:13px\">5 进程 3 类资源，Total=(10,5,7)，Allocation/Need 给定 → 找 Need[i] ≤ Available 的进程逐步释放，直到所有进程 Finish。常见题：给一个新 Request，判断是否安全。</p>\n      </div>\n    </div>"}, {"title": "进程通信 IPC", "content": "<p class=\"kicker\">08 · IPC</p>\n    <h2 class=\"h2\">进程之间怎么\"说话\"。</h2>\n    <div class=\"grid g3 mt-l\">\n      <div class=\"card card-accent\">\n        <h4>共享内存</h4>\n        <ul class=\"dim mt-s\" style=\"font-size:13px;line-height:1.85\">\n          <li>多个进程映射同一段物理内存</li>\n          <li><b>最快</b>，零拷贝</li>\n          <li>但需要 PV / mutex 同步</li>\n          <li>shmget / shmat / shmdt (Linux)</li>\n        </ul>\n      </div>\n      <div class=\"card card-accent\">\n        <h4>消息传递</h4>\n        <ul class=\"dim mt-s\" style=\"font-size:13px;line-height:1.85\">\n          <li>直接通信：send(P, msg) / receive(Q, msg)</li>\n          <li>间接通信：mailbox 邮箱</li>\n          <li>阻塞 / 非阻塞两版</li>\n          <li>OS 负责拷贝，慢但安全</li>\n        </ul>\n      </div>\n      <div class=\"card card-accent\">\n        <h4>管道</h4>\n        <ul class=\"dim mt-s\" style=\"font-size:13px;line-height:1.85\">\n          <li>半双工的\"特殊文件\"</li>\n          <li>匿名管道：只能父子 / 兄弟</li>\n          <li>命名管道 FIFO：任意进程</li>\n          <li>满时写阻塞，空时读阻塞</li>\n        </ul>\n      </div>\n    </div>\n    <div class=\"grid g3 mt-l\">\n      <div class=\"card card-soft\">\n        <b>信号 Signal</b>\n        <p class=\"dim mt-s\" style=\"font-size:12.5px\">异步通知（SIGINT、SIGTERM）；处理函数注册 / 默认动作 / 忽略。</p>\n      </div>\n      <div class=\"card card-soft\">\n        <b>套接字 Socket</b>\n        <p class=\"dim mt-s\" style=\"font-size:12.5px\">网络 IPC，支持本机和跨机；TCP / UDP / Unix Domain。</p>\n      </div>\n      <div class=\"card card-soft\">\n        <b>信号量集 + 共享队列</b>\n        <p class=\"dim mt-s\" style=\"font-size:12.5px\">System V 三件套：sem / msg / shm。</p>\n      </div>\n    </div>"}, {"title": "内存分配", "content": "<p class=\"kicker\">09 · 内存基础</p>\n    <h2 class=\"h2\">从连续分配到动态分区。</h2>\n    <div class=\"grid g2 mt-l\" style=\"align-items:start\">\n      <div>\n        <h4>程序装入方式</h4>\n        <table class=\"cmp-table mt-s\">\n          <tr><th>方式</th><th>说明</th></tr>\n          <tr><td>绝对装入</td><td>编译时确定物理地址；适合单道</td></tr>\n          <tr><td>静态重定位</td><td>装入时修改地址；运行中不能再移</td></tr>\n          <tr><td>动态重定位</td><td>运行时通过<b>重定位寄存器</b> + 偏移；可在内存中移动（现代 OS）</td></tr>\n        </table>\n        <h4 class=\"mt-l\">链接方式</h4>\n        <ul class=\"dim mt-s\" style=\"font-size:13.5px;line-height:1.85\">\n          <li><b>静态链接</b>：装入前合并目标模块</li>\n          <li><b>装入时动态</b>：装入时按需链接</li>\n          <li><b>运行时动态</b>：用到时才链（如 .dll / .so）</li>\n        </ul>\n      </div>\n      <div>\n        <h4>连续分配 4 种 (已淘汰但要会)</h4>\n        <table class=\"cmp-table mt-s\">\n          <tr><th>方法</th><th>规则</th><th>问题</th></tr>\n          <tr><td>单一连续</td><td>整个用户区给一个程序</td><td>低利用率</td></tr>\n          <tr><td>固定分区</td><td>分若干固定大小区</td><td>内部碎片</td></tr>\n          <tr><td>动态分区</td><td>按需切割</td><td>外部碎片</td></tr>\n        </table>\n        <h4 class=\"mt-l\">动态分区分配算法</h4>\n        <ul class=\"dim mt-s\" style=\"font-size:13px;line-height:1.85\">\n          <li><b>首次适应 FF</b>：按地址升序找第一块合适 → 简单、低地址碎片</li>\n          <li><b>最佳适应 BF</b>：找最小够用 → 易产生大量小碎片</li>\n          <li><b>最坏适应 WF</b>：找最大块切 → 大块快用尽</li>\n          <li><b>邻近适应 NF</b>：从上次结束处开始找</li>\n        </ul>\n        <p class=\"dim mt-s\" style=\"font-size:13px\">\"碎片紧凑\"compaction 可以整理外部碎片 → 但需要动态重定位支持。</p>\n      </div>\n    </div>"}, {"title": "分页 + TLB", "content": "<p class=\"kicker\">09 · 分页</p>\n    <h2 class=\"h2\">把内存切成块，把程序切成页，用页表映射。</h2>\n    <div class=\"grid g2 mt-l\" style=\"align-items:start\">\n      <div>\n        <h4>地址变换</h4>\n        <div class=\"viz mt-s\" style=\"font-size:12.5px\">\n逻辑地址 = 页号 P | 页内偏移 d\n  P × 4B + 页表起址 → 页表项 → 物理页框号 F\n物理地址 = F × 页大小 + d\n       或 = F | d  (位拼接)\n页大小通常 = 2^k → 偏移用低 k 位\n页表项 PTE: 物理块号 + 标志位 (V/D/A/U)</div>\n        <h4 class=\"mt-m\">访存次数</h4>\n        <p class=\"dim\" style=\"font-size:13.5px\">基本分页：<b>2 次访存</b>（取页表项 + 取数据）。<br>有 TLB 时：命中只需 1 次（TLB 内含目标页表项）。</p>\n      </div>\n      <div>\n        <h4>TLB 快表</h4>\n        <ul class=\"dim mt-s\" style=\"font-size:13.5px;line-height:1.85\">\n          <li>位于 MMU，相联存储器</li>\n          <li>缓存近期使用的页表项（数十到数百条）</li>\n          <li>命中率通常 &gt; 90%</li>\n          <li>EAT（有效访问时间）= h(t_tlb + t_mem) + (1-h)(t_tlb + 2t_mem)</li>\n        </ul>\n        <h4 class=\"mt-l\">页内碎片</h4>\n        <p class=\"dim mt-s\" style=\"font-size:13.5px\">每个进程最后一页可能不满 → <b>内部碎片</b>，平均损失半页。页越大碎片越多，但页表越小。</p>\n        <p class=\"dim mt-s\" style=\"font-size:13px\">典型页大小：4 KB、8 KB（Linux x86 默认 4 KB）。</p>\n        <h4 class=\"mt-m\">页表项标志位</h4>\n        <p class=\"dim mt-s\" style=\"font-size:13px\">V 有效位 / D 修改位（dirty）/ A 访问位 / U 用户权限 / R/W 读写位 / G 全局位。</p>\n      </div>\n    </div>"}, {"title": "多级 / 反置页表", "content": "<p class=\"kicker\">09 · 大地址空间</p>\n    <h2 class=\"h2\">32 位 / 64 位下页表怎么\"瘦身\"。</h2>\n    <div class=\"grid g2 mt-l\" style=\"align-items:start\">\n      <div>\n        <h4>问题</h4>\n        <p class=\"dim mt-s\" style=\"font-size:13.5px\">32 位虚拟地址，4 KB 页：页表项数 = 2³²/2¹² = 2²⁰ = 1M 项。每项 4 字节 → <b>4 MB 页表 / 进程</b>。100 个进程就要 400MB。</p>\n        <h4 class=\"mt-l\">二级页表</h4>\n        <div class=\"viz mt-s\" style=\"font-size:12px\">\n逻辑地址 = 一级页号 | 二级页号 | 页内偏移\n           10 位      10 位       12 位\n         一级页表 (页目录, 4KB)\n            |\n            ↓\n         二级页表 (按需创建)\n            |\n            ↓\n         物理页框 + 偏移\n未访问的二级页表不创建 → 实际省内存</div>\n      </div>\n      <div>\n        <h4>反置页表 IPT</h4>\n        <p class=\"dim mt-s\" style=\"font-size:13.5px\">每个<b>物理页框</b>一项，全 OS 共一张表（不再按进程）。</p>\n        <p class=\"mono mt-s\" style=\"font-size:13px;background:var(--surface-2);padding:10px;border-radius:8px\">\n          表项 = &lt;PID, 页号 P, 控制位&gt;<br>\n          地址变换：(PID, P) → hash → 表项 i → 物理帧 i\n        </p>\n        <ul class=\"dim mt-s\" style=\"font-size:13px;line-height:1.85\">\n          <li>表大小：与物理内存正比，与虚拟空间无关</li>\n          <li>查找慢 → 配 TLB 弥补</li>\n          <li>共享页较难表达</li>\n          <li>Power、UltraSPARC 用</li>\n        </ul>\n        <h4 class=\"mt-l\">64 位 → 4 级或 5 级</h4>\n        <p class=\"dim mt-s\" style=\"font-size:13px\">x86_64：48 位地址，4 KB 页 → 4 级页表（9+9+9+9+12 位）。Intel 5 级页表支持 56/57 位虚拟地址。</p>\n      </div>\n    </div>"}, {"title": "分段 / 段页式", "content": "<p class=\"kicker\">09 · 段页</p>\n    <h2 class=\"h2\">把\"逻辑分段\"和\"物理分页\"叠起来。</h2>\n    <div class=\"grid g2 mt-l\" style=\"align-items:start\">\n      <div>\n        <h4>分段</h4>\n        <div class=\"viz mt-s\" style=\"font-size:12.5px\">\n逻辑地址 = 段号 S | 段内偏移 W\n段表项: 基址 + 段长\n判越界: W ≥ 段长 → 异常\n物理地址: 基址 + W\n✅ 段可独立编译、动态扩展、共享\n✅ 符合用户视角 (代码段/数据段/堆栈段)\n❌ 外部碎片 (段大小不一)</div>\n        <h4 class=\"mt-m\">分页 vs 分段</h4>\n        <table class=\"cmp-table mt-s\">\n          <tr><th></th><th>分页</th><th>分段</th></tr>\n          <tr><td>大小</td><td>固定</td><td>可变</td></tr>\n          <tr><td>地址</td><td>一维</td><td>二维</td></tr>\n          <tr><td>视角</td><td>物理</td><td>逻辑</td></tr>\n          <tr><td>碎片</td><td>内部</td><td>外部</td></tr>\n        </table>\n      </div>\n      <div>\n        <h4>段页式</h4>\n        <div class=\"viz mt-s\" style=\"font-size:12px\">\n逻辑地址 = 段号 S | 段内页号 P | 页内偏移 d\n  S → 段表项 (页表起址, 段长)\n  P → 页表项 (物理块号 F)\n  物理 = F | d\n三次访存 (段表 → 页表 → 数据)\n配 TLB 后 ≈ 一次访存</div>\n        <p class=\"dim mt-s\" style=\"font-size:13.5px\">既保留分段的逻辑独立 / 共享 / 保护，又用分页解决碎片。<br>每段单独分页，段内的页表起址在段表中。</p>\n        <h4 class=\"mt-l\">保护与共享</h4>\n        <ul class=\"dim mt-s\" style=\"font-size:13px;line-height:1.85\">\n          <li><b>分段共享</b>：在段表中指向同一段（共享代码段）</li>\n          <li><b>分页共享</b>：两个进程的页表项指向同一物理帧（写时拷贝）</li>\n          <li>分页保护：页表项的 R/W、U/S 位</li>\n        </ul>\n      </div>\n    </div>"}, {"title": "虚拟内存", "content": "<p class=\"kicker\">10 · 虚拟内存</p>\n    <h2 class=\"h2\">让程序\"假装\"内存比实际大。</h2>\n    <div class=\"grid g2 mt-l\" style=\"align-items:start\">\n      <div>\n        <h4>基础</h4>\n        <p class=\"dim mt-s\" style=\"font-size:13.5px\">利用程序的<b>局部性原理</b>：只调入当前真用到的页；缺页时再从磁盘换入。</p>\n        <ul class=\"dim mt-s\" style=\"font-size:13px;line-height:1.85\">\n          <li>时间局部性：刚访问的近期还会用</li>\n          <li>空间局部性：附近地址会被一起用</li>\n          <li>虚拟地址空间可以远大于物理内存</li>\n        </ul>\n        <h4 class=\"mt-l\">页表项扩展</h4>\n        <p class=\"mono mt-s\" style=\"font-size:13px;background:var(--surface-2);padding:10px;border-radius:8px\">\n          物理块号 | V 有效 | D 修改 | A 访问 | U/S 权限\n        </p>\n        <p class=\"dim mt-s\" style=\"font-size:13px\">V=0 表示该页不在内存中。</p>\n      </div>\n      <div>\n        <h4>缺页中断处理 8 步</h4>\n        <ol class=\"steps mt-s\" style=\"font-size:13px;counter-reset:s 0\">\n          <li>CPU 取页表项发现 V=0</li>\n          <li>触发缺页中断 → 进入核心态</li>\n          <li>OS 找空闲物理块（无则调置换算法）</li>\n          <li>若被换出页的 D=1 → 先写回磁盘</li>\n          <li>把目标页从磁盘读入物理块</li>\n          <li>更新页表：V=1，填入物理块号</li>\n          <li>更新 TLB</li>\n          <li>重启被中断的指令</li>\n        </ol>\n        <h4 class=\"mt-l\">驻留集 + 分配策略</h4>\n        <ul class=\"dim mt-s\" style=\"font-size:13px;line-height:1.85\">\n          <li>固定 / 可变驻留集</li>\n          <li>局部置换：只在本进程范围内换</li>\n          <li>全局置换：可以挑别的进程的页</li>\n          <li>固定+局部 / 可变+全局 / 可变+局部</li>\n        </ul>\n      </div>\n    </div>"}, {"title": "置换算法", "content": "<p class=\"kicker\">10 · 置换</p>\n    <h2 class=\"h2\">四种算法对比 + Belady 异常。</h2>\n    <div class=\"grid g2 mt-l\" style=\"align-items:start\">\n      <div>\n        <table class=\"cmp-table mt-s\">\n          <tr><th>算法</th><th>规则</th><th>问题</th></tr>\n          <tr><td><b>OPT</b></td><td>淘汰未来最久不用</td><td>无法实现（无未来信息）</td></tr>\n          <tr><td><b>FIFO</b></td><td>淘汰最早进入的页</td><td>Belady 异常</td></tr>\n          <tr><td><b>LRU</b></td><td>淘汰最近最久未用</td><td>实现开销大</td></tr>\n          <tr><td><b>Clock</b> (简单)</td><td>循环扫，用访问位 A=0 替换</td><td>近似 LRU</td></tr>\n          <tr><td><b>Clock</b> 改进</td><td>(A,D) → (0,0) &lt; (0,1) &lt; (1,0) &lt; (1,1)</td><td>考虑修改位减少写回</td></tr>\n        </table>\n        <h4 class=\"mt-l\">Belady 异常</h4>\n        <p class=\"dim mt-s\" style=\"font-size:13.5px\">FIFO 算法下，物理块数<b>增加</b>反而<b>缺页率上升</b>的反常现象。LRU、OPT 不会出现。</p>\n      </div>\n      <div>\n        <h4>LRU 模拟例</h4>\n        <p class=\"mono mt-s\" style=\"font-size:13px\">页面引用串：7,0,1,2,0,3,0,4,2,3</p>\n        <p class=\"mono mt-s\" style=\"font-size:12px\">3 个物理块：</p>\n        <div class=\"viz\" style=\"font-size:12px\">\n访  缓存       缺页?\n7   7         √\n0   7 0       √\n1   7 0 1     √\n2   0 1 2     √ (7 最久没用)\n0   1 2 0     ×\n3   2 0 3     √ (1 最久没用)\n0   2 0 3     ×\n4   0 3 4     √ (2 最久没用)\n2   3 4 2     √\n3   4 2 3     ×\n共 7 次缺页</div>\n        <h4 class=\"mt-l\">Clock 算法描述</h4>\n        <p class=\"dim mt-s\" style=\"font-size:13px\">页框组成环形链表，扫描指针顺序前进；访问位 A：1→清零并跳过；0→替换并新页 A=1。</p>\n      </div>\n    </div>"}, {"title": "工作集 / 抖动", "content": "<p class=\"kicker\">10 · 内存调优</p>\n    <h2 class=\"h2\">分配的物理块要恰到好处。</h2>\n    <div class=\"grid g2 mt-l\" style=\"align-items:start\">\n      <div>\n        <h4>抖动 Thrashing</h4>\n        <p class=\"dim mt-s\" style=\"font-size:13.5px\">物理块过少 → 缺页频繁 → CPU 大量时间在换页而非计算 → 系统吞吐反而下降。</p>\n        <p class=\"dim mt-s\" style=\"font-size:13.5px\">原因：进程数太多、驻留集太小。</p>\n        <h4 class=\"mt-l\">两种解决思路</h4>\n        <ul class=\"dim mt-s\" style=\"font-size:13px;line-height:1.85\">\n          <li><b>工作集模型</b> Working Set：W(t,Δ) = 时刻 t 之前 Δ 时间窗口内访问过的页集合。给每个进程的驻留集 ≥ W。</li>\n          <li><b>缺页频率</b> PFF：监控缺页率，过高 → 加分配；过低 → 减分配</li>\n        </ul>\n      </div>\n      <div>\n        <h4>程序结构与缺页</h4>\n        <p class=\"dim mt-s\" style=\"font-size:13.5px\">同样的逻辑，按行 vs 按列访问 NxM 数组缺页次数可相差 N 倍（行优先存储时按行访问最佳）。</p>\n        <pre class=\"code-block\" style=\"font-size:12px\">\n<span class=\"c\">// 假设页大小 4KB, int 4B, 1页=1024个int</span>\n<span class=\"c\">// 二维数组 1024×1024 行优先</span>\n<span class=\"c\">// 好: 按行访问</span>\n<span class=\"k\">for</span>(i=0; i&lt;1024; i++)\n  <span class=\"k\">for</span>(j=0; j&lt;1024; j++)\n    a[i][j] = 0;    <span class=\"c\">// 缺页 1024 次</span>\n<span class=\"c\">// 差: 按列访问</span>\n<span class=\"k\">for</span>(j=0; j&lt;1024; j++)\n  <span class=\"k\">for</span>(i=0; i&lt;1024; i++)\n    a[i][j] = 0;    <span class=\"c\">// 缺页 1024×1024 次!</span></pre>\n      </div>\n    </div>"}, {"title": "文件 / FCB / inode", "content": "<p class=\"kicker\">11 · 文件</p>\n    <h2 class=\"h2\">文件 = 数据 + 元信息。</h2>\n    <div class=\"grid g2 mt-l\" style=\"align-items:start\">\n      <div>\n        <h4>文件控制块 FCB</h4>\n        <p class=\"dim mt-s\" style=\"font-size:13.5px\">每个文件对应一个 FCB（也叫 inode），存元信息。</p>\n        <p class=\"mono mt-s\" style=\"font-size:13px;background:var(--surface-2);padding:10px;border-radius:8px\">\n          inode 内容：<br>\n          类型 / 大小 / 时间戳<br>\n          权限 (r/w/x × user/group/other)<br>\n          链接计数<br>\n          数据块指针（12 直接 + 1/2/3 级间接）\n        </p>\n        <h4 class=\"mt-l\">三种目录结构</h4>\n        <ul class=\"dim mt-s\" style=\"font-size:13px;line-height:1.85\">\n          <li><b>单级</b>：一张表，名字必须全局唯一</li>\n          <li><b>两级</b>：每用户一目录</li>\n          <li><b>树形</b>：路径唯一标识；分相对路径 / 绝对路径</li>\n          <li><b>图形</b>：允许硬链接（共享 inode）</li>\n        </ul>\n      </div>\n      <div>\n        <h4>软链接 vs 硬链接</h4>\n        <table class=\"cmp-table mt-s\">\n          <tr><th></th><th>硬链接</th><th>软链接</th></tr>\n          <tr><td>本质</td><td>新目录项指向同一 inode</td><td>新文件，内容为路径字符串</td></tr>\n          <tr><td>跨分区</td><td>❌</td><td>✅</td></tr>\n          <tr><td>目录</td><td>❌</td><td>✅</td></tr>\n          <tr><td>源删除</td><td>另一份还能用</td><td>失效（悬空）</td></tr>\n          <tr><td>引用计数</td><td>+1</td><td>不变</td></tr>\n        </table>\n        <h4 class=\"mt-l\">文件保护</h4>\n        <ul class=\"dim mt-s\" style=\"font-size:13px;line-height:1.85\">\n          <li>访问控制表 ACL</li>\n          <li>访问权限：r / w / x / append</li>\n          <li>Unix 权限：rwxrwxrwx（owner/group/other）</li>\n          <li>口令 / 加密</li>\n        </ul>\n      </div>\n    </div>"}, {"title": "分配 + 空闲管理", "content": "<p class=\"kicker\">11 · 物理结构</p>\n    <h2 class=\"h2\">文件数据怎么放进磁盘。</h2>\n    <div class=\"grid g2 mt-l\" style=\"align-items:start\">\n      <div>\n        <h4>三种文件分配</h4>\n        <table class=\"cmp-table mt-s\">\n          <tr><th>方式</th><th>优点</th><th>缺点</th></tr>\n          <tr><td>连续</td><td>顺序快，random O(1)</td><td>外部碎片，难扩展</td></tr>\n          <tr><td>链接</td><td>无碎片，扩展容易</td><td>random 慢，1 块坏全坏</td></tr>\n          <tr><td>索引</td><td>random 快，扩展灵活</td><td>额外索引块</td></tr>\n          <tr><td>多级索引</td><td>支持超大文件</td><td>访问深度大</td></tr>\n        </table>\n        <h4 class=\"mt-l\">Unix 混合索引</h4>\n        <div class=\"viz mt-s\" style=\"font-size:11.5px\">\ninode (假设块 1KB, 指针 4B → 一块容 256 指针)\n├── 直接索引 ×12   →  12 KB\n├── 一级间接 ×1   →  256 KB\n├── 二级间接 ×1   →  64 MB\n└── 三级间接 ×1   →  16 GB\n文件最大 ≈ 12 + 256 + 256² + 256³ 块</div>\n      </div>\n      <div>\n        <h4>空闲管理</h4>\n        <ul class=\"dim mt-s\" style=\"font-size:13.5px;line-height:1.85\">\n          <li><b>空闲表</b>：连续区段，类似分区</li>\n          <li><b>空闲链</b>：所有空闲块串成链</li>\n          <li><b>位示图</b>：1 bit/块；1=分配，0=空闲<br>n 块磁盘需 n bit = ⌈n/8⌉ 字节</li>\n          <li><b>成组链接</b>：每 100 块为一组，组首块存指向下一组的指针</li>\n        </ul>\n        <h4 class=\"mt-l\">位示图计算</h4>\n        <p class=\"mono mt-s\" style=\"font-size:13px;background:var(--surface-2);padding:10px;border-radius:8px\">\n          字号 i, 位号 j, 每字 32 bit<br>\n          块号 b = 32·i + j<br>\n          反过来 i = b / 32, j = b % 32\n        </p>\n      </div>\n    </div>"}, {"title": "磁盘 + IO 控制", "content": "<p class=\"kicker\">12 · IO</p>\n    <h2 class=\"h2\">磁盘调度 + 4 种 IO 方式 + SPOOLing。</h2>\n    <div class=\"grid g2 mt-l\" style=\"align-items:start\">\n      <div>\n        <h4>磁盘访问时间</h4>\n        <p class=\"mono mt-s\" style=\"font-size:13.5px;background:var(--surface-2);padding:10px;border-radius:8px\">\n          T = T_寻道 + T_旋转 + T_传输<br>\n          <span class=\"dim\">// 寻道占主导，调度优化的就是这一项</span>\n        </p>\n        <h4 class=\"mt-m\">5 种调度算法</h4>\n        <table class=\"cmp-table mt-s\">\n          <tr><th>算法</th><th>规则</th></tr>\n          <tr><td><b>FCFS</b></td><td>到达顺序，公平</td></tr>\n          <tr><td><b>SSTF</b></td><td>最短寻道优先，可能远端饥饿</td></tr>\n          <tr><td><b>SCAN</b>（电梯）</td><td>一个方向扫到底再回头</td></tr>\n          <tr><td><b>C-SCAN</b></td><td>扫到尽头直接跳回起点</td></tr>\n          <tr><td><b>LOOK</b> / <b>C-LOOK</b></td><td>不到尽头，到最远请求就回头</td></tr>\n        </table>\n      </div>\n      <div>\n        <h4>4 种 IO 控制方式</h4>\n        <table class=\"cmp-table mt-s\">\n          <tr><th>方式</th><th>CPU 介入度</th><th>每次单位</th></tr>\n          <tr><td>查询</td><td>持续轮询</td><td>1 字</td></tr>\n          <tr><td>中断</td><td>就绪通知</td><td>1 字 / 中断</td></tr>\n          <tr><td><b>DMA</b></td><td>启动 + 结束</td><td>1 块 / 中断</td></tr>\n          <tr><td>通道</td><td>仅启动通道程序</td><td>1 组数据 / 中断</td></tr>\n        </table>\n        <h4 class=\"mt-l\">缓冲 + SPOOLing</h4>\n        <ul class=\"dim mt-s\" style=\"font-size:13px;line-height:1.85\">\n          <li>单缓冲：完成 IO 时 CPU 才能继续</li>\n          <li>双缓冲：CPU 与 IO 可并行</li>\n          <li>循环缓冲：多个缓冲区轮换</li>\n          <li><b>SPOOLing</b>：用磁盘虚拟独占设备（打印机），输入井 / 输出井，提交即返回</li>\n        </ul>\n      </div>\n    </div>"}]}, "computer-network": {"title": "计算机网络", "weight": "25分", "slides": [{"title": "Cover", "content": "<p class=\"kicker\">408 · COMPUTER NETWORK · 谢希仁 完整版</p>\n    <h1 class=\"h1 huge anim-fade-up\" data-anim=\"fade-up\">计算机网络</h1>\n    <h2 class=\"h2\" style=\"font-weight:400;color:var(--text-2);margin-top:-8px\"><span class=\"gradient-text\">五层之上</span>，每一行字、每一张图，都在跑长跑。</h2>\n    <p class=\"lede mt-l\">28 节课，从五层模型起步：物理层编码、链路层 CRC 计算、IP 与子网划分、TCP 三次握手 + 滑动窗口 + 拥塞控制、DNS / HTTP 完整解析，每一项都给出算例和代码。</p>\n    <div class=\"label-strip\">\n      <span class=\"pill\">~25 分</span>\n      <span class=\"pill\">5 层 28 节</span>\n      <span class=\"pill\">大题：CRC / 子网 / TCP</span>\n    </div>"}, {"title": "目录", "content": "<p class=\"kicker\">// agenda</p>\n    <h2 class=\"h2\">28 张卡片：一条 HTTP 请求的全旅程</h2>\n    <div class=\"grid g3 mt-l\" style=\"gap:24px;font-size:13px\">\n      <div>\n        <h4 style=\"font-size:15px\">体系 + 物理 + 链路</h4>\n        <ol class=\"steps mt-s\" style=\"counter-reset:s 0\">\n          <li>OSI 与 TCP/IP 模型</li>\n          <li>物理层编码</li>\n          <li>物理层复用 + 介质</li>\n          <li>链路层成帧 + CRC</li>\n          <li>流量控制 + ARQ</li>\n          <li>介质访问控制</li>\n          <li>以太网帧 + MAC</li>\n          <li>交换机 + VLAN</li>\n          <li>无线 802.11</li>\n        </ol>\n      </div>\n      <div>\n        <h4 style=\"font-size:15px\">网络层 + 路由</h4>\n        <ol class=\"steps mt-s\" style=\"counter-reset:s 9\">\n          <li>IP 数据报详细</li>\n          <li>IP 地址分类</li>\n          <li>子网划分完整算例</li>\n          <li>CIDR + 路由表查找</li>\n          <li>NAT + IPv6</li>\n          <li>路由协议 RIP/OSPF/BGP</li>\n          <li>ARP / ICMP / DHCP</li>\n        </ol>\n      </div>\n      <div>\n        <h4 style=\"font-size:15px\">传输 + 应用</h4>\n        <ol class=\"steps mt-s\" style=\"counter-reset:s 16\">\n          <li>UDP 详细</li>\n          <li>TCP 首部</li>\n          <li>三次/四次握手</li>\n          <li>TCP 状态机</li>\n          <li>流量控制 / 滑动窗口</li>\n          <li>拥塞控制 4 算法</li>\n          <li>DNS 解析</li>\n          <li>HTTP / HTTPS</li>\n          <li>邮件 / FTP</li>\n          <li>整体回顾</li>\n        </ol>\n      </div>\n    </div>"}, {"title": "OSI / TCP/IP", "content": "<p class=\"kicker\">01 · 体系结构</p>\n    <h2 class=\"h2\">OSI 七层 vs TCP/IP 四层 vs 五层教学版</h2>\n    <div class=\"grid g2 mt-l\" style=\"align-items:start\">\n      <div>\n        <div class=\"layers\">\n          <div class=\"layer app\"><div><span class=\"ln\">应用层</span> · 数据 Data</div><span class=\"pdu\">HTTP / DNS / SMTP / FTP</span></div>\n          <div class=\"layer tra\"><div><span class=\"ln\">传输层</span> · 报文段 Segment</div><span class=\"pdu\">TCP / UDP</span></div>\n          <div class=\"layer net\"><div><span class=\"ln\">网络层</span> · 数据报 Packet</div><span class=\"pdu\">IP / ICMP / ARP</span></div>\n          <div class=\"layer link\"><div><span class=\"ln\">数据链路层</span> · 帧 Frame</div><span class=\"pdu\">以太网 / PPP / HDLC</span></div>\n          <div class=\"layer phy\"><div><span class=\"ln\">物理层</span> · 比特 Bit</div><span class=\"pdu\">电缆 / 光纤 / 无线</span></div>\n        </div>\n        <h4 class=\"mt-l\">封装与解封</h4>\n        <p class=\"dim mt-s\" style=\"font-size:13px\">每下一层 → 加自己的 header；每上一层 → 剥掉。<b>同层对等通信，实际数据沿栈\"折跃\"</b>。</p>\n      </div>\n      <div>\n        <h4>同层对应设备</h4>\n        <table class=\"cmp-table mt-s\">\n          <tr><th>层</th><th>设备</th><th>转发依据</th></tr>\n          <tr><td>物理</td><td>中继器 / 集线器</td><td>仅放大信号</td></tr>\n          <tr><td>链路</td><td>网桥 / 交换机</td><td>MAC 地址表</td></tr>\n          <tr><td>网络</td><td>路由器</td><td>IP 路由表</td></tr>\n          <tr><td>传输+</td><td>网关 / 防火墙</td><td>协议转换 / 端口</td></tr>\n        </table>\n        <h4 class=\"mt-l\">三个域</h4>\n        <ul class=\"dim mt-s\" style=\"font-size:13.5px;line-height:1.85\">\n          <li><b>冲突域</b>：可能争用同一介质的范围；集线器扩大、交换机分隔</li>\n          <li><b>广播域</b>：广播帧能到的范围；交换机扩大、路由器分隔</li>\n          <li><b>VLAN</b>：在交换机层逻辑划分广播域</li>\n        </ul>\n      </div>\n    </div>"}, {"title": "物理层 · 编码", "content": "<p class=\"kicker\">02 · 物理层</p>\n    <h2 class=\"h2\">把比特送上线路 + 4 种编码 + 2 个定理。</h2>\n    <div class=\"grid g2 mt-l\" style=\"align-items:start\">\n      <div>\n        <h4>关键公式</h4>\n        <ul class=\"dim mt-s\" style=\"font-size:14px;line-height:1.95\">\n          <li>奈奎斯特：<b>C = 2W log₂V</b>（无噪声）</li>\n          <li>香农：<b>C = W log₂(1 + S/N)</b>（有噪声）</li>\n          <li>S/N(dB) = 10 log₁₀(S/N)</li>\n          <li>码元速率 (Baud) = 信号变化次数 / 秒</li>\n          <li>比特率 (bps) = 码元 × log₂V</li>\n        </ul>\n        <h4 class=\"mt-l\">实例</h4>\n        <p class=\"dim mt-s\" style=\"font-size:13px\">带宽 3kHz、S/N = 30 dB（千倍）：<br>香农容量 = 3000 × log₂(1001) ≈ 30 kbps</p>\n      </div>\n      <div>\n        <h4>编码方式</h4>\n        <div class=\"viz mt-s\" style=\"font-size:12.5px\">\nNRZ 不归零：    高电平=1, 低电平=0\n              （需另发时钟同步）\nRZ 归零：       每位前半信号, 后半 0\n              （自带同步, 但占带宽多）\n曼彻斯特：     高→低=0, 低→高=1\n              （自同步, 以太网用; 带宽×2）\n差分曼彻斯特：每位起点跳变=0, 不跳=1\n              （抗干扰强）\nNRZI:          翻转=1, 不翻=0</div>\n        <h4 class=\"mt-m\">基带 vs 频带</h4>\n        <ul class=\"dim mt-s\" style=\"font-size:13px;line-height:1.85\">\n          <li><b>基带</b>：直接发送数字信号（短距、局域网）</li>\n          <li><b>频带</b>：用调制变成模拟（ASK/FSK/PSK/QAM）远距、电话线</li>\n        </ul>\n      </div>\n    </div>"}, {"title": "物理层 · 复用 / 介质", "content": "<p class=\"kicker\">02 · 多路复用</p>\n    <h2 class=\"h2\">让一条物理通道承载多路逻辑信号。</h2>\n    <div class=\"grid g2 mt-l\" style=\"align-items:start\">\n      <div>\n        <h4>4 种复用</h4>\n        <table class=\"cmp-table mt-s\">\n          <tr><th>类型</th><th>原理</th><th>例</th></tr>\n          <tr><td><b>FDM</b> 频分</td><td>不同频段同时传</td><td>调频广播、ADSL</td></tr>\n          <tr><td><b>TDM</b> 时分</td><td>不同时隙轮流</td><td>电话、E1</td></tr>\n          <tr><td><b>WDM</b> 波分</td><td>光纤不同波长</td><td>骨干光纤</td></tr>\n          <tr><td><b>CDM</b> 码分</td><td>正交码区分</td><td>CDMA 移动通信</td></tr>\n        </table>\n        <h4 class=\"mt-l\">同步 vs 统计 TDM</h4>\n        <p class=\"dim mt-s\" style=\"font-size:13px\">同步 TDM：每个用户固定时隙，空闲也不分配 → 浪费。<br>统计 TDM：按需分配（信元 / 数据包）→ 高效，但需排队。</p>\n      </div>\n      <div>\n        <h4>传输介质</h4>\n        <table class=\"cmp-table mt-s\">\n          <tr><th>介质</th><th>带宽</th><th>距离 / 用途</th></tr>\n          <tr><td>双绞线 UTP</td><td>100 Mbps - 10 Gbps</td><td>百 m / 局域网</td></tr>\n          <tr><td>同轴电缆</td><td>类似</td><td>CATV、早期以太</td></tr>\n          <tr><td>单模光纤</td><td>40 Gbps+</td><td>数十 km / 长距</td></tr>\n          <tr><td>多模光纤</td><td>10 Gbps</td><td>2 km / 短距</td></tr>\n          <tr><td>无线 Wi-Fi</td><td>54 Mbps - 9 Gbps</td><td>百 m / 室内</td></tr>\n          <tr><td>微波 / 卫星</td><td>多种</td><td>跨海 / 偏远</td></tr>\n        </table>\n        <p class=\"dim mt-s\" style=\"font-size:13px\">5e/6 类双绞线是局域网默认；单模光纤适合干线。</p>\n      </div>\n    </div>"}, {"title": "链路层 · CRC", "content": "<p class=\"kicker\">03 · 数据链路</p>\n    <h2 class=\"h2\">成帧方式 + CRC 完整计算。</h2>\n    <div class=\"grid g2 mt-l\" style=\"align-items:start\">\n      <div>\n        <h4>4 种成帧</h4>\n        <ul class=\"dim mt-s\" style=\"font-size:13.5px;line-height:1.85\">\n          <li><b>字符计数</b>：首字段计长（一处错全乱）</li>\n          <li><b>字符填充</b>：FLAG 边界 + ESC 转义（PPP 用）</li>\n          <li><b>零比特填充</b>：连 5 个 1 后插 0（HDLC）</li>\n          <li><b>违规编码</b>：用物理层\"非法\"模式做边界</li>\n        </ul>\n        <h4 class=\"mt-l\">差错检测 CRC</h4>\n        <p class=\"mono mt-s\" style=\"font-size:14px;background:var(--surface-2);padding:12px;border-radius:8px;line-height:1.95\">\n          M(x) · 2^r = Q(x) · G(x) + R(x)<br>\n          发送 = (M · 2^r) XOR R<br>\n          收方用 G(x) 除整帧，余数 = 0 → 无错\n        </p>\n      </div>\n      <div>\n        <h4>完整 CRC 计算示例</h4>\n        <p class=\"dim mt-s\" style=\"font-size:13.5px\">数据 M = 101001（6 位），G = 1101（r=3 位余数）</p>\n        <pre class=\"code-block\" style=\"font-size:12.5px\">\nM · 2³ = 101001 000\n   101001000 ÷ 1101 =\n   1101\n   ────\n    11110\n    1101\n    ────\n     0111\n     0\n     ────\n      1110\n      1101\n      ────\n       0110\n       0\n       ────\n        1100\n        1101\n        ────\n        0001  ← R = 001\n发送 = 101001 001  (帧)\n接收 = 101001 001 ÷ 1101 → 余数 0 → OK</pre>\n        <p class=\"dim mt-s\" style=\"font-size:13px\">CRC 只能<b>检错</b>，不能纠错。多项式越长检错能力越强。</p>\n      </div>\n    </div>"}, {"title": "流量控制 + ARQ", "content": "<p class=\"kicker\">03 · 可靠传输</p>\n    <h2 class=\"h2\">停-等 · GBN · SR · 三种 ARQ 策略。</h2>\n    <div class=\"grid g2 mt-l\" style=\"align-items:start\">\n      <div>\n        <h4>停-等 Stop-and-Wait</h4>\n        <p class=\"dim mt-s\" style=\"font-size:13.5px\">发一帧 → 等 ACK → 再发下一帧。超时则重传。简单但信道利用率低。</p>\n        <p class=\"mono mt-s\" style=\"font-size:13px;background:var(--surface-2);padding:10px;border-radius:8px\">\n          U = T_d / (T_d + RTT)\n        </p>\n        <h4 class=\"mt-l\">GBN 后退 N</h4>\n        <ul class=\"dim mt-s\" style=\"font-size:13px;line-height:1.85\">\n          <li>发送窗口 W ≤ 2^n − 1（n 位序号）</li>\n          <li>接收窗口 = 1，按序到达才接受</li>\n          <li>接收方丢失某帧 → 之后<b>所有</b>帧丢弃</li>\n          <li>发送方超时 → 重传从该帧开始的所有未确认帧</li>\n          <li>使用累积 ACK</li>\n        </ul>\n      </div>\n      <div>\n        <h4>SR 选择重传</h4>\n        <ul class=\"dim mt-s\" style=\"font-size:13.5px;line-height:1.85\">\n          <li>发送 / 接收窗口都 ≤ 2^(n-1)（序号空间一半）</li>\n          <li>接收方对每帧单独确认 / 缓存</li>\n          <li>发送方仅重传超时 / 被 NACK 的那一帧</li>\n          <li>带宽利用最高</li>\n        </ul>\n        <h4 class=\"mt-l\">利用率公式</h4>\n        <p class=\"mono mt-s\" style=\"font-size:13px;background:var(--surface-2);padding:12px;border-radius:8px;line-height:1.95\">\n          U = W·T_d / (T_d + RTT)<br>\n          U ≤ 1 → W ≥ (T_d + RTT)/T_d<br>\n          <span class=\"dim\">// 窗口够大才能填满\"飞行中\"</span>\n        </p>\n        <h4 class=\"mt-m\">序号空间 vs 窗口</h4>\n        <ul class=\"dim mt-s\" style=\"font-size:13px;line-height:1.85\">\n          <li>停等：序号 1 位</li>\n          <li>GBN：W_T ≤ 2^n − 1</li>\n          <li>SR：W_T, W_R ≤ 2^(n-1)</li>\n        </ul>\n      </div>\n    </div>"}, {"title": "介质访问控制", "content": "<p class=\"kicker\">03 · MAC</p>\n    <h2 class=\"h2\">静态 vs 动态：怎么共享一根线。</h2>\n    <div class=\"grid g2 mt-l\" style=\"align-items:start\">\n      <div>\n        <h4>分类</h4>\n        <ul class=\"dim mt-s\" style=\"font-size:13.5px;line-height:1.85\">\n          <li><b>静态划分</b>：FDM、TDM、WDM、CDM</li>\n          <li><b>动态-随机</b>：ALOHA、CSMA、CSMA/CD、CSMA/CA</li>\n          <li><b>动态-轮询</b>：令牌环、令牌总线</li>\n        </ul>\n        <h4 class=\"mt-l\">ALOHA</h4>\n        <p class=\"dim mt-s\" style=\"font-size:13px\">纯 ALOHA：想发就发，冲突后随机退避。利用率最高 18.4%。<br>分槽 ALOHA：只在固定时隙发，利用率 36.8%。</p>\n        <h4 class=\"mt-l\">CSMA</h4>\n        <ul class=\"dim mt-s\" style=\"font-size:13px;line-height:1.85\">\n          <li>1-坚持：监听到忙就一直等到空闲</li>\n          <li>非坚持：忙则等随机时长再听</li>\n          <li>p-坚持：空闲时以概率 p 发</li>\n        </ul>\n      </div>\n      <div>\n        <h4>CSMA/CD 五步</h4>\n        <ol class=\"dim mt-s\" style=\"font-size:13px;line-height:1.85\">\n          <li>先听后发：信道空闲才发</li>\n          <li>边发边听：检测冲突</li>\n          <li>检测到冲突 → 立刻发干扰信号 32-48 bit</li>\n          <li>等待二进制指数退避 r·51.2μs，r ∈ [0, 2^k − 1]，k = min(尝试次数, 10)</li>\n          <li>16 次都冲突 → 放弃，报错</li>\n        </ol>\n        <h4 class=\"mt-l\">CSMA/CA（无线）</h4>\n        <ul class=\"dim mt-s\" style=\"font-size:13px;line-height:1.85\">\n          <li>无线半双工，无法边发边听 → 避免冲突</li>\n          <li>发帧前等 DIFS + 随机退避</li>\n          <li>接收方收到后等 SIFS 发 ACK</li>\n          <li>RTS / CTS 解决<b>隐藏终端</b>问题</li>\n        </ul>\n      </div>\n    </div>"}, {"title": "以太网 + MAC", "content": "<p class=\"kicker\">04 · 局域网</p>\n    <h2 class=\"h2\">以太网帧 + MAC 地址 + 最小帧规则。</h2>\n    <div class=\"grid g2 mt-l\" style=\"align-items:start\">\n      <div>\n        <h4>以太网帧格式（DIX V2）</h4>\n        <div class=\"packet mt-s\">\n          <div><b>Preamble</b>7B</div>\n          <div><b>SFD</b>1B</div>\n          <div><b>DST</b>6B</div>\n          <div><b>SRC</b>6B</div>\n          <div><b>Type</b>2B</div>\n          <div><b>Data</b>46-1500B</div>\n          <div><b>FCS</b>4B</div>\n        </div>\n        <ul class=\"dim mt-s\" style=\"font-size:13px;line-height:1.85\">\n          <li>最小帧 = 64 B（不含前导码），用于检测冲突窗口</li>\n          <li>最大帧 = 1518 B（数据 1500）</li>\n          <li>少于 46 B 数据 → 填充</li>\n          <li>FCS 用 CRC-32</li>\n        </ul>\n        <h4 class=\"mt-l\">为什么 64 B？</h4>\n        <p class=\"dim mt-s\" style=\"font-size:13px\">10 Mbps 以太网：双向传播延迟 51.2μs → 512 bit = 64 B。<br>发送时间 ≥ 2×τ 才能\"听到\"冲突。</p>\n      </div>\n      <div>\n        <h4>MAC 地址（48 bit）</h4>\n        <pre class=\"code-block\" style=\"font-size:12px\">\n0A:1B:2C:3D:4E:5F\n└── 前 3 字节 OUI ── 厂商分配\n    后 3 字节 ── 厂商内部唯一\n最低字节最低 2 位：\n  bit 0: 单播 0 / 多播 1\n  bit 1: 全球 0 / 本地 1\n特殊：\n  FF:FF:FF:FF:FF:FF  广播\n  01:00:5E:xx:xx:xx  多播\n  IPv6 多播: 33:33:xx:xx:xx:xx</pre>\n        <h4 class=\"mt-l\">以太网速率</h4>\n        <ul class=\"dim mt-s\" style=\"font-size:13px;line-height:1.85\">\n          <li>10BASE-T：10 Mbps 双绞线</li>\n          <li>100BASE-TX：100 Mbps</li>\n          <li>1000BASE-T：千兆</li>\n          <li>10GBASE-T：万兆</li>\n        </ul>\n      </div>\n    </div>"}, {"title": "交换机 / VLAN", "content": "<p class=\"kicker\">04 · 局域网设备</p>\n    <h2 class=\"h2\">交换机的自学习 + VLAN 隔离。</h2>\n    <div class=\"grid g2 mt-l\" style=\"align-items:start\">\n      <div>\n        <h4>交换机 vs 集线器</h4>\n        <table class=\"cmp-table mt-s\">\n          <tr><th></th><th>集线器</th><th>交换机</th></tr>\n          <tr><td>层次</td><td>物理</td><td>链路</td></tr>\n          <tr><td>转发</td><td>广播</td><td>按 MAC 表精确</td></tr>\n          <tr><td>冲突域</td><td>所有端口共一个</td><td>每端口独立</td></tr>\n          <tr><td>广播域</td><td>所有端口共一个</td><td>所有端口共一个</td></tr>\n          <tr><td>带宽</td><td>共享</td><td>独享</td></tr>\n        </table>\n        <h4 class=\"mt-l\">交换机自学习</h4>\n        <ol class=\"dim mt-s\" style=\"font-size:13px;line-height:1.85\">\n          <li>收到帧 → 记录\"源 MAC → 该端口\"到 MAC 表（含 TTL）</li>\n          <li>查目的 MAC → 表中有 → 仅向该端口转发</li>\n          <li>表中无 → 向除来源外所有端口<b>泛洪</b></li>\n          <li>表项过期自动删除</li>\n        </ol>\n      </div>\n      <div>\n        <h4>VLAN 虚拟局域网</h4>\n        <p class=\"dim mt-s\" style=\"font-size:13.5px\">把一台物理交换机划分成多个<b>逻辑广播域</b>。同 VLAN 才能直接通信，跨 VLAN 必须经过三层设备（路由器或三层交换机）。</p>\n        <h4 class=\"mt-m\">802.1Q VLAN Tag (4B)</h4>\n        <pre class=\"code-block\" style=\"font-size:12px\">\nDST | SRC | <b>802.1Q Tag</b> | Type | Data | FCS\nTag (4B):\n  TPID 16b = 0x8100   <span class=\"c\">// 标识为 VLAN 帧</span>\n  PRI  3b              <span class=\"c\">// 优先级 0-7</span>\n  CFI  1b\n  VID  12b             <span class=\"c\">// VLAN ID 0-4095</span></pre>\n        <h4 class=\"mt-m\">STP 生成树</h4>\n        <p class=\"dim mt-s\" style=\"font-size:13px\">交换机之间若有冗余链路会形成环，广播帧无限循环。STP 通过选根 / 阻塞冗余端口构造无环生成树。</p>\n      </div>\n    </div>"}, {"title": "无线 802.11", "content": "<p class=\"kicker\">04 · WLAN</p>\n    <h2 class=\"h2\">隐藏终端 + RTS/CTS。</h2>\n    <div class=\"grid g2 mt-l\" style=\"align-items:start\">\n      <div>\n        <h4>802.11 体系</h4>\n        <ul class=\"dim mt-s\" style=\"font-size:13.5px;line-height:1.85\">\n          <li><b>基础设施模式</b>：站点通过 AP 通信</li>\n          <li><b>Ad-hoc 模式</b>：站点直接通信</li>\n          <li>SSID = 网络名称</li>\n          <li>BSS = 基本服务集（一个 AP 覆盖）</li>\n          <li>ESS = 扩展服务集（多个 BSS）</li>\n        </ul>\n        <h4 class=\"mt-l\">隐藏终端问题</h4>\n        <p class=\"dim mt-s\" style=\"font-size:13px\">A、C 在 B 的覆盖内，但 A、C 之间被障碍隔开。A、C 同时发，都在 B 处冲突，自己却\"听不见\"对方 → CSMA 失效。</p>\n        <p class=\"dim mt-s\" style=\"font-size:13px\"><b>暴露终端</b>：A 听到 B 在发，于是不发，但其实自己的目标方向是 D，本可同时进行。</p>\n      </div>\n      <div>\n        <h4>RTS / CTS 解决</h4>\n        <div class=\"viz mt-s\" style=\"font-size:12px\">\nA 想发给 B:\n  A → RTS → B\n  B → CTS → 所有听见的（含 C）\nC 收到 CTS → 在 NAV 期间禁声\nA 安心发数据\nB 收完 → 发 ACK\nNAV 网络分配向量 = 虚拟载波监听</div>\n        <h4 class=\"mt-m\">802.11 帧结构</h4>\n        <p class=\"dim mt-s\" style=\"font-size:13px\">含 4 个地址字段（源 / 目 / 发送 AP / 接收 AP）。<br>序号字段用于排重。</p>\n        <h4 class=\"mt-m\">主要版本</h4>\n        <p class=\"dim mt-s\" style=\"font-size:13px\">a/b/g/n/ac/ax；速率从 11 Mbps → 9.6 Gbps（Wi-Fi 6）。</p>\n      </div>\n    </div>"}, {"title": "IP 数据报", "content": "<p class=\"kicker\">05 · 网络层</p>\n    <h2 class=\"h2\">IPv4 首部 + 分片重组算例。</h2>\n    <div class=\"grid g2 mt-l\" style=\"align-items:start\">\n      <div>\n        <h4>首部 20 ~ 60 字节</h4>\n        <div class=\"packet mt-s\" style=\"flex-direction:column\">\n          <div style=\"display:flex\"><div><b>Ver</b>4b</div><div><b>IHL</b>4b</div><div><b>TOS</b>8b</div><div><b>Total Length</b>16b</div></div>\n          <div style=\"display:flex\"><div><b>Identifier</b>16b</div><div><b>Flag</b>3b</div><div><b>Frag Offset</b>13b</div></div>\n          <div style=\"display:flex\"><div><b>TTL</b>8b</div><div><b>Protocol</b>8b</div><div><b>Header Checksum</b>16b</div></div>\n          <div style=\"display:flex\"><div style=\"flex:2\"><b>Source IP</b> 32b</div></div>\n          <div style=\"display:flex\"><div style=\"flex:2\"><b>Destination IP</b> 32b</div></div>\n          <div style=\"display:flex\"><div><b>Options + Padding</b></div></div>\n        </div>\n        <ul class=\"dim mt-s\" style=\"font-size:13px;line-height:1.85\">\n          <li><b>IHL</b>：首部长度，单位 4 字节</li>\n          <li><b>TTL</b>：每经过一跳 -1；为 0 丢弃 + 发 ICMP</li>\n          <li><b>Proto</b>：TCP=6 / UDP=17 / ICMP=1 / OSPF=89</li>\n          <li><b>Flag</b>：DF 不分片 / MF 还有更多分片</li>\n        </ul>\n      </div>\n      <div>\n        <h4>分片完整例</h4>\n        <p class=\"dim mt-s\" style=\"font-size:13.5px\">原 IP 数据报：3800 B 数据 + 20 B 首部；途经 MTU = 1500 的链路。</p>\n        <pre class=\"code-block\" style=\"font-size:12px\">\n最大数据 / 片 = (1500 − 20) = 1480 B\n分片偏移单位 = 8 B → 1480/8 = 185\n3800 → 三片：\n  片1: 1480 B  offset=0   MF=1\n  片2: 1480 B  offset=185 MF=1\n  片3:  840 B  offset=370 MF=0\n每片都有完整 20 B 首部\nIdentifier 相同; Total Length 各异</pre>\n        <p class=\"dim mt-s\" style=\"font-size:13px\">重组由<b>目的主机</b>完成，路由器不重组。<br>设置定时器：超时 → 丢弃整个数据报。</p>\n      </div>\n    </div>"}, {"title": "IP 地址分类", "content": "<p class=\"kicker\">05 · IP 地址</p>\n    <h2 class=\"h2\">A B C D 五类 + 特殊地址。</h2>\n    <div class=\"grid g2 mt-l\" style=\"align-items:start\">\n      <div>\n        <h4>分类地址（旧）</h4>\n        <table class=\"cmp-table mt-s\">\n          <tr><th>类</th><th>首位</th><th>网络号</th><th>范围</th><th>主机数</th></tr>\n          <tr><td>A</td><td>0</td><td>8 位</td><td>1-126</td><td>2²⁴-2</td></tr>\n          <tr><td>B</td><td>10</td><td>16 位</td><td>128-191</td><td>2¹⁶-2</td></tr>\n          <tr><td>C</td><td>110</td><td>24 位</td><td>192-223</td><td>2⁸-2</td></tr>\n          <tr><td>D</td><td>1110</td><td>—</td><td>224-239</td><td>多播</td></tr>\n          <tr><td>E</td><td>1111</td><td>—</td><td>240-247</td><td>保留</td></tr>\n        </table>\n        <p class=\"dim mt-s\" style=\"font-size:13px\">主机数 −2：去掉<b>网络号</b>本身（全 0）和<b>广播地址</b>（全 1）。</p>\n      </div>\n      <div>\n        <h4>特殊地址</h4>\n        <table class=\"cmp-table mt-s\">\n          <tr><th>地址</th><th>含义</th></tr>\n          <tr><td>0.0.0.0</td><td>本网络上的本主机（初始 DHCP）</td></tr>\n          <tr><td>0.0.0.0/0</td><td>默认路由</td></tr>\n          <tr><td>255.255.255.255</td><td>本网广播（路由器不转发）</td></tr>\n          <tr><td>net.255.255.255</td><td>定向广播（指定网络的所有主机）</td></tr>\n          <tr><td>127.0.0.0/8</td><td>本机环回</td></tr>\n          <tr><td>169.254/16</td><td>APIPA 链路本地</td></tr>\n        </table>\n        <h4 class=\"mt-l\">私有地址（不路由到公网）</h4>\n        <ul class=\"dim mt-s\" style=\"font-size:13px;line-height:1.85\">\n          <li>A 类：10.0.0.0/8</li>\n          <li>B 类：172.16.0.0/12</li>\n          <li>C 类：192.168.0.0/16</li>\n        </ul>\n      </div>\n    </div>"}, {"title": "子网划分", "content": "<p class=\"kicker\">05 · 子网</p>\n    <h2 class=\"h2\">借主机位做子网号。</h2>\n    <div class=\"grid g2 mt-l\" style=\"align-items:start\">\n      <div>\n        <h4>步骤</h4>\n        <ol class=\"dim mt-s\" style=\"font-size:13.5px;line-height:1.85\">\n          <li>确定子网数 N，借 ⌈log₂N⌉ 位</li>\n          <li>新掩码 = 旧掩码长度 + 借位</li>\n          <li>每子网主机数 = 2^(剩余主机位) − 2</li>\n          <li>第 i 个子网起点：网络号 | (i ≪ 主机位)</li>\n        </ol>\n        <h4 class=\"mt-l\">完整算例</h4>\n        <pre class=\"code-block\" style=\"font-size:12px\">\n原: 192.168.10.0/24 (C 类)\n要划分 6 个子网\n需借 ⌈log₂6⌉ = 3 位\n新掩码: /27 = 255.255.255.224\n每子网容主机 = 2⁵ − 2 = 30\n子网 0: 192.168.10.0   范围 .0 – .31\n        广播 .31, 可用 .1–.30\n子网 1: 192.168.10.32  .32–.63\n子网 2: 192.168.10.64\n子网 3: 192.168.10.96\n子网 4: 192.168.10.128\n子网 5: 192.168.10.160\n(可用 6 个, 实际划出 8 个)</pre>\n      </div>\n      <div>\n        <h4>VLSM 变长掩码</h4>\n        <p class=\"dim mt-s\" style=\"font-size:13.5px\">不同子网用不同长度掩码，按需分配。例：A 部门要 60 主机 → /26；B 部门要 30 → /27；C 部门要 14 → /28。</p>\n        <h4 class=\"mt-l\">某 IP 的子网判定</h4>\n        <p class=\"dim mt-s\" style=\"font-size:13.5px\">IP 与掩码<b>按位与</b> → 子网号。</p>\n        <pre class=\"code-block\" style=\"font-size:12px\">\nIP    = 192.168.10.130\nMask  = 255.255.255.192  (/26)\nAND   = 192.168.10.128   子网号\n子网范围: .128 – .191\n广播: .191\n可用主机: .129 – .190\n共 62 台</pre>\n        <h4 class=\"mt-m\">超网 / CIDR</h4>\n        <p class=\"dim mt-s\" style=\"font-size:13px\">把多个连续 C 类合并：192.168.0.0/22 = 4 个 C → 一条路由项。<br>路由聚合 → 减少路由表大小。</p>\n      </div>\n    </div>"}, {"title": "路由表查找", "content": "<p class=\"kicker\">05 · 转发</p>\n    <h2 class=\"h2\">最长前缀匹配。</h2>\n    <div class=\"grid g2 mt-l\" style=\"align-items:start\">\n      <div>\n        <h4>路由表项</h4>\n        <table class=\"cmp-table mt-s\">\n          <tr><th>目的网络</th><th>掩码</th><th>下一跳</th></tr>\n          <tr><td>0.0.0.0</td><td>0.0.0.0</td><td>R1 (默认)</td></tr>\n          <tr><td>192.168.0.0</td><td>255.255.0.0</td><td>R2</td></tr>\n          <tr><td>192.168.1.0</td><td>255.255.255.0</td><td>R3</td></tr>\n          <tr><td>192.168.1.128</td><td>255.255.255.192</td><td>R4</td></tr>\n        </table>\n        <h4 class=\"mt-l\">查找过程</h4>\n        <p class=\"dim mt-s\" style=\"font-size:13px\">收到 IP = 192.168.1.150：</p>\n        <ul class=\"dim mt-s\" style=\"font-size:13px;line-height:1.85\">\n          <li>与 /16 与 → 192.168.0.0 ✓</li>\n          <li>与 /24 与 → 192.168.1.0 ✓</li>\n          <li>与 /26 与 → 192.168.1.128 ✓</li>\n          <li>三项都匹配 → 取<b>最长 /26</b> → R4</li>\n        </ul>\n      </div>\n      <div>\n        <h4>路由器转发流程</h4>\n        <ol class=\"dim mt-s\" style=\"font-size:13px;line-height:1.85\">\n          <li>接收到数据报，验证 IP 首部校验和</li>\n          <li>TTL -= 1；若为 0 → 丢弃 + 发 ICMP 超时</li>\n          <li>查路由表（最长前缀匹配）</li>\n          <li>用 ARP 获取下一跳 MAC</li>\n          <li>重新封装链路层帧</li>\n          <li>从出口转发</li>\n        </ol>\n        <h4 class=\"mt-l\">直连 / 远端</h4>\n        <p class=\"dim mt-s\" style=\"font-size:13px\">同子网的目的 → 直接 ARP 拿对方 MAC；不同子网 → ARP 拿网关 MAC，由网关转发。</p>\n        <h4 class=\"mt-m\">默认路由</h4>\n        <p class=\"dim mt-s\" style=\"font-size:13px\">0.0.0.0/0 表示\"匹配所有\"。当无具体路由时使用。</p>\n      </div>\n    </div>"}, {"title": "NAT + IPv6", "content": "<p class=\"kicker\">05 · 地址扩展</p>\n    <h2 class=\"h2\">从地址不够用到新的 128 位时代。</h2>\n    <div class=\"grid g2 mt-l\" style=\"align-items:start\">\n      <div>\n        <h4>NAT 网络地址转换</h4>\n        <p class=\"dim mt-s\" style=\"font-size:13.5px\">出口路由器把\"私网 IP + 端口\"映射到\"公网 IP + 不同端口\"，记录在 NAT 表中。</p>\n        <div class=\"viz mt-s\" style=\"font-size:12px\">\n内: 192.168.1.5:5000 → 8.8.8.8:80\n出: 公网IP:38001     → 8.8.8.8:80\nNAT 表:\n  192.168.1.5:5000 ↔ 38001\n  192.168.1.6:4000 ↔ 38002\n回包: 8.8.8.8:80 → 公网IP:38001\nNAT 查表 → 改为 192.168.1.5:5000</div>\n        <p class=\"dim mt-s\" style=\"font-size:13px\">优点：解决 IPv4 不够用；缺点：破坏端到端，P2P 难穿透。</p>\n      </div>\n      <div>\n        <h4>IPv6 关键改进</h4>\n        <ul class=\"dim mt-s\" style=\"font-size:13.5px;line-height:1.85\">\n          <li>地址 32 → 128 位 → 2¹²⁸ 个地址</li>\n          <li>固定 40 B 首部（去掉校验和、IHL）</li>\n          <li>无需 NAT、无需分片（由源做\"路径 MTU 发现\"）</li>\n          <li>支持地址自动配置 SLAAC</li>\n          <li>更好支持流标记 / QoS</li>\n        </ul>\n        <h4 class=\"mt-l\">IPv6 地址表示</h4>\n        <pre class=\"code-block\" style=\"font-size:12px\">\n2001:0DB8:0000:0000:0000:FF00:0042:8329\n简化:\n  连续 0 段用 :: 一次\n  → 2001:DB8::FF00:42:8329\n特殊:\n  ::1 / 128       本机环回\n  ::/0            默认路由\n  FE80::/10       链路本地\n  FF00::/8        多播\n  2000::/3        全球单播</pre>\n      </div>\n    </div>"}, {"title": "路由协议", "content": "<p class=\"kicker\">06 · 路由协议</p>\n    <h2 class=\"h2\">RIP / OSPF / BGP — 内 / 外网关。</h2>\n    <div class=\"grid g2 mt-l\" style=\"align-items:start\">\n      <div>\n        <table class=\"cmp-table mt-s\">\n          <tr><th></th><th>RIP</th><th>OSPF</th><th>BGP</th></tr>\n          <tr><td>算法</td><td>距离向量</td><td>链路状态</td><td>路径向量</td></tr>\n          <tr><td>度量</td><td>跳数 ≤ 15</td><td>带宽 cost</td><td>策略</td></tr>\n          <tr><td>范围</td><td>小型内网</td><td>大型 AS 内</td><td>AS 之间</td></tr>\n          <tr><td>更新方式</td><td>30s 全表</td><td>有变化才发</td><td>有变化才发</td></tr>\n          <tr><td>消息</td><td>UDP 520</td><td>IP 89</td><td>TCP 179</td></tr>\n        </table>\n        <h4 class=\"mt-l\">RIP 局限</h4>\n        <p class=\"dim mt-s\" style=\"font-size:13px\">最大跳数 15 → 16 不可达。<b>\"计数到无穷\"</b>问题（环路时跳数无限增大）。<br>解决：水平分割、毒性反转、抑制定时器。</p>\n      </div>\n      <div>\n        <h4>OSPF 工作流程</h4>\n        <ol class=\"dim mt-s\" style=\"font-size:13px;line-height:1.85\">\n          <li>HELLO 报文发现邻居</li>\n          <li>建立邻居关系，同步 LSDB（链路状态数据库）</li>\n          <li>每个路由器对 LSDB 用 Dijkstra 算最短路径树</li>\n          <li>用变更 LSA 增量更新</li>\n        </ol>\n        <p class=\"dim mt-s\" style=\"font-size:13px\">支持多区域划分（area 0 是骨干），减少 LSA 范围。</p>\n        <h4 class=\"mt-l\">BGP 特点</h4>\n        <ul class=\"dim mt-s\" style=\"font-size:13px;line-height:1.85\">\n          <li>承载 AS_PATH（经过的 AS 序列）</li>\n          <li>路由选择基于<b>策略</b>而非最短</li>\n          <li>邻居关系建立在 TCP 之上</li>\n          <li>分 iBGP（同 AS 内）和 eBGP（跨 AS）</li>\n        </ul>\n      </div>\n    </div>"}, {"title": "ARP / ICMP / DHCP", "content": "<p class=\"kicker\">06 · 网络层辅助</p>\n    <h2 class=\"h2\">解析 · 报告 · 动态分配。</h2>\n    <div class=\"grid g3 mt-l\">\n      <div class=\"card card-accent\">\n        <h4>ARP 地址解析</h4>\n        <p class=\"dim mt-s\" style=\"font-size:13px\">解决\"IP → MAC\"映射。</p>\n        <ol class=\"dim mt-s\" style=\"font-size:12.5px;line-height:1.85\">\n          <li>广播 ARP Request（含目标 IP）</li>\n          <li>目标主机单播 ARP Reply（含 MAC）</li>\n          <li>双方更新 ARP 缓存</li>\n        </ol>\n        <p class=\"dim mt-s\" style=\"font-size:12px\"><b>免费 ARP</b>：广播自己的 IP/MAC，检测 IP 冲突。</p>\n        <p class=\"dim mt-s\" style=\"font-size:12px\"><b>RARP</b>：反向 ARP，由 MAC 求 IP（早期无盘工作站）。</p>\n      </div>\n      <div class=\"card card-accent\">\n        <h4>ICMP</h4>\n        <p class=\"dim mt-s\" style=\"font-size:13px\">报告错误 / 查询。</p>\n        <ul class=\"dim mt-s\" style=\"font-size:12.5px;line-height:1.85\">\n          <li>差错：终点不可达、超时、参数错</li>\n          <li>查询：回送请求 / 应答（ping）</li>\n          <li>traceroute = 故意发 TTL=1/2/3 → 收 ICMP 超时</li>\n        </ul>\n        <p class=\"dim mt-s\" style=\"font-size:12px\">不会发对：广播包、ICMP 差错本身、片偏移非 0 的片。</p>\n      </div>\n      <div class=\"card card-accent\">\n        <h4>DHCP</h4>\n        <p class=\"dim mt-s\" style=\"font-size:13px\">动态分配 IP + 网关 + DNS。</p>\n        <ol class=\"dim mt-s\" style=\"font-size:12.5px;line-height:1.85\">\n          <li>Discover（广播）</li>\n          <li>Offer（服务器单播 / 广播）</li>\n          <li>Request（客户确认）</li>\n          <li>Ack（服务器确认）</li>\n        </ol>\n        <p class=\"dim mt-s\" style=\"font-size:12px\">基于 UDP；客户 68，服务器 67。<br>租约到期前 1/2 / 7/8 续约。</p>\n      </div>\n    </div>\n    <div class=\"card mt-l\">\n      <h4>三者层次</h4>\n      <p class=\"dim mt-s\" style=\"font-size:13.5px\">ARP / ICMP 在<b>网络层</b>（ARP 帧的 Type=0x0806，ICMP 协议号 1）；DHCP 在<b>应用层</b>（基于 UDP）。<br>易错：ARP 不是链路层。</p>\n    </div>"}, {"title": "UDP 详细", "content": "<p class=\"kicker\">07 · 传输层</p>\n    <h2 class=\"h2\">明信片协议：尽力交付，简单高效。</h2>\n    <div class=\"grid g2 mt-l\" style=\"align-items:start\">\n      <div>\n        <h4>UDP 首部（8 字节）</h4>\n        <div class=\"packet mt-s\" style=\"flex-direction:column\">\n          <div style=\"display:flex\"><div><b>Source Port</b>16b</div><div><b>Dest Port</b>16b</div></div>\n          <div style=\"display:flex\"><div><b>Length</b>16b</div><div><b>Checksum</b>16b</div></div>\n        </div>\n        <ul class=\"dim mt-s\" style=\"font-size:13px;line-height:1.85\">\n          <li>Length：UDP 首部 + 数据总长</li>\n          <li>Checksum 覆盖<b>伪首部 + 首部 + 数据</b></li>\n          <li>无连接，无序，无重传，无流量 / 拥塞控制</li>\n          <li>面向报文：应用一次写多大就发多大</li>\n        </ul>\n      </div>\n      <div>\n        <h4>UDP 伪首部</h4>\n        <pre class=\"code-block\" style=\"font-size:12.5px\">\n源 IP (4B) | 目的 IP (4B)\n0 (1B) | 协议=17 (1B) | UDP 长度 (2B)\n+ UDP 首部 + 数据\n计算校验和时拼上, 发送时不实际传\n作用: 检测 IP 是否传错收件人</pre>\n        <h4 class=\"mt-l\">用途</h4>\n        <ul class=\"dim mt-s\" style=\"font-size:13px;line-height:1.85\">\n          <li>DNS（53 端口）</li>\n          <li>DHCP（67/68）</li>\n          <li>TFTP（69）</li>\n          <li>SNMP（161）</li>\n          <li>视频会议 / 实时游戏</li>\n          <li>RIP（520）</li>\n        </ul>\n        <h4 class=\"mt-m\">复用 / 分用</h4>\n        <p class=\"dim mt-s\" style=\"font-size:13px\">复用：多进程共享一个 UDP/IP 出去；分用：靠 (协议, 端口) 派发到对应进程。</p>\n      </div>\n    </div>"}, {"title": "TCP 首部", "content": "<p class=\"kicker\">07 · TCP</p>\n    <h2 class=\"h2\">挂号信协议：可靠、有序、字节流。</h2>\n    <div class=\"grid g2 mt-l\" style=\"align-items:start\">\n      <div>\n        <h4>TCP 首部（最少 20B）</h4>\n        <div class=\"packet mt-s\" style=\"flex-direction:column;font-size:11px\">\n          <div style=\"display:flex\"><div><b>Source Port</b>16b</div><div><b>Dest Port</b>16b</div></div>\n          <div style=\"display:flex\"><div><b>Seq Number</b>32b</div></div>\n          <div style=\"display:flex\"><div><b>Ack Number</b>32b</div></div>\n          <div style=\"display:flex\"><div><b>HL</b>4b</div><div><b>Rsv</b>6b</div><div><b>Flags</b>6b<br>U A P R S F</div><div><b>Window</b>16b</div></div>\n          <div style=\"display:flex\"><div><b>Checksum</b>16b</div><div><b>Urg Ptr</b>16b</div></div>\n          <div style=\"display:flex\"><div><b>Options + Padding</b></div></div>\n        </div>\n      </div>\n      <div>\n        <h4>关键字段</h4>\n        <ul class=\"dim mt-s\" style=\"font-size:13px;line-height:1.85\">\n          <li><b>Seq</b>：本段第一字节在数据流中的序号</li>\n          <li><b>Ack</b>：期望收到对方下一字节的序号（累计 ACK）</li>\n          <li><b>Window</b>：本端剩余可接收字节数 → 流量控制</li>\n          <li><b>Urg Ptr</b>：紧急数据末尾的偏移（与 URG 标志一起用）</li>\n        </ul>\n        <h4 class=\"mt-l\">6 个标志位</h4>\n        <table class=\"cmp-table mt-s\">\n          <tr><th>位</th><th>意义</th></tr>\n          <tr><td>URG</td><td>紧急数据上交</td></tr>\n          <tr><td>ACK</td><td>Ack Number 字段有效</td></tr>\n          <tr><td>PSH</td><td>立即上交应用</td></tr>\n          <tr><td>RST</td><td>异常 → 复位连接</td></tr>\n          <tr><td>SYN</td><td>建立连接请求</td></tr>\n          <tr><td>FIN</td><td>终止连接</td></tr>\n        </table>\n      </div>\n    </div>"}, {"title": "握手 / 挥手", "content": "<p class=\"kicker\">08 · 连接</p>\n    <h2 class=\"h2\">为什么三次？为什么四次？</h2>\n    <div class=\"grid g2 mt-l\" style=\"align-items:start\">\n      <div>\n        <h4>三次握手</h4>\n        <div class=\"flow mt-s\">\n          <div class=\"lhs\">Client</div><div class=\"arr\">SYN <small>seq=x</small> →</div><div class=\"rhs\">Server</div>\n          <div class=\"lhs\">SYN_SENT</div><div class=\"arr\">← SYN+ACK <small>seq=y, ack=x+1</small></div><div class=\"rhs\">SYN_RCVD</div>\n          <div class=\"lhs\">ESTABLISHED</div><div class=\"arr\">ACK <small>seq=x+1, ack=y+1</small> →</div><div class=\"rhs\">ESTABLISHED</div>\n        </div>\n        <p class=\"dim mt-m\" style=\"font-size:13.5px\"><b>为什么三次？</b></p>\n        <ul class=\"dim mt-s\" style=\"font-size:12.5px;line-height:1.85\">\n          <li>双方确认彼此发送 / 接收能力</li>\n          <li>防止历史延迟的 SYN 报文导致服务端建立\"假连接\"浪费资源</li>\n        </ul>\n        <p class=\"dim mt-s\" style=\"font-size:13px\"><b>SYN 攻击</b>：发大量 SYN 不完成握手，耗光服务器资源。<br>解决：SYN Cookie。</p>\n      </div>\n      <div>\n        <h4>四次挥手</h4>\n        <div class=\"flow mt-s\">\n          <div class=\"lhs\">主动方</div><div class=\"arr\">FIN <small>seq=u</small> →</div><div class=\"rhs\">被动方</div>\n          <div class=\"lhs\">FIN_WAIT_1</div><div class=\"arr\">← ACK <small>ack=u+1</small></div><div class=\"rhs\">CLOSE_WAIT</div>\n          <div class=\"lhs\">FIN_WAIT_2</div><div class=\"arr\">← FIN <small>seq=v</small></div><div class=\"rhs\">LAST_ACK</div>\n          <div class=\"lhs\">TIME_WAIT</div><div class=\"arr\">ACK <small>ack=v+1</small> →</div><div class=\"rhs\">CLOSED</div>\n        </div>\n        <p class=\"dim mt-m\" style=\"font-size:13.5px\"><b>为什么四次？</b>TCP 全双工，每方关一个方向（自己发完 FIN）。中间被动方可能还有数据要传，所以 FIN/ACK 分两组。</p>\n        <h4 class=\"mt-l\">TIME_WAIT 2MSL</h4>\n        <ul class=\"dim mt-s\" style=\"font-size:12.5px;line-height:1.85\">\n          <li>等待网络中残留报文消失，避免影响下一连接</li>\n          <li>保证对端收到最后的 ACK（若丢失可重发）</li>\n          <li>MSL 通常 30s-2min</li>\n        </ul>\n      </div>\n    </div>"}, {"title": "TCP 状态机", "content": "<p class=\"kicker\">08 · 11 个状态</p>\n    <h2 class=\"h2\">从 CLOSED 到 ESTABLISHED 到 CLOSED。</h2>\n    <div class=\"grid g2 mt-l\" style=\"align-items:start\">\n      <div>\n        <h4>11 个状态</h4>\n        <ul class=\"dim mt-s\" style=\"font-size:13px;line-height:1.85\">\n          <li><b>CLOSED</b>：初始状态</li>\n          <li><b>LISTEN</b>：服务器等待连接</li>\n          <li><b>SYN_SENT</b>：客户已发 SYN，等待回应</li>\n          <li><b>SYN_RCVD</b>：服务器已发 SYN+ACK</li>\n          <li><b>ESTABLISHED</b>：连接已建立</li>\n          <li><b>FIN_WAIT_1</b>：发出 FIN，等 ACK</li>\n          <li><b>FIN_WAIT_2</b>：收到 ACK，等对方 FIN</li>\n          <li><b>CLOSE_WAIT</b>：被动方收到 FIN</li>\n          <li><b>LAST_ACK</b>：被动方发出 FIN，等最后 ACK</li>\n          <li><b>TIME_WAIT</b>：主动方等 2MSL</li>\n          <li><b>CLOSING</b>：双方同时关闭（少见）</li>\n        </ul>\n      </div>\n      <div>\n        <h4>典型转换路径</h4>\n        <div class=\"viz mt-s\" style=\"font-size:11.5px\">\n客户:\nCLOSED → SYN_SENT → ESTABLISHED → FIN_WAIT_1\n       → FIN_WAIT_2 → TIME_WAIT → CLOSED\n服务器:\nCLOSED → LISTEN → SYN_RCVD → ESTABLISHED → CLOSE_WAIT\n       → LAST_ACK → CLOSED</div>\n        <h4 class=\"mt-l\">异常处理</h4>\n        <ul class=\"dim mt-s\" style=\"font-size:13px;line-height:1.85\">\n          <li><b>RST</b>：收到不属于任何连接的报文 / 异常 → 强行复位</li>\n          <li><b>保活定时器</b>：长时间无活动，发探测包；若多次无响应 → 断开</li>\n          <li><b>持续定时器</b>：rwnd=0 时探测对方是否更新窗口</li>\n        </ul>\n        <h4 class=\"mt-m\">netstat 看状态</h4>\n        <p class=\"dim mt-s\" style=\"font-size:13px\">`netstat -ant` 显示当前所有 TCP 连接状态；大量 TIME_WAIT 通常没问题，CLOSE_WAIT 多 → 应用层没正确 close()。</p>\n      </div>\n    </div>"}, {"title": "流量控制", "content": "<p class=\"kicker\">09 · 流量控制</p>\n    <h2 class=\"h2\">滑动窗口 + 0 窗口探测。</h2>\n    <div class=\"grid g2 mt-l\" style=\"align-items:start\">\n      <div>\n        <h4>原理</h4>\n        <p class=\"dim mt-s\" style=\"font-size:13.5px\">接收方在 ACK 中通告 rwnd（剩余空间），发送方维护\"发送窗口 ≤ rwnd\"，发完就等 ACK。</p>\n        <div class=\"viz mt-s\" style=\"font-size:12px\">\n发送窗口 (假设 W=4)\n[ack已确认] [发了未ack] [可发未发] [不允发]\n随 ACK 到达, 窗口右移\n若 rwnd 缩小, 窗口收缩</div>\n        <h4 class=\"mt-l\">0 窗口死锁</h4>\n        <p class=\"dim mt-s\" style=\"font-size:13px\">接收方通告 rwnd=0 后，再恢复时若那个 ACK 丢失 → 双方僵持。<br>解决：<b>持续计时器</b>，发送方每隔一段时间发 1 字节探测包，强制接收方重新通告 rwnd。</p>\n      </div>\n      <div>\n        <h4>糊涂窗口综合症</h4>\n        <p class=\"dim mt-s\" style=\"font-size:13.5px\">问题：接收方刚腾出一点空间就通告小 rwnd → 发送方发小包 → 效率低。</p>\n        <p class=\"dim mt-s\" style=\"font-size:13px\">解决：</p>\n        <ul class=\"dim mt-s\" style=\"font-size:13px;line-height:1.85\">\n          <li>接收方：等 rwnd ≥ MSS 或缓冲半空再通告</li>\n          <li>发送方：<b>Nagle</b> 算法 —— 攒够 MSS 或收到对方 ACK 再发</li>\n        </ul>\n        <h4 class=\"mt-l\">实际窗口</h4>\n        <p class=\"mono mt-s\" style=\"font-size:14px;background:var(--surface-2);padding:12px;border-radius:8px\">\n          发送窗口 swnd = min(cwnd, rwnd)<br>\n          <span class=\"dim\">// 流量 vs 拥塞，取小者</span>\n        </p>\n        <p class=\"dim mt-s\" style=\"font-size:13px\">流量控制保护<b>接收方</b>不被淹没；拥塞控制保护<b>网络</b>不被淹没。</p>\n      </div>\n    </div>"}, {"title": "拥塞控制 4 算法", "content": "<p class=\"kicker\">09 · 拥塞</p>\n    <h2 class=\"h2\">慢开始 · 拥塞避免 · 快重传 · 快恢复。</h2>\n    <div class=\"grid g2 mt-l\" style=\"align-items:start\">\n      <div>\n        <h4>4 个算法配合</h4>\n        <ol class=\"dim mt-s\" style=\"font-size:13px;line-height:1.85\">\n          <li><b>慢开始</b>：cwnd = 1，每 RTT 翻倍（指数增）</li>\n          <li>cwnd ≥ ssthresh → 进入<b>拥塞避免</b>：每 RTT +1（线性增）</li>\n          <li>超时丢包 → ssthresh = cwnd / 2，cwnd = 1，回到慢开始</li>\n          <li>收到 3 个重复 ACK → <b>快重传</b>立即重发丢失段</li>\n          <li>同时 <b>快恢复</b>：ssthresh = cwnd / 2，cwnd = ssthresh，进入拥塞避免（不退到 1）</li>\n        </ol>\n        <h4 class=\"mt-l\">关键设定</h4>\n        <ul class=\"dim mt-s\" style=\"font-size:13px;line-height:1.85\">\n          <li>初始 ssthresh：通常 16 或 64 KB</li>\n          <li>cwnd 单位 = MSS</li>\n          <li>超时 RTO = RTT + 4 × DevRTT（Karn 算法估计）</li>\n        </ul>\n      </div>\n      <div>\n        <h4>cwnd 曲线</h4>\n        <div class=\"viz mt-s\" style=\"font-size:12px\">\ncwnd\n │                       ●超时\n │                      /│\n │              ●●●●  / ↓\n │            ●● ●●●●/ cwnd=1\n │          ●●  快重传 + 快恢复\n │     ssth ─── ┐\n │         ●●   │ ssth=cwnd/2\n │       ●●     │\n │     ●●       │\n │   ●●         │\n │ ●●     初始 ssthresh\n │●  慢开始 (×2)\n 0 ────────────────→ RTT</div>\n        <h4 class=\"mt-l\">TCP Reno vs Tahoe</h4>\n        <ul class=\"dim mt-s\" style=\"font-size:13px;line-height:1.85\">\n          <li><b>Tahoe</b>：任何丢失（超时或快重传）都回到 cwnd=1</li>\n          <li><b>Reno</b>：快重传 → 快恢复（cwnd=ssth），仅超时回 1</li>\n          <li><b>Cubic</b>（Linux 默认）：用三次函数缓慢增窗</li>\n          <li><b>BBR</b>（Google）：基于带宽时延，不再以丢包为信号</li>\n        </ul>\n      </div>\n    </div>"}, {"title": "DNS 解析", "content": "<p class=\"kicker\">10 · 应用层</p>\n    <h2 class=\"h2\">从域名到 IP，递归 + 迭代两次。</h2>\n    <div class=\"grid g2 mt-l\" style=\"align-items:start\">\n      <div>\n        <h4>层次结构</h4>\n        <pre class=\"code-block\" style=\"font-size:12px\">\n. (根)\n├── com\n│   ├── google\n│   │   ├── www\n│   │   └── mail\n│   └── microsoft\n├── cn\n│   └── edu\n│       └── tsinghua\n└── org\n完整域名 www.google.com.\n从右到左由大到小</pre>\n        <h4 class=\"mt-l\">常用记录类型</h4>\n        <ul class=\"dim mt-s\" style=\"font-size:13px;line-height:1.85\">\n          <li><b>A</b>：域名 → IPv4</li>\n          <li><b>AAAA</b>：域名 → IPv6</li>\n          <li><b>CNAME</b>：别名</li>\n          <li><b>MX</b>：邮件交换器</li>\n          <li><b>NS</b>：权威 DNS 服务器</li>\n          <li><b>PTR</b>：反向解析（IP → 域名）</li>\n        </ul>\n      </div>\n      <div>\n        <h4>解析过程</h4>\n        <pre class=\"code-block\" style=\"font-size:12px\">\n用户 → 本地 DNS (递归)\n       本地 DNS → 根 DNS (迭代)\n       根 → 返回 .com 服务器\n       本地 DNS → .com 服务器\n       → 返回 google.com 权威 NS\n       本地 DNS → google.com 权威\n       → 返回 IP\n返回过程沿原路返回, 缓存逐级</pre>\n        <h4 class=\"mt-l\">递归 vs 迭代</h4>\n        <ul class=\"dim mt-s\" style=\"font-size:13px;line-height:1.85\">\n          <li><b>递归</b>：服务器替客户问到底再返回</li>\n          <li><b>迭代</b>：服务器只告诉你下一步该问谁</li>\n          <li>常见：用户 → 本地 DNS 用递归；本地 DNS → 上层用迭代</li>\n        </ul>\n        <h4 class=\"mt-l\">DNS 协议</h4>\n        <p class=\"dim mt-s\" style=\"font-size:13px\">UDP 53 端口；查询包小于 512 B 时用 UDP，否则用 TCP（区域传送也走 TCP）。<br>DNS 缓存有 TTL，过期才重新查询。</p>\n      </div>\n    </div>"}, {"title": "HTTP / HTTPS", "content": "<p class=\"kicker\">10 · HTTP</p>\n    <h2 class=\"h2\">请求 / 响应 + 状态码 + 版本演进。</h2>\n    <div class=\"grid g2 mt-l\" style=\"align-items:start\">\n      <div>\n        <h4>HTTP 报文</h4>\n        <pre class=\"code-block\" style=\"font-size:12px\">\n<span class=\"c\">// 请求</span>\nGET /index.html HTTP/1.1\nHost: example.com\nUser-Agent: Mozilla/5.0\nAccept: text/html\nCookie: SESSID=abc123\n&lt;空行&gt;\n<span class=\"c\">// 响应</span>\nHTTP/1.1 200 OK\nDate: Mon, 23 May 2026 ...\nServer: nginx\nContent-Type: text/html\nContent-Length: 1234\n&lt;空行&gt;\n&lt;!DOCTYPE html&gt;...</pre>\n        <h4 class=\"mt-l\">8 种方法</h4>\n        <ul class=\"dim mt-s\" style=\"font-size:13px;line-height:1.85\">\n          <li>GET / POST / PUT / DELETE</li>\n          <li>HEAD（只要响应头）</li>\n          <li>OPTIONS（询问支持的方法）</li>\n          <li>PATCH（局部更新）</li>\n          <li>TRACE / CONNECT</li>\n        </ul>\n      </div>\n      <div>\n        <h4>状态码 5 大类</h4>\n        <table class=\"cmp-table mt-s\">\n          <tr><th>类</th><th>含义</th><th>例</th></tr>\n          <tr><td>1xx</td><td>信息</td><td>100 Continue</td></tr>\n          <tr><td>2xx</td><td>成功</td><td>200 OK, 201 Created, 204 No Content</td></tr>\n          <tr><td>3xx</td><td>重定向</td><td>301 永久, 302 临时, 304 Not Modified</td></tr>\n          <tr><td>4xx</td><td>客户错</td><td>400 Bad, 401 未授权, 403 禁止, 404 NotFound</td></tr>\n          <tr><td>5xx</td><td>服务器错</td><td>500 内部错, 502 网关, 503 不可用</td></tr>\n        </table>\n        <h4 class=\"mt-l\">HTTP 版本</h4>\n        <ul class=\"dim mt-s\" style=\"font-size:13px;line-height:1.85\">\n          <li>1.0：非持久连接（每请求一连接）</li>\n          <li>1.1：持久连接 + 流水线（pipelining）</li>\n          <li>2.0：二进制分帧 + 多路复用 + 头压缩</li>\n          <li>3.0：基于 QUIC（UDP），0-RTT</li>\n        </ul>\n        <h4 class=\"mt-m\">HTTPS</h4>\n        <p class=\"dim mt-s\" style=\"font-size:13px\">HTTP + TLS（443 端口）。TLS 握手协商对称密钥，后续数据加密 + 完整性 + 服务器身份认证。</p>\n      </div>\n    </div>"}, {"title": "邮件 + FTP", "content": "<p class=\"kicker\">10 · 其他应用</p>\n    <h2 class=\"h2\">邮件 4 协议 + FTP 双通道。</h2>\n    <div class=\"grid g2 mt-l\" style=\"align-items:start\">\n      <div>\n        <h4>邮件协议</h4>\n        <table class=\"cmp-table mt-s\">\n          <tr><th>协议</th><th>端口</th><th>方向 / 用途</th></tr>\n          <tr><td>SMTP</td><td>25 / 587</td><td>发送（推送到邮件服务器）</td></tr>\n          <tr><td>POP3</td><td>110</td><td>下载到本地后默认从服务器删除</td></tr>\n          <tr><td>IMAP</td><td>143</td><td>服务器留存 + 多设备同步</td></tr>\n          <tr><td>MIME</td><td>—</td><td>对邮件内容的扩展（附件 / 多语言）</td></tr>\n        </table>\n        <h4 class=\"mt-l\">邮件流向</h4>\n        <pre class=\"code-block\" style=\"font-size:11.5px\">\n发件方\n  → SMTP → 发件方 ISP 邮件服务器\n  → SMTP → 收件方 ISP 邮件服务器\n  ← POP3/IMAP ← 收件方读取</pre>\n      </div>\n      <div>\n        <h4>FTP 双通道</h4>\n        <ul class=\"dim mt-s\" style=\"font-size:13.5px;line-height:1.85\">\n          <li><b>控制连接</b> 21：命令 / 响应，整个会话期间保持</li>\n          <li><b>数据连接</b> 20（PORT 主动）或客户随机口（PASV 被动）</li>\n          <li>主动 PORT：服务器主动连客户 → 易被防火墙挡</li>\n          <li>被动 PASV：客户主动连服务器，更友好</li>\n        </ul>\n        <h4 class=\"mt-l\">FTP 命令</h4>\n        <pre class=\"code-block\" style=\"font-size:12px\">\nUSER username\nPASS password\nLIST  (目录列表)\nRETR file (下载)\nSTOR file (上传)\nQUIT</pre>\n        <h4 class=\"mt-m\">一次完整网页访问</h4>\n        <ol class=\"dim mt-s\" style=\"font-size:12.5px;line-height:1.85\">\n          <li>DNS：域名 → IP</li>\n          <li>TCP 三次握手</li>\n          <li>HTTP GET → 收 HTML</li>\n          <li>解析 HTML → 加载 CSS / JS / 图片</li>\n          <li>TCP 四次挥手</li>\n        </ol>\n      </div>\n    </div>"}, {"title": "整体回顾", "content": "<p class=\"kicker\">// summary</p>\n    <h2 class=\"h2\">五层一图收尾。</h2>\n    <div class=\"grid g2 mt-l\">\n      <div class=\"card\">\n        <h4>每层在干什么</h4>\n        <table class=\"cmp-table mt-s\">\n          <tr><td><b>应用</b></td><td>进程交互；HTTP/DNS/SMTP/FTP；端口</td></tr>\n          <tr><td><b>传输</b></td><td>端到端可靠；TCP/UDP；流量+拥塞</td></tr>\n          <tr><td><b>网络</b></td><td>主机到主机路由；IP/ICMP/ARP</td></tr>\n          <tr><td><b>链路</b></td><td>相邻节点；以太网/MAC；CRC</td></tr>\n          <tr><td><b>物理</b></td><td>比特；编码/复用</td></tr>\n        </table>\n      </div>\n      <div class=\"card\">\n        <h4>三大易丢分点</h4>\n        <ol class=\"dim mt-s\" style=\"font-size:13.5px;line-height:1.9\">\n          <li>OSI 与设备对应（路由器 ≠ 网桥）</li>\n          <li>子网掩码 / 最长前缀匹配</li>\n          <li>TCP Seq、Ack 具体数值</li>\n        </ol>\n        <h4 class=\"mt-l\">三大必备公式</h4>\n        <p class=\"mono mt-s\" style=\"background:var(--surface-2);padding:12px;border-radius:8px;font-size:13px;line-height:1.95\">\n          奈奎斯特: C = 2W log₂V<br>\n          香农: C = W log₂(1+S/N)<br>\n          停-等: U = T_d / (T_d + RTT)\n        </p>\n        <h4 class=\"mt-l\">10 道高频大题</h4>\n        <ul class=\"dim mt-s\" style=\"font-size:12.5px;line-height:1.85\">\n          <li>CRC 余数 / 帧封装</li>\n          <li>子网划分 + 路由表</li>\n          <li>TCP 三次/四次握手 Seq</li>\n          <li>cwnd 模拟变化</li>\n          <li>DNS 解析过程</li>\n        </ul>\n      </div>\n    </div>"}]}};
